    _ITEM_FIELD_SIZES = {
        0: 4,
        1: 8,
        2: 4,
        3: 2,
        4: 8,
        5: 2,
        6: 2,
        7: 2,
        8: 2,
        9: 8,
        10: 8,
        11: 1,
        12: 1,
    }

    @staticmethod
    def _item_bitmask_field_present(bitmask_bytes: bytes, field_idx: int) -> bool:
        byte_idx = field_idx // 8
        bit_idx = field_idx % 8
        if byte_idx >= len(bitmask_bytes):
            return False
        return bool(bitmask_bytes[byte_idx] & (1 << bit_idx))

    def _read_item_bitmask(self, blob: bytearray, item: 'SaveItem') -> bytes:
        """Return the per-item bitmask, handling all known save-format variants.

        Game ≤ v1.0.4 locator (8 bytes at offset-24):
            [mbc:2 = 3] [bitmask:3] [pad:3]

        Game v1.0.5 locator (8 bytes at offset-24):
            [discriminator:1 = 0] [bitmask:4] [pad:3]

        The v1.0.5 bitmask is 4 bytes wide because the game added a new
        optional field at bit 21. Bits 0..12 — what the editor walks for
        socket fields — are the same in both formats.

        Falls back to upstream's flexible scan (mbc in [1..8] at offsets
        -24/-25/-26) for any other variants not covered above.
        """
        locator_start = item.offset - 24
        if locator_start + 5 > len(blob):
            return b'\x00\x00\x00'
        # Game ≤ v1.0.4: 2-byte mbc=3 + 3-byte bitmask.
        mbc = struct.unpack_from("<H", blob, locator_start)[0]
        if mbc == 3:
            return bytes(blob[locator_start + 2: locator_start + 5])
        # Game v1.0.5: 1-byte discriminator=0 + 4-byte bitmask.
        if blob[locator_start] == 0x00:
            return bytes(blob[locator_start + 1: locator_start + 5])
        # Fallback: upstream's flexible mbc scan.
        for back in (24, 25, 26):
            ls = item.offset - back
            if ls < 0:
                continue
            m = struct.unpack_from("<H", blob, ls)[0]
            if 1 <= m <= 8:
                return bytes(blob[ls + 2: ls + 2 + m]).ljust(3, b'\x00')
        return b'\x00\x00\x00'

    def _compute_socket_list_offset(self, bitmask: bytes) -> int:
        offset = 0
        for field_idx in range(13):
            if self._item_bitmask_field_present(bitmask, field_idx):
                offset += self._ITEM_FIELD_SIZES[field_idx]
        return offset

    def _read_socket_gems(self, blob: bytearray, item: 'SaveItem') -> list:
        bitmask = self._read_item_bitmask(blob, item)
        sock_list_rel = self._compute_socket_list_offset(bitmask)
        sock_list_abs = item.offset + sock_list_rel

        if sock_list_abs + 18 > len(blob):
            return []
        header_prefix = blob[sock_list_abs]
        sock_count = blob[sock_list_abs + 1] | (blob[sock_list_abs + 2] << 8) | (blob[sock_list_abs + 3] << 16)
        if sock_count < 1 or sock_count > 6:
            return []

        elements_start = sock_list_abs + 18
        results = []
        pos = elements_start

        for si in range(sock_count):
            if pos + 3 > len(blob):
                break
            elem_start = pos
            mbc = struct.unpack_from("<H", blob, pos)[0]
            mask = blob[pos + 2]

            if mask == 0x03:
                gem_key_abs = elem_start + 24
                if gem_key_abs + 4 > len(blob):
                    break
                gem_key = struct.unpack_from("<I", blob, gem_key_abs)[0]
                endurance = struct.unpack_from("<H", blob, elem_start + 22)[0]
                results.append({
                    'slot': si,
                    'has_gem': True,
                    'gem_key': gem_key,
                    'gem_key_abs_offset': gem_key_abs,
                    'endurance': endurance,
                })
                pos = elem_start + 32
            elif mask == 0x00:
                results.append({
                    'slot': si,
                    'has_gem': False,
                    'gem_key': 0,
                    'gem_key_abs_offset': 0,
                    'endurance': 0,
                })
                pos = elem_start + 26
            else:
                field_size = 0
                if mask & 0x01:
                    field_size += 2
                if mask & 0x02:
                    field_size += 4
                total = 18 + 4 + field_size + 4
                if mask & 0x02:
                    key_off = elem_start + 18 + 4
                    if mask & 0x01:
                        key_off += 2
                    gem_key = struct.unpack_from("<I", blob, key_off)[0]
                    results.append({
                        'slot': si,
                        'has_gem': True,
                        'gem_key': gem_key,
                        'gem_key_abs_offset': key_off,
                        'endurance': 0,
                    })
                else:
                    results.append({
                        'slot': si,
                        'has_gem': False,
                        'gem_key': 0,
                        'gem_key_abs_offset': 0,
                        'endurance': 0,
                    })
                pos = elem_start + total

        return results

    def _read_max_valid_sockets(self, blob: bytearray, item: 'SaveItem') -> tuple:
        bitmask = self._read_item_bitmask(blob, item)
        offset = 0
        for field_idx in range(11):
            if self._item_bitmask_field_present(bitmask, field_idx):
                offset += self._ITEM_FIELD_SIZES[field_idx]
        max_s = blob[item.offset + offset] if self._item_bitmask_field_present(bitmask, 11) else 0
        valid_s = 0
        if self._item_bitmask_field_present(bitmask, 11):
            offset += 1
        if self._item_bitmask_field_present(bitmask, 12):
            valid_s = blob[item.offset + offset]
        return max_s, valid_s

    def _apply_socket_unlock(self) -> None:
        if not self._save_data or not self._sock_current_item:
            QMessageBox.warning(self, "Sockets", "No item selected.")
            return

        item = self._sock_current_item
        blob = self._save_data.decompressed_blob
        bitmask = self._read_item_bitmask(blob, item)
        new_count = self._sock_unlock_spin.value()
        max_s, valid_s = self._read_max_valid_sockets(blob, item)

        design_limit = self._get_socket_design_limit(item.item_key)
        if design_limit > 0 and new_count > design_limit:
            QMessageBox.warning(
                self, "Sockets",
                f"Cannot unlock {new_count} slots: this item's design limit is {design_limit}.\n\n"
                f"Filling more than {design_limit} slots crashes the game on save load."
            )
            return

        socket_data = self._read_socket_gems(blob, item)
        if new_count > 0 and max_s == 0 and len(socket_data) == 0:
            reply = QMessageBox.warning(
                self, "No Socket Records",
                "This item has NO socket data records in the save.\n"
                "Setting a socket count without records may crash the game.\n\n"
                "This works best on items that already have sockets\n"
                "(e.g., from the spear swap trick).\n\n"
                "Continue anyway?",
                QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
            )
            if reply != QMessageBox.Yes:
                return

        offset = 0
        field_offsets = {}
        for field_idx in range(13):
            if self._item_bitmask_field_present(bitmask, field_idx):
                field_offsets[field_idx] = offset
                offset += self._ITEM_FIELD_SIZES[field_idx]

        changes = []

        if 7 in field_offsets:
            end_off = item.offset + field_offsets[7]
            old_end = struct.unpack_from("<H", blob, end_off)[0]
            end_low = old_end & 0xFF
            new_end = (new_count << 8) | end_low
            struct.pack_into("<H", blob, end_off, new_end)
            changes.append(f"_endurance: {old_end} (0x{old_end:04X}) → {new_end} (0x{new_end:04X})")

        if 11 in field_offsets:
            max_off = item.offset + field_offsets[11]
            old_max = blob[max_off]
            blob[max_off] = new_count
            changes.append(f"_maxSocketCount: {old_max} → {new_count}")

        if 12 in field_offsets:
            valid_off = item.offset + field_offsets[12]
            old_valid = blob[valid_off]
            blob[valid_off] = new_count
            changes.append(f"_validSocketCount: {old_valid} → {new_count}")

        if not changes:
            QMessageBox.warning(self, "Sockets", "Could not find socket fields in this item's bitmask.")
            return

        name = self._name_db.get_name(item.item_key)
        detail = "\n".join(changes)
        self._dirty = True
        QMessageBox.information(
            self, "Sockets Unlocked",
            f"Set {new_count} socket slots on {name}:\n\n{detail}\n\n"
            f"Save the file and reload in-game to see the change."
        )

        self._on_socket_item_changed(self._sock_item_combo.currentIndex())

    def _build_sockets_tab(self) -> None:
        tab = QWidget()
        layout = QVBoxLayout(tab)
        layout.setContentsMargins(8, 8, 8, 8)
        layout.setSpacing(6)
        layout.addWidget(self._make_scope_label("save"))

        top = QHBoxLayout()
        top.addWidget(QLabel("Equipment:"))
        self._sock_item_combo = QComboBox()
        self._sock_item_combo.setMinimumWidth(200)
        self._sock_item_combo.currentIndexChanged.connect(self._on_socket_item_changed)
        top.addWidget(self._sock_item_combo, 1)

        refresh_btn = QPushButton("Refresh")
        refresh_btn.clicked.connect(self._populate_socket_items)
        top.addWidget(refresh_btn)

        self._sock_show_merc = QCheckBox("Show Companion/NPC")
        self._sock_show_merc.setToolTip("Include Mercenary/companion equipment in the list")
        self._sock_show_merc.setChecked(False)
        self._sock_show_merc.stateChanged.connect(lambda: self._populate_socket_items())
        top.addWidget(self._sock_show_merc)
        top.addWidget(self._make_help_btn("sockets"))

        layout.addLayout(top)

        self._sock_group = QGroupBox("Socket Slots")
        self._sock_layout = QVBoxLayout(self._sock_group)
        self._sock_layout.setSpacing(4)

        self._sock_info = QLabel("Select an equipment item above to view and edit its sockets.")
        self._sock_info.setStyleSheet(f"color: {COLORS['text_dim']}; padding: 4px;")
        self._sock_layout.addWidget(self._sock_info)

        self._sock_locked_hint = QLabel("")
        self._sock_locked_hint.setWordWrap(True)
        self._sock_locked_hint.setStyleSheet(
            f"color: {COLORS['accent']}; padding: 4px 8px; "
            f"border: 1px solid {COLORS['accent']}; border-radius: 4px;"
        )
        self._sock_locked_hint.setVisible(False)
        self._sock_layout.addWidget(self._sock_locked_hint)

        self._sock_rows = []
        for i in range(6):
            row = QHBoxLayout()
            row.setSpacing(6)

            label = QLabel(f"Slot {i+1}:")
            label.setFixedWidth(55)
            label.setStyleSheet("font-weight: bold;")
            row.addWidget(label)

            combo = QComboBox()
            combo.setFixedWidth(280)
            row.addWidget(combo)

            cat_filter = QComboBox()
            cat_filter.addItems(["All"] + list(self.GEM_CATEGORIES.keys()))
            cat_filter.setFixedWidth(130)
            cat_filter.currentTextChanged.connect(lambda text, idx=i: self._filter_gem_combo(idx, text))
            row.addWidget(cat_filter)

            search = QLineEdit()
            search.setPlaceholderText("Search...")
            search.setFixedWidth(120)
            search.textChanged.connect(lambda text, idx=i: self._filter_gem_combo(idx))
            row.addWidget(search)

            row.addStretch(1)

            container = QWidget()
            container.setLayout(row)
            container.setVisible(False)
            self._sock_layout.addWidget(container)
            self._sock_rows.append({"container": container, "label": label, "combo": combo, "filter": cat_filter, "search": search})

        self._sock_layout.addStretch(1)

        from PySide6.QtWidgets import QScrollArea
        sock_scroll = QScrollArea()
        sock_scroll.setWidget(self._sock_group)
        sock_scroll.setWidgetResizable(True)
        sock_scroll.setFrameShape(QFrame.NoFrame)
        sock_scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarAsNeeded)
        sock_scroll.setVerticalScrollBarPolicy(Qt.ScrollBarAsNeeded)
        layout.addWidget(sock_scroll, 1)

        self._sock_unlock_group = QGroupBox("Unlock Socket Slots")
        unlock_layout = QHBoxLayout(self._sock_unlock_group)
        unlock_layout.addWidget(QLabel("Socket Count:"))
        self._sock_unlock_spin = QSpinBox()
        self._sock_unlock_spin.setRange(0, 5)
        self._sock_unlock_spin.setValue(0)
        self._sock_unlock_spin.setToolTip("Set the number of unlocked socket slots (capped at this item's design limit)")
        unlock_layout.addWidget(self._sock_unlock_spin)
        unlock_btn = QPushButton("Unlock Sockets")
        unlock_btn.setObjectName("accentBtn")
        unlock_btn.setToolTip(
            "Sets maxSocketCount, validSocketCount, and the socket bits in enchantLevel.\n"
            "Capped at the item's design limit to avoid crash-on-load saves."
        )
        unlock_btn.clicked.connect(self._apply_socket_unlock)
        unlock_layout.addWidget(unlock_btn)
        unlock_layout.addStretch()
        self._sock_unlock_group.setVisible(False)
        layout.addWidget(self._sock_unlock_group)

        btn_row = QHBoxLayout()
        apply_sock_btn = QPushButton("Apply Socket Changes")
        apply_sock_btn.setObjectName("accentBtn")
        apply_sock_btn.setToolTip("Write the selected gems into the item's socket slots. Only modifies filled sockets.")
        apply_sock_btn.clicked.connect(self._apply_socket_changes)
        btn_row.addWidget(apply_sock_btn)
        btn_row.addStretch()
        layout.addLayout(btn_row)
        self._tabs.addTab(tab, tr("tab.sockets"))
        self._sock_current_item: Optional[SaveItem] = None

    def _populate_gem_combo(self, combo: QComboBox, category: str = "All", search: str = "") -> None:
        combo.blockSignals(True)
        combo.clear()
        combo.addItem("(Empty — remove gem)", 0)
        q = search.lower().strip()
        if category == "All":
            for cat, gems in self.GEM_CATEGORIES.items():
                for key, name in gems:
                    if q and q not in name.lower() and q not in cat.lower():
                        continue
                    combo.addItem(f"{name}  [{cat}]", key)
        else:
            gems = self.GEM_CATEGORIES.get(category, [])
            for key, name in gems:
                if q and q not in name.lower():
                    continue
                combo.addItem(name, key)
        combo.blockSignals(False)

    def _filter_gem_combo(self, slot_idx: int, category: str = None) -> None:
        if slot_idx < len(self._sock_rows):
            row = self._sock_rows[slot_idx]
            combo = row["combo"]
            current_key = combo.currentData()
            cat = category if category is not None else row["filter"].currentText()
            search = row["search"].text()
            self._populate_gem_combo(combo, cat, search)
            if current_key is not None:
                for i in range(combo.count()):
                    if combo.itemData(i) == current_key:
                        combo.setCurrentIndex(i)
                        break

    def _populate_socket_items(self) -> None:
        self._sock_item_combo.blockSignals(True)
        self._sock_item_combo.clear()
        if not self._items:
            self._sock_item_combo.blockSignals(False)
            return

        show_merc = hasattr(self, '_sock_show_merc') and self._sock_show_merc.isChecked()
        filter_socketable = bool(self._socket_design_limits)
        equip = [
            i for i in self._items
            if i.has_enchant
            and (show_merc or i.source not in ("Mercenary",))
            and (not filter_socketable or self._get_socket_design_limit(i.item_key) > 0)
        ]
        for it in equip:
            if not self._save_data:
                continue
            blob = self._save_data.decompressed_blob
            max_s, valid_s = self._read_max_valid_sockets(blob, it)
            name = self._name_db.get_name(it.item_key)
            enc = f"+{it.enchant_level}" if it.has_enchant else ""
            text = f"{name} {enc}  (no={it.item_no}, sockets={valid_s}/{max_s})"
            self._sock_item_combo.addItem(text, id(it))

        self._sock_item_combo.blockSignals(False)
        if self._sock_item_combo.count() > 0:
            self._sock_item_combo.setCurrentIndex(0)
            self._on_socket_item_changed(0)

    def _get_socket_design_limit(self, item_key: int) -> int:
        """Return the max fillable socket count for this item from iteminfo.pabgb.

        Returns 0 for items that aren't in the lookup table — non-socketable
        items (cloaks, accessories) and any item not present in
        item_limits.json. The game crashes on load if more than this many
        slots are filled.
        """
        return self._socket_design_limits.get(str(item_key), 0)

    def _on_socket_item_changed(self, index: int) -> None:
        if not self._save_data or index < 0:
            return

        item_id = self._sock_item_combo.itemData(index)
        item = None
        for it in self._items:
            if id(it) == item_id:
                item = it
                break
        if not item:
            return

        self._sock_current_item = item
        blob = self._save_data.decompressed_blob
        max_s, valid_s = self._read_max_valid_sockets(blob, item)
        design_limit = self._get_socket_design_limit(item.item_key)

        name = self._name_db.get_name(item.item_key)
        bitmask = self._read_item_bitmask(blob, item)

        end_raw = item.endurance
        end_low = end_raw & 0xFF
        end_high = (end_raw >> 8) & 0xFF

        if design_limit == 0:
            self._sock_info.setText(
                f"{name} +{item.enchant_level}  |  "
                f"This item does not support abyss gears."
            )
            self._sock_info.setStyleSheet(f"color: {COLORS['text_dim']}; padding: 4px;")
            self._sock_locked_hint.setVisible(False)
            for r in self._sock_rows:
                r["container"].setVisible(False)
            self._sock_unlock_group.setVisible(False)
            return

        socket_data = self._read_socket_gems(blob, item)
        filled = sum(1 for sd in socket_data if sd.get('has_gem'))

        self._sock_info.setText(
            f"{name} +{item.enchant_level}  |  "
            f"Sockets: {filled} filled · {valid_s} unlocked · {design_limit} max for this item ({max_s} structural)  |  "
            f"Endurance raw=0x{end_raw:04X} (endurance={end_low}, sockets={end_high})  |  "
            f"Offset=0x{item.offset:06X}"
        )
        self._sock_info.setStyleSheet(f"color: {COLORS['accent']}; padding: 4px; font-weight: bold;")

        locked_count = max(0, design_limit - valid_s)
        if locked_count > 0:
            slot_word = "slot" if locked_count == 1 else "slots"
            self._sock_locked_hint.setText(
                f"{locked_count} {slot_word} locked. Use the 'Unlock Socket Slots' panel "
                f"below the slot rows to enable up to {design_limit} slots without visiting the Witch."
            )
            self._sock_locked_hint.setVisible(True)
        else:
            self._sock_locked_hint.setVisible(False)

        self._sock_unlock_group.setVisible(True)
        self._sock_unlock_spin.blockSignals(True)
        self._sock_unlock_spin.setRange(0, design_limit)
        self._sock_unlock_spin.setValue(min(max_s, design_limit))
        self._sock_unlock_spin.blockSignals(False)

        for i in range(6):
            row = self._sock_rows[i]
            if i >= design_limit:
                row["container"].setVisible(False)
                continue

            row["container"].setVisible(True)
            self._populate_gem_combo(row["combo"], row["filter"].currentText())

            current_gem = 0
            has_gem = False
            if i < len(socket_data):
                current_gem = socket_data[i]['gem_key']
                has_gem = socket_data[i]['has_gem']

            gem_name = self.GEM_LOOKUP.get(current_gem, (self._name_db.get_name(current_gem), "?"))[0] if current_gem else "(Empty)"

            combo = row["combo"]
            unlocked = i < valid_s

            combo.setEnabled(unlocked)
            row["filter"].setEnabled(unlocked)
            row["search"].setEnabled(unlocked)

            if unlocked:
                row["label"].setText(f"Slot {i+1}:")
                row["label"].setStyleSheet(
                    "font-weight: bold;" if has_gem
                    else "font-weight: bold; color: gray;"
                )
                row["label"].setToolTip("")
            else:
                row["label"].setText(f"Slot {i+1} (locked):")
                row["label"].setStyleSheet("font-weight: bold; color: gray;")
                row["label"].setToolTip("Locked — visit the Witch (or use Unlock Sockets below) to enable this slot.")

            selected = False
            for ci in range(combo.count()):
                if combo.itemData(ci) == current_gem:
                    combo.setCurrentIndex(ci)
                    selected = True
                    break
            if not selected and current_gem:
                combo.insertItem(0, f"{gem_name} (current, key={current_gem})", current_gem)
                combo.setCurrentIndex(0)
            elif not selected:
                for ci in range(combo.count()):
                    if combo.itemData(ci) == 0:
                        combo.setCurrentIndex(ci)
                        break

    def _shift_item_offsets_after_splice(self, splice_point: int, delta: int) -> None:
        if delta == 0 or not getattr(self, '_items', None):
            return
        for it in self._items:
            if it.offset >= splice_point:
                it.offset += delta
            fo = getattr(it, 'field_offsets', None)
            if fo:
                for name, val in list(fo.items()):
                    if val >= splice_point:
                        fo[name] = val + delta

    def _apply_socket_changes(self) -> None:
        if not self._save_data or not self._sock_current_item:
            QMessageBox.warning(self, "Sockets", "No item selected.")
            return

        item = self._sock_current_item
        blob = self._save_data.decompressed_blob
        max_s, _ = self._read_max_valid_sockets(blob, item)
        design_limit = self._get_socket_design_limit(item.item_key)
        socket_data = self._read_socket_gems(blob, item)

        # Only iterate slots the user can actually see and edit. The combo
        # widgets are reused across item selections, so rows beyond the
        # current item's design_limit (which are hidden) still hold whatever
        # gem keys were left over from a previously-selected higher-slot
        # item. Iterating range(max_s) — the structural array width, always
        # 5 — would scoop up that stale data and misclassify it as fills,
        # tripping the design-limit guard for swaps on 1- or 2-slot items.
        edit_limit = min(max_s, design_limit) if design_limit > 0 else 0
        new_gems = []
        for i in range(edit_limit):
            key = self._sock_rows[i]["combo"].currentData() if i < len(self._sock_rows) else 0
            new_gems.append(key if key else 0)

        fills: Dict[int, int] = {}
        clears: Dict[int, bool] = {}
        swaps: Dict[int, int] = {}

        for i, new_key in enumerate(new_gems):
            if i >= len(socket_data):
                continue
            sd = socket_data[i]
            if not sd['has_gem']:
                if new_key != 0:
                    fills[i] = new_key
            else:
                if new_key == 0:
                    clears[i] = True
                elif new_key != sd['gem_key']:
                    swaps[i] = new_key

        if not fills and not clears and not swaps:
            return

        bitmask_pre = self._read_item_bitmask(blob, item)
        sock_abs_pre = item.offset + self._compute_socket_list_offset(bitmask_pre)

        # Validate against design limit
        existing_filled = sum(1 for sd in socket_data if sd['has_gem'])
        new_filled = existing_filled + len(fills) - len(clears)
        if new_filled > design_limit:
            QMessageBox.warning(
                self, "Sockets",
                f"Cannot fill {len(fills)} slot(s): would exceed the design limit of "
                f"{design_limit} for this item (currently {existing_filled} filled).\n\n"
                f"The game will crash if more than {design_limit} slots are filled."
            )
            return

        if fills:
            from parc_inserter3 import fill_socket_slots
            original_blob_size = len(blob)
            ok, new_blob, msg = fill_socket_slots(blob, item, fills)
            if not ok:
                QMessageBox.warning(self, "Sockets", f"Fill failed: {msg}")
                return
            self._save_data.decompressed_blob[:] = new_blob
            blob = self._save_data.decompressed_blob
            delta = len(blob) - original_blob_size
            if delta:
                self._shift_item_offsets_after_splice(sock_abs_pre, delta)
            socket_data = self._read_socket_gems(blob, item)

        if clears:
            from parc_inserter3 import clear_socket_slots
            original_blob_size = len(blob)
            ok, new_blob, msg = clear_socket_slots(blob, item, list(clears.keys()))
            if not ok:
                QMessageBox.warning(self, "Sockets", f"Clear failed: {msg}")
                return
            self._save_data.decompressed_blob[:] = new_blob
            blob = self._save_data.decompressed_blob
            delta = len(blob) - original_blob_size
            if delta:
                self._shift_item_offsets_after_splice(sock_abs_pre, delta)
            socket_data = self._read_socket_gems(blob, item)

        swap_edits = []
        for i, new_key in swaps.items():
            if i >= len(socket_data):
                continue
            sd = socket_data[i]
            if not sd['has_gem']:
                continue
            off = sd['gem_key_abs_offset']
            old = bytes(blob[off:off + 4])
            struct.pack_into("<I", blob, off, new_key)
            swap_edits.append((off, old, bytes(blob[off:off + 4])))

        if swap_edits:
            self._undo_stack.append(UndoEntry(
                description="Socket swap",
                patches=swap_edits,
            ))

        self._dirty = True
        self._on_socket_item_changed(self._sock_item_combo.currentIndex())

        parts = []
        if fills:
            parts.append(f"installed {len(fills)} gem(s)")
        if clears:
            parts.append(f"removed {len(clears)} gem(s)")
        if swaps:
            parts.append(f"swapped {len(swaps)} gem(s)")
        self._update_status(f"Sockets: {', '.join(parts)}")

    def _max_sockets(self) -> None:
        if not self._save_data or not self._sock_current_item:
            QMessageBox.warning(self, "Max Sockets", "No item selected.")
            return

        item = self._sock_current_item
        blob = self._save_data.decompressed_blob
        bitmask = self._read_item_bitmask(blob, item)

        offset = 0
        for field_idx in range(11):
            if self._item_bitmask_field_present(bitmask, field_idx):
                offset += self._ITEM_FIELD_SIZES[field_idx]
        max_s_off = item.offset + offset if self._item_bitmask_field_present(bitmask, 11) else None
        valid_s_off = None
        if self._item_bitmask_field_present(bitmask, 11):
            offset += 1
        if self._item_bitmask_field_present(bitmask, 12):
            valid_s_off = item.offset + offset

        if max_s_off is None:
            QMessageBox.warning(self, "Max Sockets", "This item has no maxSocketCount field.")
            return

        reply = QMessageBox.question(
            self, "Max Sockets",
            f"Set socket count to 6 for {self._name_db.get_name(item.item_key)}?\n\n"
            "WARNING: The game may not support more sockets than the item originally had. "
            "This could cause issues. Back up first.",
            QMessageBox.Yes | QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        patches = []
        old_max = bytes([blob[max_s_off]])
        blob[max_s_off] = 6
        patches.append((max_s_off, old_max, bytes([6])))

        if valid_s_off is not None:
            old_valid = bytes([blob[valid_s_off]])
            blob[valid_s_off] = 6
            patches.append((valid_s_off, old_valid, bytes([6])))

        self._undo_stack.append(UndoEntry(
            description=f"Max sockets (6) for {self._name_db.get_name(item.item_key)}",
            patches=patches,
        ))
        self._dirty = True
        self._populate_socket_items()
        self._update_status(f"Set sockets to 6 for {self._name_db.get_name(item.item_key)}")


    def _build_swap_tab(self) -> None:
        tab = QWidget()
        layout = QVBoxLayout(tab)
        layout.setContentsMargins(8, 8, 8, 8)
        layout.setSpacing(8)
        layout.addWidget(self._make_scope_label("save"))

        swap_warn = QLabel(
            "WARNING: Swapping equipment in the Inventory tab may cause items to not appear in-game. "
            "For reliable equipment swaps, use the Repurchase tab (Vendor Swap) instead."
        )
        swap_warn.setWordWrap(True)
        swap_warn.setStyleSheet(
            f"color: #FF5252; font-weight: bold; padding: 8px; "
            f"border: 1px solid #FF5252; border-radius: 4px; "
            f"background-color: rgba(255,82,82,0.10);"
        )
        help_row = QHBoxLayout()
        help_row.addWidget(swap_warn, 1)
        help_row.addWidget(self._make_help_btn("swap"))
        layout.addLayout(help_row)

        info_group = QGroupBox("Selected Item")
        info_layout = QGridLayout(info_group)
        self._swap_icon_label = QLabel()
        self._swap_icon_label.setFixedSize(ICON_SIZE, ICON_SIZE)
        info_layout.addWidget(self._swap_icon_label, 0, 0)
        self._swap_current_label = QLabel("No item selected. Select an item from the Inventory tab first.")
        self._swap_current_label.setWordWrap(True)
        info_layout.addWidget(self._swap_current_label, 0, 1, 1, 2)
        layout.addWidget(info_group)

        target_group = QGroupBox("Swap To")
        target_layout = QVBoxLayout(target_group)

        filter_row = QHBoxLayout()
        filter_row.addWidget(QLabel("Category:"))
        self._swap_category = QComboBox()
        self._swap_category.addItem("All")
        self._swap_category.addItem("Has Template")
        for cat in ["Equipment", "Armor", "Weapon", "Shield", "Accessory",
                     "Consumable", "Material", "Ammo", "Quest", "Visione",
                     "Skill", "Trade", "Recipe", "Currency", "Misc", "Dev"]:
            self._swap_category.addItem(cat)
        self._swap_category.currentTextChanged.connect(self._filter_swap_items)
        self._swap_category.setFixedWidth(130)
        filter_row.addWidget(self._swap_category)

        filter_row.addWidget(QLabel("Search:"))
        self._swap_search = QLineEdit()
        self._swap_search.setPlaceholderText("Type to search items by name or key...")
        self._swap_search.textChanged.connect(self._filter_swap_items)
        filter_row.addWidget(self._swap_search, 2)
        target_layout.addLayout(filter_row)

        self._swap_list = QTableWidget()
        self._swap_list.setColumnCount(4)
        self._swap_list.setHorizontalHeaderLabels(["", "ItemKey", "Name", "Category"])
        self._swap_list.setSelectionBehavior(QAbstractItemView.SelectRows)
        self._swap_list.setSelectionMode(QAbstractItemView.SingleSelection)
        self._swap_list.horizontalHeader().setSectionResizeMode(0, QHeaderView.Interactive)
        self._swap_list.setColumnWidth(0, 0)
        self._swap_list.horizontalHeader().setSectionResizeMode(2, QHeaderView.Interactive)
        self._swap_list.setColumnWidth(2, 200)
        self._swap_list.setEditTriggers(QAbstractItemView.NoEditTriggers)
        self._swap_list.setSortingEnabled(True)
        self._swap_list.verticalHeader().setDefaultSectionSize(22)
        self._swap_list.setIconSize(QSize(ICON_SIZE, ICON_SIZE))
        target_layout.addWidget(self._swap_list, 1)

        manual_row = QHBoxLayout()
        manual_row.addWidget(QLabel("Manual Key:"))
        self._swap_manual_key = QSpinBox()
        self._swap_manual_key.setRange(1, 0x7FFFFFFF)
        manual_row.addWidget(self._swap_manual_key)
        manual_row.addStretch()
        target_layout.addLayout(manual_row)

        layout.addWidget(target_group, 1)

        warn = QLabel(
            "WARNING: Item swaps change the item key in-place. "
            "Visual appearance and stats may not match the new item. "
            "Equipment slot records will also be patched."
        )
        warn.setWordWrap(True)
        warn.setStyleSheet(f"color: {COLORS['warning']}; padding: 6px;")
        layout.addWidget(warn)

        btn_row = QHBoxLayout()
        btn_row.addStretch()
        swap_btn = QPushButton("Swap (Single Item)")
        swap_btn.setObjectName("accentBtn")
        swap_btn.setToolTip("Swap only this specific item instance. Other copies of the same item are untouched.")
        swap_btn.clicked.connect(self._perform_swap)
        btn_row.addWidget(swap_btn)

        swap_all_btn = QPushButton("Swap All (Global)")
        swap_all_btn.setToolTip("Replace EVERY occurrence of this item key in the entire save. All copies become the new item.")
        swap_all_btn.clicked.connect(self._perform_swap_all)
        btn_row.addWidget(swap_all_btn)

        self._template_swap_btn = QPushButton("Template Swap (Real Stats)")
        self._template_swap_btn.setObjectName("accentBtn")
        self._template_swap_btn.setToolTip(
            "Swap using real game data from community templates.\n"
            "Replaces the entire item record — correct stats, sockets, endurance.\n"
            "Only works when items have the same binary size (most do).\n"
            "Falls back to key-only swap if sizes don't match.")
        self._template_swap_btn.clicked.connect(self._perform_template_swap)
        btn_row.addWidget(self._template_swap_btn)

        self._clean_swap_btn = QPushButton("Clean Swap")
        self._clean_swap_btn.setToolTip("Swap + zero out gimmick state, charged count, and timestamps. May fix placeholder icons.")
        self._clean_swap_btn.clicked.connect(self._perform_clean_swap)
        self._clean_swap_btn.setVisible(self._experimental_mode)
        btn_row.addWidget(self._clean_swap_btn)
        layout.addLayout(btn_row)

        self._swap_tab_widget = tab
        self._tabs.addTab(tab, tr("tab.item_swap"))

        self._populate_swap_list()


