    def _update_community_status(self) -> None:
        try:
            from template_sync import get_sync_status
            status = get_sync_status()
            self._community_status.setText(
                f"Master DB: {status['master_count']} templates  |  "
                f"Coverage: {status['coverage_pct']}% of {status['total_game_items']} game items  |  "
                f"Local: {status['local_count']} templates  |  "
                f"New to contribute: {status['new_count']}"
            )
            self._update_coverage_table()
        except Exception as e:
            self._community_status.setText(f"Template DB not loaded: {e}")

    def _update_coverage_table(self) -> None:
        try:
            from template_sync import load_local_master
            master = load_local_master()
            templates = master.get('templates', {})

            categories = {}
            for info in self._name_db.get_all_sorted():
                cat = info.category
                categories.setdefault(cat, {'total': 0, 'mapped': 0})
                categories[cat]['total'] += 1
                if str(info.item_key) in templates:
                    categories[cat]['mapped'] += 1

            table = self._coverage_table
            table.setRowCount(len(categories))
            for row, (cat, counts) in enumerate(sorted(categories.items(), key=lambda x: -x[1]['total'])):
                pct = (counts['mapped'] / counts['total'] * 100) if counts['total'] > 0 else 0
                table.setItem(row, 0, QTableWidgetItem(cat))
                table.setItem(row, 1, QTableWidgetItem(str(counts['mapped'])))
                table.setItem(row, 2, QTableWidgetItem(str(counts['total'])))
                pct_item = QTableWidgetItem(f"{pct:.1f}%")
                if pct >= 90:
                    pct_item.setForeground(QBrush(QColor(COLORS['success'])))
                elif pct >= 50:
                    pct_item.setForeground(QBrush(QColor(COLORS['warning'])))
                else:
                    pct_item.setForeground(QBrush(QColor(COLORS['error'])))
                table.setItem(row, 3, pct_item)
        except Exception:
            pass

    def _community_sync(self) -> None:
        self._community_status.setText("Downloading master DB...")
        QApplication.processEvents()
        try:
            from template_sync import download_master, find_new_templates, upload_contribution, _LOCAL_MASTER
            from item_template_db import load_db
            import json

            master = download_master()
            master_count = len(master.get('templates', {}))
            self._community_status.setText(f"Master DB: {master_count} templates. Checking local...")
            QApplication.processEvents()

            db = load_db()
            new = find_new_templates(db, master)

            if new:
                self._community_status.setText(f"Uploading {len(new)} new templates...")
                QApplication.processEvents()
                ok, msg = upload_contribution(new)
                if ok:
                    master_templates = master.get('templates', {})
                    master_templates.update(new)
                    master['templates'] = master_templates
                    master['total_items'] = len(master_templates)
                    with open(_LOCAL_MASTER, 'w', encoding='utf-8') as f:
                        json.dump(master, f, separators=(',', ':'))
                self._community_status.setText(msg)
            else:
                self._community_status.setText(
                    f"Up to date! Master: {master_count} templates, nothing new to contribute."
                )
        except Exception as e:
            self._community_status.setText(f"Sync failed: {e}")
        self._update_community_status()

    def _community_download(self) -> None:
        self._community_status.setText("Downloading...")
        QApplication.processEvents()
        try:
            from template_sync import download_master
            master = download_master()
            count = len(master.get('templates', {}))
            self._community_status.setText(f"Downloaded master DB: {count} templates")
        except Exception as e:
            self._community_status.setText(f"Download failed: {e}")
        self._update_community_status()

    def _community_upload(self) -> None:
        self._community_status.setText("Checking for new templates to upload...")
        QApplication.processEvents()
        try:
            from template_sync import load_local_master, find_new_templates, upload_contribution
            from item_template_db import load_db
            db = load_db()
            master = load_local_master()
            new = find_new_templates(db, master)
            if not new:
                self._community_status.setText("Nothing new to upload — local DB matches master.")
                return
            ok, msg = upload_contribution(new)
            if ok:
                master_templates = master.get('templates', {})
                master_templates.update(new)
                master['templates'] = master_templates
                master['total_items'] = len(master_templates)
                import json
                from template_sync import _LOCAL_MASTER
                with open(_LOCAL_MASTER, 'w', encoding='utf-8') as f:
                    json.dump(master, f, separators=(',', ':'))
            self._community_status.setText(msg)
        except Exception as e:
            self._community_status.setText(f"Upload failed: {e}")
        self._update_community_status()

    def _community_scan_loaded(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Scan", "No save file loaded.")
            return
        self._community_status.setText("Scanning loaded save...")
        QApplication.processEvents()
        try:
            from item_template_db import extract_items_from_parse_tree, save_db, load_db, _get_parser
            from template_sync import load_local_master, find_new_templates
            sp = _get_parser()
            raw = bytes(self._save_data.decompressed_blob)
            result = sp.build_result_from_raw(raw, {'input_kind': 'raw_blob'})
            templates = extract_items_from_parse_tree(result, raw, 'loaded_save')
            db = load_db()
            new_count = 0
            for key, t in templates.items():
                clean = {
                    'hex': t['hex'], 'mask': t['mask'], 'size': t['size'],
                    'item_key': t['item_key'], 'field_positions': t.get('field_positions', {}),
                }
                if key not in db or clean['size'] < db[key].get('size', 9999):
                    db[key] = clean
                    new_count += 1
            save_db(db)
            master = load_local_master()
            new_to_share = find_new_templates(db, master)
            self._community_status.setText(
                f"Loaded save: {len(templates)} items found, {new_count} new to local DB. "
                f"{len(new_to_share)} ready to contribute."
            )
        except Exception as e:
            self._community_status.setText(f"Scan failed: {e}")
        self._update_community_status()

    def _community_scan_saves(self) -> None:
        reply = QMessageBox.question(
            self, "Scan All Saves",
            "This will scan ALL save slots for item templates.\n"
            "This may take up to 5 minutes depending on how many saves you have.\n\n"
            "Continue?",
            QMessageBox.Yes | QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return
        self._community_status.setText("Scanning all saves (this may take a few minutes)...")
        self._community_progress.setVisible(True)
        self._community_progress.setRange(0, 0)
        QApplication.processEvents()
        try:
            from template_sync import scan_all_saves, load_local_master, find_new_templates
            from item_template_db import save_db
            local = scan_all_saves()
            save_db(local)
            master = load_local_master()
            new = find_new_templates(local, master)
            self._community_status.setText(
                f"Scanned: {len(local)} templates found. {len(new)} new to contribute."
            )
        except Exception as e:
            self._community_status.setText(f"Scan failed: {e}")
        finally:
            self._community_progress.setVisible(False)
            self._update_community_status()

    def _background_template_scan(self) -> None:
        if not self._save_data:
            return
        try:
            from item_template_db import extract_items_from_parse_tree, save_db, load_db, _get_parser
            sp = _get_parser()
            raw = bytes(self._save_data.decompressed_blob)
            result = sp.build_result_from_raw(raw, {'input_kind': 'raw_blob'})
            templates = extract_items_from_parse_tree(result, raw, 'auto_scan')
            db = load_db()
            new_count = 0
            for key, t in templates.items():
                clean = {
                    'hex': t['hex'], 'mask': t['mask'], 'size': t['size'],
                    'item_key': t['item_key'], 'field_positions': t.get('field_positions', {}),
                }
                if key not in db or clean['size'] < db[key].get('size', 9999):
                    db[key] = clean
                    new_count += 1
            if new_count > 0:
                save_db(db)
            self._update_community_status()
        except Exception:
            pass

    def _mass_swap(self) -> None:
        if not self._save_data or not self._items:
            QMessageBox.warning(self, "Mass Swap", "Load a save file first.")
            return

        key_min = self._mass_swap_min.value()
        key_max = self._mass_swap_max.value()

        try:
            from template_sync import load_local_master
            master = load_local_master()
            mapped_keys = set(int(k) for k in master.get('templates', {}).keys())
        except Exception:
            mapped_keys = set()

        all_targets = []
        for info in self._name_db.get_all_sorted():
            k = info.item_key
            if k < key_min or k > key_max:
                continue
            if k in mapped_keys:
                continue
            all_targets.append(info)

        if not all_targets:
            self._mass_swap_status.setText(
                f"No unmapped items in range {key_min}-{key_max}. Try a different range or sync first."
            )
            return

        inv_items = [i for i in self._items if i.source == "Inventory" and i.item_key > 0]
        if not inv_items:
            self._mass_swap_status.setText("No inventory items to swap.")
            return

        targets_by_cat = {}
        for info in all_targets:
            targets_by_cat.setdefault(info.category, []).append(info)

        used_keys = set()
        swap_count = 0
        patches_all = []

        for item in inv_items:
            item_cat = self._name_db.get_category(item.item_key)

            available = [t for t in targets_by_cat.get(item_cat, []) if t.item_key not in used_keys]

            if not available:
                for cat, targets in targets_by_cat.items():
                    available = [t for t in targets if t.item_key not in used_keys]
                    if available:
                        break

            if not available:
                continue

            target = available[0]
            used_keys.add(target.item_key)

            try:
                patches = smart_item_swap(
                    self._save_data.decompressed_blob, item, target.item_key
                )
                patches_all.extend(patches)
                swap_count += 1
            except Exception:
                continue

        if swap_count > 0:
            self._undo_stack.append(UndoEntry(
                description=f"Mass Swap: {swap_count} items to unmapped keys",
                patches=patches_all,
            ))
            self._dirty = True
            self._scan_and_populate()

        self._mass_swap_status.setText(
            f"Swapped {swap_count} items to unmapped keys. "
            f"{len(all_targets) - len(used_keys)} unmapped targets remaining in range."
        )
        self._update_community_status()

    def _fetch_community_packs(self) -> None:
        self._packs_status.setText("Fetching...")
        QApplication.processEvents()
        ok, msg = self._pack_mgr.fetch_remote_index()
        self._packs_status.setText(msg)

        table = self._community_table
        entries = self._pack_mgr.get_remote_index()
        table.setRowCount(len(entries))
        for row, e in enumerate(entries):
            table.setItem(row, 0, QTableWidgetItem(e.name))
            table.setItem(row, 1, QTableWidgetItem(e.author))
            table.setItem(row, 2, QTableWidgetItem(str(e.item_count)))
            table.setItem(row, 3, QTableWidgetItem(e.description))
            table.setItem(row, 4, QTableWidgetItem(e.filename))

    def _download_community_pack(self) -> None:
        rows = set(idx.row() for idx in self._community_table.selectedIndexes())
        if not rows:
            QMessageBox.information(self, "Download", "Select a pack from the list first.")
            return
        row = min(rows)
        fname_w = self._community_table.item(row, 4)
        if not fname_w:
            return
        filename = fname_w.text()

        self._packs_status.setText(f"Downloading {filename}...")
        QApplication.processEvents()
        pack, msg = self._pack_mgr.download_pack(filename)
        self._packs_status.setText(msg)

        if pack:
            self._refresh_local_packs()
            QMessageBox.information(self, "Downloaded", msg)

    def _preview_community_pack(self) -> None:
        rows = set(idx.row() for idx in self._community_table.selectedIndexes())
        if not rows:
            return
        row = min(rows)
        fname_w = self._community_table.item(row, 4)
        name_w = self._community_table.item(row, 0)
        if not fname_w:
            return

        pack, msg = self._pack_mgr.download_pack(fname_w.text())
        if not pack:
            QMessageBox.warning(self, "Preview", msg)
            return

        items_text = "\n".join(
            f"  {it.name or f'Key:{it.item_key}'} x{it.count}"
            + (f" +{it.enchant}" if it.enchant >= 0 else "")
            for it in pack.items
        )
        QMessageBox.information(
            self, f"Pack: {pack.name}",
            f"Author: {pack.author}\n"
            f"Description: {pack.description}\n"
            f"Items ({len(pack.items)}):\n{items_text}"
        )

    def _refresh_local_packs(self) -> None:
        packs = self._pack_mgr.scan_local()
        table = self._local_table
        table.setRowCount(len(packs))
        for row, p in enumerate(packs):
            name_item = QTableWidgetItem(p.name)
            name_item.setData(Qt.UserRole, p.filename)
            table.setItem(row, 0, name_item)
            table.setItem(row, 1, QTableWidgetItem(p.author))
            table.setItem(row, 2, QTableWidgetItem(str(len(p.items))))
            table.setItem(row, 3, QTableWidgetItem(p.filename))

    def _parc_add_pack(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Add Pack", "Load a save file first.")
            return
        if insert_item_to_inventory is None:
            QMessageBox.critical(self, "Add Pack", "PARC inserter module not available.")
            return

        rows = set(idx.row() for idx in self._local_table.selectedIndexes())
        if not rows:
            QMessageBox.information(self, "Add Pack", "Select a pack from the list.")
            return

        row = min(rows)
        pack_name_item = self._local_table.item(row, 0)
        if not pack_name_item:
            return
        pack_filename = pack_name_item.data(Qt.UserRole) or self._local_table.item(row, 3).text() if self._local_table.item(row, 3) else ""
        if not pack_filename:
            QMessageBox.warning(self, "Add Pack", "No pack filename found.")
            return

        pack_path = os.path.join(self._pack_mgr.local_dir, pack_filename)
        if not os.path.isfile(pack_path):
            pack_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'dist', 'packs', pack_filename)
        if not os.path.isfile(pack_path):
            pack_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'packs', pack_filename)
        if not os.path.isfile(pack_path):
            QMessageBox.warning(self, "Add Pack", f"Pack file not found: {pack_filename}")
            return

        try:
            import json
            with open(pack_path) as f:
                pack_data = json.load(f)
        except Exception as e:
            QMessageBox.warning(self, "Add Pack", f"Failed to load pack: {e}")
            return

        items = pack_data.get("items", [])
        if not items:
            QMessageBox.warning(self, "Add Pack", "Pack has no items.")
            return

        item_lines = []
        for it in items[:10]:
            name = self._name_db.get_name(it.get("item_key", 0))
            count = it.get("count", 1)
            item_lines.append(f"  {name} x{count}")
        if len(items) > 10:
            item_lines.append(f"  ... and {len(items) - 10} more")

        reply = QMessageBox.question(
            self, "Add Pack (PARC Insert)",
            f"Insert {len(items)} items from '{pack_data.get('name', '?')}' into inventory?\n\n"
            + "\n".join(item_lines) + "\n\n"
            f"Items will be ADDED as new — no donor items needed.\n"
            f"May require 2 reloads but not usually.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        self._update_status(f"PARC inserting {len(items)} items (batch mode)...")
        QApplication.processEvents()

        try:
            batch = []
            slot_start = 200
            for i, it in enumerate(items):
                item_key = it.get("item_key", 0)
                count = it.get("count", 1)
                if item_key > 0:
                    batch.append((item_key, count, slot_start + i))

            blob = bytearray(self._save_data.decompressed_blob)
            if insert_items_batch is not None:
                ok, new_blob, msg = insert_items_batch(blob, batch, bag_key=2)
            else:
                ok, new_blob, msg = False, blob, "PARC inserter not available"

            if ok:
                blob = bytearray(new_blob)
                inserted = len(batch)
            else:
                inserted = 0
                QMessageBox.warning(self, "Pack Insert", f"Batch insert failed:\n{msg}")
        except Exception as e:
            inserted = 0
            QMessageBox.critical(self, "Pack Insert Error", str(e))

        if inserted > 0:
            self._save_data.decompressed_blob = bytearray(blob)
            self._dirty = True
            self._scan_and_populate()

        result_msg = f"Inserted {inserted}/{len(items)} items."
        if failed > 0:
            result_msg += f" {failed} failed."
        result_msg += "\nSave (Ctrl+S), then reload in-game (may require 2 reloads but not usually)."

        self._update_status(result_msg)
        QMessageBox.information(self, "Pack Added", result_msg)

    def _apply_local_pack(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Apply Pack", "Load a save file first.")
            return

        rows = set(idx.row() for idx in self._local_table.selectedIndexes())
        if not rows:
            QMessageBox.information(self, "Apply Pack", "Select a pack from the list.")
            return
        row = min(rows)
        fname_w = self._local_table.item(row, 3)
        if not fname_w:
            return

        pack = self._pack_mgr.load_pack_file(
            os.path.join(self._pack_mgr.local_dir, fname_w.text())
        )
        if not pack:
            QMessageBox.warning(self, "Apply Pack", "Failed to load pack file.")
            return

        dlg = ApplyPackDialog(pack, self._name_db, self._items, self, experimental=self._experimental_mode)
        if dlg.exec() != QDialog.Accepted:
            return

        all_patches = []
        applied = 0
        for pack_item, donor in dlg.mappings:
            patches = smart_item_swap(self._save_data.decompressed_blob, donor, pack_item.item_key)
            old_stack = apply_stack_edit(self._save_data.decompressed_blob, donor, pack_item.count)
            patches.append((
                donor.offset + 18, old_stack,
                self._save_data.decompressed_blob[donor.offset + 18:donor.offset + 26]
            ))
            if pack_item.enchant >= 0 and donor.has_enchant:
                old_enc = apply_enchant_edit(self._save_data.decompressed_blob, donor, pack_item.enchant)
                patches.append((
                    donor.offset + 26, old_enc,
                    self._save_data.decompressed_blob[donor.offset + 26:donor.offset + 28]
                ))
            all_patches.extend(patches)
            applied += 1

        if all_patches:
            self._undo_stack.append(UndoEntry(
                description=f"Apply pack '{pack.name}' ({applied} items)",
                patches=all_patches,
            ))
            self._dirty = True
            self._populate_inventory()
            self._populate_equipment()
            self._update_status(f"Applied pack '{pack.name}': {applied} items transformed")

    def _create_pack(self) -> None:
        dlg = CreatePackDialog(self._name_db, self)
        if dlg.exec() != QDialog.Accepted:
            return
        pack = dlg.pack
        if not pack.items:
            QMessageBox.information(self, "Create Pack", "Pack has no items.")
            return
        path = self._pack_mgr.save_pack(pack)
        self._refresh_local_packs()
        QMessageBox.information(
            self, "Pack Created",
            f"Saved '{pack.name}' with {len(pack.items)} items.\n{path}"
        )

    def _import_pack(self) -> None:
        path, _ = QFileDialog.getOpenFileName(
            self, "Import Pack", "", "JSON Files (*.json);;All Files (*.*)"
        )
        if not path:
            return
        pack = self._pack_mgr.load_pack_file(path)
        if not pack:
            QMessageBox.warning(self, "Import", "Failed to read pack file.")
            return
        self._pack_mgr.save_pack(pack)
        self._refresh_local_packs()
        self._update_status(f"Imported pack '{pack.name}'")

    def _export_pack(self) -> None:
        rows = set(idx.row() for idx in self._local_table.selectedIndexes())
        if not rows:
            QMessageBox.information(self, "Export", "Select a pack first.")
            return
        row = min(rows)
        fname_w = self._local_table.item(row, 3)
        if not fname_w:
            return
        pack = self._pack_mgr.load_pack_file(
            os.path.join(self._pack_mgr.local_dir, fname_w.text())
        )
        if not pack:
            return

        json_str = self._pack_mgr.export_pack_json(pack)
        QApplication.clipboard().setText(json_str)

        save_path, _ = QFileDialog.getSaveFileName(
            self, "Export Pack", f"{pack.filename}", "JSON Files (*.json)"
        )
        if save_path:
            with open(save_path, "w", encoding="utf-8") as f:
                f.write(json_str)

        QMessageBox.information(
            self, "Exported",
            f"Pack JSON copied to clipboard.\n"
            + (f"Also saved to: {save_path}" if save_path else "Use File > Save As for a file copy.")
        )

    def _delete_local_pack(self) -> None:
        rows = set(idx.row() for idx in self._local_table.selectedIndexes())
        if not rows:
            return
        row = min(rows)
        fname_w = self._local_table.item(row, 3)
        name_w = self._local_table.item(row, 0)
        if not fname_w:
            return
        reply = QMessageBox.question(
            self, "Delete Pack",
            f"Delete pack '{name_w.text() if name_w else fname_w.text()}'?",
            QMessageBox.Yes | QMessageBox.No,
        )
        if reply == QMessageBox.Yes:
            self._pack_mgr.delete_pack(fname_w.text())
            self._refresh_local_packs()


