    def _merc_refresh(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Mercenary", "Load a save file first.")
            return

        self._merc_status.setText("Scanning mercenaries...")
        QApplication.processEvents()

        try:
            import struct as _st
            sys_path = __import__('sys').path
            for d in ['Communitydump/tools', 'tools', 'Communitydump/desktopeditor', 'desktopeditor']:
                p = os.path.join(os.path.dirname(__file__), d)
                if os.path.isdir(p) and p not in sys_path:
                    sys_path.insert(0, p)

            raw = bytes(self._save_data.decompressed_blob)

            try:
                from save_pet_rename import find_mercenary_bitmap_positions, parse_reflection_layout
                layout = parse_reflection_layout(raw)
                mercs_raw = find_mercenary_bitmap_positions(raw, layout)
                self._merc_pet_rename_layout = layout
            except ImportError:
                mercs_raw = []

            self._merc_entries = []
            for idx, m in enumerate(mercs_raw):
                merc = {
                    'index': idx,
                    'char_key': m.get('extra', {}).get('_characterKey', 0),
                    'char_key_offset': -1,
                    'name': m.get('name_current_value') or '',
                    'name_offset': m.get('name_insert_pos', -1),
                    'name_length': 0,
                    'name_present': m.get('name_bit_set', False),
                    'name_insert_pos': m.get('name_insert_pos', -1),
                    'name_prop_idx': m.get('name_prop_idx', -1),
                    'merc_no': m.get('mercenary_no', 0),
                    'bitmap_pos': m.get('bitmap_pos', -1),
                    'raw_merc_info': m,
                }
                if merc['name_present'] and merc['name']:
                    merc['name_length'] = len(merc['name'].encode('utf-8'))
                self._merc_entries.append(merc)

            self._merc_table.setRowCount(len(self._merc_entries))
            icon_col_w = (ICON_SIZE + 12) if self._icons_enabled else 0
            self._merc_table.setColumnWidth(0, icon_col_w)
            if icon_col_w:
                self._merc_table.verticalHeader().setDefaultSectionSize(max(ICON_SIZE + 2, 22))

            for row, merc in enumerate(self._merc_entries):
                icon_item = QTableWidgetItem()
                if self._icons_enabled:
                    px = self._icon_cache.get_merc_pixmap(merc['char_key'])
                    if px:
                        icon_item.setIcon(QIcon(px))
                self._merc_table.setItem(row, 0, icon_item)

                idx_item = QTableWidgetItem(str(row))
                idx_item.setData(Qt.UserRole, row)
                self._merc_table.setItem(row, 1, idx_item)

                mno_item = QTableWidgetItem(str(merc['merc_no']))
                self._merc_table.setItem(row, 2, mno_item)

                key_item = QTableWidgetItem(str(merc['char_key']))
                self._merc_table.setItem(row, 3, key_item)

                type_name = self._merc_identify_type(merc['char_key'])
                type_item = QTableWidgetItem(type_name)
                self._merc_table.setItem(row, 4, type_item)

                name_item = QTableWidgetItem(merc['name'] if merc['name'] else "(unnamed)")
                if not merc['name']:
                    name_item.setForeground(QColor(COLORS['text_dim']))
                self._merc_table.setItem(row, 5, name_item)

            self._merc_status.setText(f"Found {len(self._merc_entries)} mercenaries/pets")

        except Exception as e:
            import traceback; traceback.print_exc()
            self._merc_status.setText(f"Error: {e}")

