    def _merc_identify_type(self, char_key: int) -> str:
        name = self.CHAR_KEY_NAMES.get(char_key)
        if name:
            return name
        if char_key < 100:
            return f"Playable Character ({char_key})"
        return f"Unknown ({char_key})"

    def _merc_rename(self) -> None:
        log.info("_merc_rename: entered (save=%s, entries=%d, current_row=%d)",
                 bool(self._save_data),
                 len(getattr(self, '_merc_entries', []) or []),
                 self._merc_table.currentRow())
        if not self._save_data:
            self._merc_status.setText("Rename: no save loaded — open a save.save first")
            QMessageBox.warning(self, "Mercenary", "Load a save first.")
            return

        if not getattr(self, '_merc_entries', None):
            self._merc_status.setText(
                "Rename: mercenary list is empty — click 'Refresh List' first. "
                "If still empty, this save has no mercenary/pet data yet.")
            QMessageBox.information(
                self, "Mercenary",
                "Mercenary list is empty.\n\n"
                "Click 'Refresh List' to scan the save. If the list stays empty, "
                "this save has no mercenary data (play enough to unlock a mount/pet first).",
            )
            return

        row = self._merc_table.currentRow()
        if row < 0:
            self._merc_table.selectRow(0)
            row = 0
        if row >= len(self._merc_entries):
            self._merc_status.setText(
                f"Rename: selected row {row} out of range (have {len(self._merc_entries)} entries)")
            QMessageBox.information(self, "Mercenary",
                                    f"Selected row {row} is out of range.")
            return

        merc = self._merc_entries[row]
        current = merc['name'] if merc['name'] else ""
        log.info("_merc_rename: opening dialog for row=%d merc_no=%s char_key=%s current=%r",
                 row, merc.get('merc_no'), merc.get('char_key'), current)

        from PySide6.QtWidgets import QInputDialog
        new_name, ok = QInputDialog.getText(
            self, "Rename Mercenary",
            f"Enter new name for mercenary #{row} (key={merc['char_key']}):\n"
            f"Current name: {current or '(none)'}",
            text=current,
        )
        if not ok or not new_name.strip():
            return

        new_name = new_name.strip()
        name_bytes = new_name.encode('utf-8')

        try:
            from save_pet_rename import patch_mercenary_name, parse_reflection_layout, find_mercenary_bitmap_positions

            plaintext = bytearray(self._save_data.decompressed_blob)
            layout = parse_reflection_layout(bytes(plaintext))
            mercs_now = find_mercenary_bitmap_positions(bytes(plaintext), layout)

            target = None
            for m in mercs_now:
                if m['mercenary_no'] == merc['merc_no']:
                    target = m
                    break

            if not target:
                QMessageBox.warning(self, "Rename", f"Could not find mercenary #{merc['merc_no']} in save.")
                return

            patched = patch_mercenary_name(plaintext, layout, target, new_name)
            self._save_data.decompressed_blob = bytearray(patched)

            self._dirty = True
            merc['name'] = new_name
            merc['name_length'] = len(name_bytes)
            merc['name_present'] = True
            self._merc_table.item(row, 5).setText(new_name)
            self._merc_table.item(row, 5).setForeground(QColor(COLORS['text']))
            self._merc_status.setText(f"Renamed mercenary #{row} to \"{new_name}\" — save with Ctrl+S")

        except Exception as e:
            import traceback; traceback.print_exc()
            QMessageBox.critical(self, "Rename Error", str(e))

    def _merc_clear_name(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Mercenary", "Load a save first.")
            return

        row = self._merc_table.currentRow()
        if row < 0 or row >= len(self._merc_entries):
            QMessageBox.information(self, "Mercenary", "Select a mercenary first.")
            return

        merc = self._merc_entries[row]
        if not merc['name_present']:
            QMessageBox.information(self, "Mercenary", "This mercenary has no name to clear.")
            return

        reply = QMessageBox.question(
            self, "Clear Name",
            f"Remove the name \"{merc['name']}\" from mercenary #{row}?",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        try:
            from save_pet_rename import clear_mercenary_name, parse_reflection_layout, find_mercenary_bitmap_positions

            plaintext = bytearray(self._save_data.decompressed_blob)
            layout = parse_reflection_layout(bytes(plaintext))
            mercs_now = find_mercenary_bitmap_positions(bytes(plaintext), layout)

            target = None
            for m in mercs_now:
                if m['mercenary_no'] == merc['merc_no']:
                    target = m
                    break

            if not target or not target['name_bit_set']:
                QMessageBox.information(self, "Mercenary", "This mercenary has no name to clear.")
                return

            patched = clear_mercenary_name(plaintext, layout, target)
            self._save_data.decompressed_blob = bytearray(patched)
            self._dirty = True

            merc['name'] = ''
            merc['name_present'] = False
            merc['name_length'] = 0
            self._merc_table.item(row, 5).setText("(unnamed)")
            self._merc_table.item(row, 5).setForeground(QColor(COLORS['text_dim']))
            self._merc_status.setText(f"Cleared name from mercenary #{row} — save with Ctrl+S")

        except Exception as e:
            import traceback; traceback.print_exc()
            QMessageBox.critical(self, "Clear Name Error", str(e))

    def _merc_label_all(self) -> None:
        if not self._save_data or not self._merc_entries:
            QMessageBox.warning(self, "Mercenary", "Load a save and refresh the list first.")
            return

        reply = QMessageBox.question(
            self, "Label All Mercenaries",
            f"Name all {len(self._merc_entries)} mercenaries with M_<merc_no>?\n\n"
            f"This lets you identify each one in-game.\n"
            f"After, rename the ones you want and clear the rest.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        try:
            from save_pet_rename import patch_mercenary_name, parse_reflection_layout, find_mercenary_bitmap_positions

            patched = bytearray(self._save_data.decompressed_blob)
            labeled = 0

            for merc in self._merc_entries:
                label = f"M_{merc['merc_no']}"
                try:
                    layout = parse_reflection_layout(bytes(patched))
                    mercs_now = find_mercenary_bitmap_positions(bytes(patched), layout)
                    target = next((m for m in mercs_now if m['mercenary_no'] == merc['merc_no']), None)
                    if target:
                        patched = patch_mercenary_name(patched, layout, target, label)
                        labeled += 1
                except Exception:
                    pass

            self._save_data.decompressed_blob = bytearray(patched)
            self._dirty = True
            self._merc_refresh()
            self._merc_status.setText(f"Labeled {labeled}/{len(self._merc_entries)} mercenaries — save with Ctrl+S")

        except ImportError:
            QMessageBox.critical(self, "Error", "save_pet_rename module not found.")
        except Exception as e:
            import traceback; traceback.print_exc()
            QMessageBox.critical(self, "Label All Error", str(e))

    CONFIRMED_MOUNT_KEYS = [1003918, 1003917, 1003919, 1003912, 1003915, 1001984]

    SIMPLE_TEMPLATE_KEYS = [k for k, (name, tmpl) in MOUNT_TEMPLATES.items()
                            if tmpl is None]

    def _unlock_all_confirmed_mounts(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Mount Unlock", "Load a save file first.")
            return

        names = [self.MOUNT_TEMPLATES[k][0] for k in self.CONFIRMED_MOUNT_KEYS]
        reply = QMessageBox.question(
            self, "Unlock All Confirmed Mounts",
            f"Unlock these 5 mounts?\n\n" + "\n".join(f"  - {n}" for n in names) +
            "\n\nAlready-owned mounts will be skipped.\nSave (Ctrl+S) afterward.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        unlocked = 0
        skipped = 0
        for ck in self.CONFIRMED_MOUNT_KEYS:
            try:
                self._unlock_mount_generic(ck, silent=True)
                unlocked += 1
            except Exception as e:
                if "already" in str(e).lower():
                    skipped += 1
                else:
                    skipped += 1

        self._merc_refresh()
        self._merc_status.setText(f"Unlocked {unlocked} mounts, {skipped} skipped — save with Ctrl+S")
        QMessageBox.information(self, "Mounts Unlocked",
            f"Unlocked {unlocked} mounts, {skipped} already owned.\n\nSave (Ctrl+S) and reload in-game.")

