    def _load_quest_names(self) -> None:
        try:
            import json as _json
            for base in [os.path.dirname(os.path.abspath(__file__)), getattr(sys, '_MEIPASS', '')]:
                p = os.path.join(base, 'quest_names.json')
                if os.path.isfile(p):
                    with open(p, 'r') as f:
                        data = _json.load(f)
                    self._quest_names = {e['key']: e.get('display', e['name']) for e in data}
                    break
        except Exception:
            pass

    def _preparse_quests(self) -> None:
        self._quest_entries = []
        self._mission_entries = []

        if not self._save_data:
            return

        try:
            import sys as _sys
            import os as _os
            desktop = _os.path.join(_os.path.dirname(_os.path.abspath(__file__)), 'desktopeditor')
            if desktop not in _sys.path:
                _sys.path.insert(0, desktop)
            import save_parser as sp

            raw = self._save_data.decompressed_blob
            result = sp.build_result_from_raw(bytes(raw), {'input_kind': 'raw_blob'})

            mission_names = {}
            try:
                import json as _json
                for base in [os.path.dirname(os.path.abspath(__file__)), getattr(sys, '_MEIPASS', '')]:
                    p = os.path.join(base, 'mission_names.json')
                    if os.path.isfile(p):
                        with open(p, 'r') as f:
                            mdata = _json.load(f)
                        mission_names = {e['key']: e.get('display', e['name']) for e in mdata}
                        break
            except Exception:
                pass

            for obj in result['objects']:
                if obj.class_name != 'QuestSaveData':
                    continue
                for f in obj.fields:
                    if f.name == '_questStateList' and f.list_elements:
                        for elem in f.list_elements:
                            entry = {'key': 0, 'state': 0, 'state_offset': -1, 'state_size': 4,
                                     'has_completed': False, 'is_mission': False, 'name': ''}
                            for cf in (elem.child_fields or []):
                                if cf.name == '_questKey' and cf.present:
                                    entry['key'] = struct.unpack_from('<I', raw, cf.start_offset)[0]
                                elif cf.name == '_state' and cf.present:
                                    sz = cf.end_offset - cf.start_offset
                                    entry['state_size'] = sz
                                    if sz == 1:
                                        entry['state'] = raw[cf.start_offset]
                                    elif sz == 2:
                                        entry['state'] = struct.unpack_from('<H', raw, cf.start_offset)[0]
                                    else:
                                        entry['state'] = struct.unpack_from('<I', raw, cf.start_offset)[0]
                                    entry['state_offset'] = cf.start_offset
                                elif cf.name == '_completedTime' and cf.present:
                                    entry['has_completed'] = True
                            entry['name'] = self._quest_names.get(entry['key'], f'Unknown_{entry["key"]}')
                            self._quest_entries.append(entry)

                    if f.name == '_missionStateList' and f.list_elements:
                        for elem in f.list_elements:
                            entry = {'key': 0, 'state': 0, 'state_offset': -1, 'state_size': 4,
                                     'has_completed': False, 'is_mission': True, 'name': ''}
                            for cf in (elem.child_fields or []):
                                if cf.name == '_key' and cf.present:
                                    entry['key'] = struct.unpack_from('<I', raw, cf.start_offset)[0]
                                elif cf.name == '_state' and cf.present:
                                    sz = cf.end_offset - cf.start_offset
                                    entry['state_size'] = sz
                                    if sz == 1:
                                        entry['state'] = raw[cf.start_offset]
                                    elif sz == 2:
                                        entry['state'] = struct.unpack_from('<H', raw, cf.start_offset)[0]
                                    else:
                                        entry['state'] = struct.unpack_from('<I', raw, cf.start_offset)[0]
                                    entry['state_offset'] = cf.start_offset
                                elif cf.name == '_completedTime' and cf.present:
                                    entry['has_completed'] = True
                            entry['name'] = mission_names.get(entry['key'], f'Mission_{entry["key"]}')
                            self._mission_entries.append(entry)
                break

        except Exception as e:
            import traceback; traceback.print_exc()

    def _populate_quests(self) -> None:
        if not self._quest_entries and self._save_data:
            from PySide6.QtWidgets import QProgressDialog
            prog = QProgressDialog("Parsing quest data...", None, 0, 0, self)
            prog.setWindowTitle("Loading Quests")
            prog.setMinimumDuration(0)
            prog.setWindowModality(Qt.WindowModal)
            prog.show()
            QApplication.processEvents()
            self._preparse_quests()
            prog.close()

        self._filter_quests()

    def _filter_quests(self, _text=None) -> None:
        table = self._quest_table
        table.setSortingEnabled(False)

        search = self._quest_search.text().strip().lower()
        filt = self._quest_filter.currentText()
        show_type = self._quest_type_filter.currentText() if hasattr(self, '_quest_type_filter') else 'Quests'

        if show_type == 'Quests':
            source = self._quest_entries
        elif show_type == 'Missions':
            source = self._mission_entries
        else:
            source = self._quest_entries + self._mission_entries

        filtered = []
        for e in source:
            if search and search not in e['name'].lower() and search not in str(e['key']):
                continue
            state_name = self._QUEST_STATE_NAMES.get(e['state'], f'Unknown (0x{e["state"]:04X})')
            if filt == "In Progress" and 'Progress' not in state_name:
                continue
            if filt == "Completed" and 'Completed' not in state_name:
                continue
            if filt == "Available" and 'Available' not in state_name:
                continue
            if filt == "Locked" and state_name != 'Locked':
                continue
            filtered.append(e)

        table.setRowCount(len(filtered))
        for row, e in enumerate(filtered):
            state_name = self._QUEST_STATE_NAMES.get(e['state'], f'Unknown (0x{e["state"]:04X})')

            key_item = QTableWidgetItem(str(e['key']))
            key_item.setData(Qt.UserRole, e)
            table.setItem(row, 0, key_item)

            name_item = QTableWidgetItem(e['name'])
            if 'Completed' in state_name:
                name_item.setForeground(QBrush(QColor(COLORS['success'])))
            elif 'Progress' in state_name:
                name_item.setForeground(QBrush(QColor(COLORS['accent'])))
            elif state_name == 'Locked':
                name_item.setForeground(QBrush(QColor(COLORS['text_dim'])))
            table.setItem(row, 1, name_item)

            type_str = "Mission" if e.get('is_mission') else "Quest"
            table.setItem(row, 2, QTableWidgetItem(type_str))
            table.setItem(row, 3, QTableWidgetItem(f'0x{e["state"]:04X}'))
            table.setItem(row, 4, QTableWidgetItem(state_name))
            table.setItem(row, 5, QTableWidgetItem("Yes" if e['has_completed'] else ""))

        table.setSortingEnabled(True)

        completed = sum(1 for e in source if e['state'] in (0x1105, 0x1905))
        in_prog = sum(1 for e in source if e['state'] in (0x0905, 0x1102))
        self._quest_count.setText(
            f"{len(self._quest_entries)} quests + {len(self._mission_entries)} missions  |  "
            f"{in_prog} in progress  |  {completed} completed  |  "
            f"Showing {len(filtered)}"
        )

    def _get_selected_quest(self):
        rows = self._quest_table.selectionModel().selectedRows()
        if not rows:
            return None
        row = rows[0].row()
        item = self._quest_table.item(row, 0)
        if item:
            return item.data(Qt.UserRole)
        return None

    def _quest_mark_completed(self) -> None:
        if not self._save_data:
            return
        entry = self._get_selected_quest()
        if not entry:
            QMessageBox.information(self, "Quests", "Select a quest first.")
            return
        if entry['state_offset'] < 0:
            QMessageBox.warning(self, "Quests", "Quest state offset not found.")
            return

        entry_type = "Mission" if entry.get('is_mission') else "Quest"
        state_name = self._QUEST_STATE_NAMES.get(entry['state'], f'0x{entry["state"]:04X}')

        if not entry.get('has_completed') and entry.get('is_mission'):
            reply = QMessageBox.question(
                self, "Complete Mission (PARC Expansion)",
                f"This mission needs timestamp fields inserted.\n\n"
                f"Key: {entry['key']}\n"
                f"Name: {entry['name']}\n"
                f"Current state: {state_name}\n\n"
                f"This modifies the save structure. Proceed?",
                QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
            )
            if reply != QMessageBox.Yes:
                return
            try:
                import parc_inserter3 as pi
                blob = bytearray(self._save_data.decompressed_blob)
                ok, new_blob, msg = pi.complete_mission_entry(blob, entry['key'])
                if ok:
                    self._save_data.decompressed_blob = bytearray(new_blob)
                    self._dirty = True
                    self._quest_entries = []
                    self._mission_entries = []
                    self._preparse_quests()
                    self._filter_quests()
                    self._update_status(f"Completed (PARC expanded): {entry['name']}")
                    QMessageBox.information(self, "Mission Completed",
                        f"{msg}\n\nSave (Ctrl+S) for changes to take effect.")
                else:
                    QMessageBox.warning(self, "Completion Failed", msg)
            except Exception as e:
                import traceback; traceback.print_exc()
                QMessageBox.critical(self, "Error", str(e))
            return

        reply = QMessageBox.question(
            self, f"Mark {entry_type} Completed",
            f"Set '{entry['name']}' (key={entry['key']}) to Completed?\n\n"
            f"Current state: {state_name}\n\n"
            f"This may allow you to skip past a bugged quest.\n"
            f"Can be undone with Ctrl+Z.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        blob = self._save_data.decompressed_blob
        off = entry['state_offset']
        sz = entry.get('state_size', 4)
        old_bytes = bytes(blob[off:off+sz])
        _write_quest_state(blob, entry, 0x1905)
        self._undo_stack.append(UndoEntry(
            description=f"{entry_type} '{entry['name']}' -> Completed",
            patches=[(off, old_bytes, bytes(blob[off:off+sz]))],
        ))
        self._dirty = True
        self._filter_quests()
        self._update_status(f"{entry_type} '{entry['name']}' set to Completed")

    def _quest_reset_progress(self) -> None:
        if not self._save_data:
            return
        entry = self._get_selected_quest()
        if not entry:
            QMessageBox.information(self, "Quests", "Select a quest first.")
            return
        if entry['state_offset'] < 0:
            QMessageBox.warning(self, "Quests", "Quest state offset not found.")
            return

        reply = QMessageBox.question(
            self, "Reset Quest",
            f"Reset quest '{entry['name']}' (key={entry['key']}) to In Progress?\n\n"
            f"Can be undone with Ctrl+Z.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        blob = self._save_data.decompressed_blob
        off = entry['state_offset']
        sz = entry.get('state_size', 4)
        old_bytes = bytes(blob[off:off+sz])
        new_state = 0x0905
        _write_quest_state(blob, entry, new_state)
        self._undo_stack.append(UndoEntry(
            description=f"Quest '{entry['name']}' -> In Progress",
            patches=[(off, old_bytes, bytes(blob[off:off+sz]))],
        ))
        self._dirty = True
        self._filter_quests()
        entry_type = "Mission" if entry.get('is_mission') else "Quest"
        self._update_status(f"{entry_type} '{entry['name']}' reset to In Progress")


