    def _qe_load(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Quest Editor", "Load a save file first.")
            return

        self._qe_status.setText("Parsing quests...")
        QApplication.processEvents()

        try:
            self._qe_window = QuestEditorWindow(
                self._save_data, self._loaded_path or "", self
            )
            self._qe_window._parse_quests()

            self._qe_entries = self._qe_window._quest_entries + self._qe_window._mission_entries

            try:
                _base_qdb = getattr(__import__('sys'), '_MEIPASS', os.path.dirname(os.path.abspath(__file__)))
                _qdb_path = os.path.join(_base_qdb, 'quest_database.json')
                if os.path.isfile(_qdb_path):
                    with open(_qdb_path, 'r', encoding='utf-8') as _f:
                        _qdb = {e['key']: e for e in json.load(_f)}
                    for entry in self._qe_entries:
                        info = _qdb.get(entry.get('key'))
                        if info:
                            cat_name = info.get('category_name', '')
                            chars = info.get('character_names', [])
                            missions = info.get('missions', [])
                            if cat_name:
                                entry['quest_category'] = cat_name
                            if chars:
                                entry['character_restriction'] = ', '.join(chars)
                            if missions:
                                entry['mission_keys'] = missions
                            if not entry.get('display') or entry['display'] == entry.get('name'):
                                display = info.get('display', '')
                                if display and display != info.get('name'):
                                    entry['display'] = display
            except Exception:
                pass

            try:
                import sys as _sys
                import save_parser as _sp
                from quest_deep_parser import parse_quest_deep

                raw = bytes(self._save_data.decompressed_blob)
                _result = _sp.build_result_from_raw(raw, {'input_kind': 'raw_blob'})

                _base = getattr(_sys, '_MEIPASS', os.path.dirname(os.path.abspath(__file__)))
                _qn = {}
                _mn = {}
                try:
                    _qn_path = os.path.join(_base, 'quest_names.json')
                    _qn_raw = json.load(open(_qn_path, 'r', encoding='utf-8'))
                    if isinstance(_qn_raw, list):
                        _qn = {e['key']: e.get('display', e.get('name', '')) for e in _qn_raw}
                    else:
                        _qn = _qn_raw
                except: pass
                try:
                    _mn_path = os.path.join(_base, 'mission_names.json')
                    _mn_raw = json.load(open(_mn_path, 'r', encoding='utf-8'))
                    if isinstance(_mn_raw, list):
                        _mn = {e['key']: e.get('display', e.get('name', '')) for e in _mn_raw}
                    else:
                        _mn = _mn_raw
                except: pass

                self._qe_deep_data = parse_quest_deep(raw, _result, _qn, _mn)

                stage_count = len(self._qe_deep_data.stages)
                gimmick_count = len(self._qe_deep_data.gimmick_links)
                npc_count = len(self._qe_deep_data.npc_blocks)
                xref_count = len(self._qe_deep_data.quest_to_stages)
                skill_count = len(self._qe_deep_data.skills_learned)
                friend_count = len(self._qe_deep_data.friendships)
                self._qe_status.setText(
                    f"{len(self._qe_entries)} quests/missions, "
                    f"{stage_count} stages ({xref_count} cross-refs), "
                    f"{gimmick_count} gimmicks, {npc_count} NPCs, "
                    f"{skill_count} skills, {friend_count} friendships")
            except Exception as _de:
                import traceback
                _tb = traceback.format_exc()
                log.warning("Deep quest parse failed: %s\n%s", _de, _tb)
                self._qe_status.setText(f"{len(self._qe_entries)} quests/missions (deep parse failed: {_de})")

            self._qe_filter()

            try:
                self._qe_filter_gimmicks()
            except: pass

            try:
                self._qe_table.selectionModel().selectionChanged.connect(self._qe_show_stages)
            except: pass

        except Exception as e:
            import traceback; traceback.print_exc()
            self._qe_status.setText(f"Error: {e}")

    def _qe_filter(self, *_args) -> None:
        if not self._qe_entries:
            return

        search = self._qe_search.text().lower().strip()
        state_filter = self._qe_state_filter.currentText()

        filtered = []
        for entry in self._qe_entries:
            if search and search not in entry.get('display', entry['name']).lower() and search not in str(entry['key']):
                continue
            state_name = entry.get('state_name', '')
            if state_filter != "All":
                if state_filter.lower() not in state_name.lower():
                    continue
            filtered.append(entry)

        table = self._qe_table
        table.setSortingEnabled(False)
        table.setRowCount(len(filtered))

        STATE_COLORS = {
            'Completed': COLORS['success'], 'Fully Completed': COLORS['success'],
            'In Progress': COLORS['accent'], 'Available': COLORS['warning'],
            'Locked': COLORS['text_dim'],
        }

        for row, entry in enumerate(filtered):
            key_w = QTableWidgetItem()
            key_w.setData(Qt.DisplayRole, entry['key'])
            key_w.setData(Qt.UserRole, entry)
            table.setItem(row, 0, key_w)

            display = entry.get('display', entry['name'])
            name_w = QTableWidgetItem(display)
            name_w.setToolTip(entry['name'])
            table.setItem(row, 1, name_w)

            state_name = entry.get('state_name', '?')
            state_w = QTableWidgetItem(state_name)
            color = STATE_COLORS.get(state_name, COLORS['text'])
            state_w.setForeground(QBrush(QColor(color)))
            table.setItem(row, 2, state_w)

            state_hex = f"0x{entry.get('state_raw', 0):04X}"
            table.setItem(row, 3, QTableWidgetItem(state_hex))

            ct = entry.get('completed_time', 0)
            bt = entry.get('branched_time', 0)
            if ct:
                _ch, _crem = divmod(ct, 3600)
                _cm, _cs = divmod(_crem, 60)
                comp_w = QTableWidgetItem(f"{_ch}h{_cm:02d}m")
                comp_w.setForeground(QBrush(QColor(COLORS['success'])))
                tip_parts = [f"Completed at: {_ch}h {_cm:02d}m {_cs:02d}s game-world time (raw={ct})"]
                if bt:
                    _bh, _brem = divmod(bt, 3600)
                    _bm, _bs = divmod(_brem, 60)
                    dur = ct - bt
                    _dh, _drem = divmod(dur, 3600)
                    _dm, _ds = divmod(_drem, 60)
                    tip_parts.append(f"Started at: {_bh}h {_bm:02d}m {_bs:02d}s (raw={bt})")
                    tip_parts.append(f"Duration: {_dh}h {_dm:02d}m {_ds:02d}s")
                comp_w.setToolTip("\n".join(tip_parts))
            else:
                comp_w = QTableWidgetItem("-")
                comp_w.setToolTip("No _completedTime — needs PARC expansion to complete")
            table.setItem(row, 4, comp_w)

            is_mission = entry.get('is_mission', False)
            needs_expand = entry.get('needs_parc_expand', False)
            has_ct = entry.get('has_completed', False)
            state_sz = entry.get('state_size', 4)
            mask_hex = entry.get('mask_hex', '')

            if has_ct:
                type_str = "OK"
                type_color = COLORS['success']
                tip = f"{'Mission' if is_mission else 'Quest'} | Has _completedTime | State: {state_sz}B | Mask: {mask_hex}"
            elif needs_expand and is_mission:
                type_str = "PARC"
                type_color = COLORS['warning']
                tip = (f"Mission | No _completedTime — needs PARC expansion to complete\n"
                       f"State: {state_sz}B | Mask: {mask_hex}\n"
                       f"Mark Completed will auto-insert timestamp fields")
            elif needs_expand:
                type_str = "PARC"
                type_color = COLORS['warning']
                tip = (f"Quest | No _completedTime — may need PARC expansion\n"
                       f"State: {state_sz}B | Mask: {mask_hex}")
            else:
                type_str = "OK"
                type_color = COLORS['text']
                tip = f"{'Mission' if is_mission else 'Quest'} | State: {state_sz}B | Mask: {mask_hex}"

            type_w = QTableWidgetItem(type_str)
            type_w.setForeground(QBrush(QColor(type_color)))
            type_w.setToolTip(tip)
            table.setItem(row, 5, type_w)

            cat_name = entry.get('quest_category', '')
            cat_w = QTableWidgetItem(cat_name)
            if cat_name == 'Main Story':
                cat_w.setForeground(QBrush(QColor(COLORS['accent'])))
            elif cat_name == 'Regional':
                cat_w.setForeground(QBrush(QColor(COLORS['warning'])))
            table.setItem(row, 6, cat_w)

            chars = entry.get('character_restriction', '')
            char_w = QTableWidgetItem(chars)
            if chars:
                char_w.setForeground(QBrush(QColor("#4FC3F7")))
            table.setItem(row, 7, char_w)

            stage_count = 0
            if self._qe_deep_data:
                stage_keys = self._qe_deep_data.quest_to_stages.get(entry.get('key', 0), [])
                stage_count = len(stage_keys)
            stages_w = QTableWidgetItem(str(stage_count) if stage_count else "")
            if stage_count > 0:
                stages_w.setForeground(QBrush(QColor(COLORS['success'])))
            table.setItem(row, 8, stages_w)

            chain = entry.get('chain')
            if chain and isinstance(chain, list) and chain:
                c = chain[0]
                chain_text = f"{c.get('chain_name', '?')} ({c.get('chain_size', '?')})"
                chain_w = QTableWidgetItem(chain_text)
                chain_w.setForeground(QBrush(QColor(COLORS['warning'])))
            else:
                chain_w = QTableWidgetItem("")
            table.setItem(row, 9, chain_w)

        table.setSortingEnabled(True)
        self._qe_status.setText(f"{len(filtered)}/{len(self._qe_entries)} shown")

    def _qe_get_selected_entry(self):
        rows = self._qe_table.selectionModel().selectedRows()
        if not rows:
            return None
        w = self._qe_table.item(rows[0].row(), 0)
        return w.data(Qt.UserRole) if w else None

    def _qe_set_state(self, entry: dict, new_state: int) -> bool:
        if not self._save_data or entry.get('state_offset', -1) < 0:
            return False
        blob = self._save_data.decompressed_blob
        _write_quest_state(blob, entry, new_state)
        return True

    def _qe_force_state(self) -> None:
        entry = self._qe_get_selected_entry()
        if not entry:
            QMessageBox.information(self, "Set Quest State", "Select a quest first.")
            return

        new_state = self._qe_state_combo.currentData()
        state_name = self._qe_state_combo.currentText()
        quest_name = entry.get('display', entry['name'])
        cur_raw = entry.get('state', 0)

        reply = QMessageBox.question(
            self, "Set Quest State",
            f"Force-set '{quest_name}' to {state_name}?\n\n"
            f"Current raw state: 0x{cur_raw:04X}\n"
            f"New state: 0x{new_state:04X}\n\n"
            f"Use this to fix corrupted or bugged quests.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        if self._qe_set_state(entry, new_state):
            self._dirty = True
            self._qe_filter()
            self._update_status(f"Set {quest_name} → {state_name}")
        else:
            QMessageBox.warning(self, "Set Quest State",
                "Could not set state — quest may not have a valid state offset.")


    def _qe_show_stages(self, selected=None, _deselected=None):
        if not self._qe_deep_data:
            return
        rows = self._qe_table.selectionModel().selectedRows()
        if not rows:
            return
        key_item = self._qe_table.item(rows[0].row(), 0)
        if not key_item:
            return
        entry = key_item.data(Qt.UserRole)
        if not entry:
            return

        quest_key = entry.get('key', 0)
        stage_keys = self._qe_deep_data.quest_to_stages.get(quest_key, [])
        if stage_keys:
            linked = [self._qe_deep_data.stage_map[k] for k in stage_keys
                      if k in self._qe_deep_data.stage_map]
            if linked:
                self._qe_stage_search.clear()
                self._qe_stage_state_filter.setCurrentIndex(0)
                self._qe_populate_stage_table(linked)
                self._qe_stage_status.setText(
                    f"Quest {quest_key}: {len(linked)} linked stages "
                    f"({len(stage_keys)} in pabgb, {len(linked)} found in save)")
                return

        self._qe_stage_status.setText(
            f"Quest {quest_key}: no stage cross-refs found - use search/filter above")

    def _qe_load_stage_names(self):
        if hasattr(self, '_qe_stage_names'):
            return self._qe_stage_names
        self._qe_stage_names = {}
        try:
            import sys as _sys
            base = getattr(_sys, '_MEIPASS', os.path.dirname(os.path.abspath(__file__)))
            sp = os.path.join(base, 'stage_names.json')
            if os.path.exists(sp):
                with open(sp, 'r', encoding='utf-8') as f:
                    self._qe_stage_names = json.load(f)
        except Exception:
            pass
        return self._qe_stage_names

    def _qe_populate_stage_table(self, stages_list):
        STAGE_STATES = {1: 'Locked', 2: 'Available', 3: 'InProgress', 4: 'Ready', 5: 'Completed'}

        stage_names = self._qe_load_stage_names()

        stage_to_quest_name = {}
        if self._qe_deep_data:
            quest_names = getattr(self, '_quest_names', {})
            for qk, skeys in self._qe_deep_data.quest_to_stages.items():
                qname = quest_names.get(qk, quest_names.get(str(qk), ''))
                for sk in skeys:
                    stage_to_quest_name[sk] = qname

        self._qe_stage_table.setRowCount(len(stages_list))
        for row_idx, stage in enumerate(stages_list):
            item = QTableWidgetItem(str(stage.key))
            item.setData(Qt.UserRole, stage)
            self._qe_stage_table.setItem(row_idx, 0, item)

            sname = stage_names.get(str(stage.key), '')
            name_item = QTableWidgetItem(sname)
            name_item.setToolTip(sname)
            self._qe_stage_table.setItem(row_idx, 1, name_item)

            state_name = STAGE_STATES.get(stage.state, f'?({stage.state})')
            item = QTableWidgetItem(state_name)
            if stage.state == 5:
                item.setForeground(QColor(COLORS['success']))
            elif stage.state == 3:
                item.setForeground(QColor(COLORS['accent']))
            elif stage.state == 1:
                item.setForeground(QColor(COLORS['text_dim']))
            self._qe_stage_table.setItem(row_idx, 2, item)

            qname = stage_to_quest_name.get(stage.key, '')
            self._qe_stage_table.setItem(row_idx, 3, QTableWidgetItem(qname))

            item = QTableWidgetItem('Yes' if stage.completed_time and stage.completed_time > 0 else 'No')
            self._qe_stage_table.setItem(row_idx, 4, item)

        self._qe_stage_table.resizeColumnsToContents()

    def _qe_filter_stages(self, *_args):
        if not self._qe_deep_data or not self._qe_deep_data.stages:
            return

        search = self._qe_stage_search.text().strip()
        state_filter = self._qe_stage_state_filter.currentText()

        filter_state = None
        if '(3)' in state_filter: filter_state = 3
        elif '(4)' in state_filter: filter_state = 4
        elif '(5)' in state_filter: filter_state = 5
        elif '(1)' in state_filter: filter_state = 1
        elif '(2)' in state_filter: filter_state = 2

        if not search and filter_state is None:
            self._qe_stage_table.setRowCount(0)
            self._qe_stage_status.setText(
                f"{len(self._qe_deep_data.stages)} stages total - use search or filter to view")
            return

        filtered = []
        stage_names = self._qe_load_stage_names()
        search_lower = search.lower() if search else ''

        stage_to_quest_name = {}
        if search and not search.isdigit():
            quest_names = getattr(self, '_quest_names', {})
            for qk, skeys in self._qe_deep_data.quest_to_stages.items():
                qname = quest_names.get(qk, quest_names.get(str(qk), ''))
                for sk in skeys:
                    stage_to_quest_name[sk] = qname

        for stage in self._qe_deep_data.stages:
            if filter_state is not None and stage.state != filter_state:
                continue
            if search:
                if search.isdigit():
                    if str(stage.key) != search and not str(stage.key).startswith(search):
                        continue
                else:
                    sname = stage_names.get(str(stage.key), '').lower()
                    qname = stage_to_quest_name.get(stage.key, '').lower()
                    if search_lower not in sname and search_lower not in qname:
                        continue
            filtered.append(stage)
            if len(filtered) >= 2000:
                break

        self._qe_populate_stage_table(filtered)
        cap_note = " (capped at 2000)" if len(filtered) >= 2000 else ""
        self._qe_stage_status.setText(f"{len(filtered)} stages shown{cap_note}")

    def _qe_complete_stages(self):
        if not self._save_data or not self._qe_deep_data:
            return
        rows = self._qe_stage_table.selectionModel().selectedRows()
        if not rows:
            QMessageBox.information(self, "Stages", "Select stages to complete.")
            return

        raw = self._save_data.decompressed_blob
        count = 0
        for idx in rows:
            item = self._qe_stage_table.item(idx.row(), 0)
            if not item:
                continue
            stage = item.data(Qt.UserRole)
            if not stage or not stage.state_offset:
                continue
            raw[stage.state_offset] = 5
            stage.state = 5
            count += 1

        self._qe_stage_status.setText(f"Completed {count} stages")
        self._qe_show_stages(None)
        self._mark_modified()

    def _qe_reset_stages(self):
        if not self._save_data or not self._qe_deep_data:
            return
        rows = self._qe_stage_table.selectionModel().selectedRows()
        if not rows:
            QMessageBox.information(self, "Stages", "Select stages to reset.")
            return

        raw = self._save_data.decompressed_blob
        count = 0
        for idx in rows:
            item = self._qe_stage_table.item(idx.row(), 0)
            if not item:
                continue
            stage = item.data(Qt.UserRole)
            if not stage or not stage.state_offset:
                continue
            raw[stage.state_offset] = 2
            stage.state = 2
            count += 1

        self._qe_stage_status.setText(f"Reset {count} stages to Available")
        self._qe_show_stages(None)
        self._mark_modified()

    def _qe_get_selected_quest_key(self):
        rows = self._qe_table.selectionModel().selectedRows()
        if not rows:
            return None
        key_item = self._qe_table.item(rows[0].row(), 0)
        if not key_item:
            return None
        entry = key_item.data(Qt.UserRole)
        return entry.get('key') if entry else None

    def _qe_complete_quest_stages(self):
        if not self._save_data or not self._qe_deep_data:
            return
        quest_key = self._qe_get_selected_quest_key()
        if not quest_key:
            QMessageBox.information(self, "Stages", "Select a quest first.")
            return
        stage_keys = self._qe_deep_data.quest_to_stages.get(quest_key, [])
        if not stage_keys:
            QMessageBox.information(self, "Stages",
                f"Quest {quest_key} has no stage cross-refs in pabgb data.")
            return

        quest_name = self._quest_names.get(quest_key, self._quest_names.get(str(quest_key), f'Unknown_{quest_key}'))
        reply = QMessageBox.question(self, "Complete Quest Stages",
            f"Complete ALL {len(stage_keys)} stages for:\n{quest_name} ({quest_key})\n\n"
            f"This sets every linked stage to Completed (state=5).\n"
            f"Make sure you have a backup!",
            QMessageBox.Yes | QMessageBox.No)
        if reply != QMessageBox.Yes:
            return

        raw = self._save_data.decompressed_blob
        count = 0
        missing = 0
        for sk in stage_keys:
            stage = self._qe_deep_data.stage_map.get(sk)
            if stage and stage.state_offset:
                raw[stage.state_offset] = 5
                stage.state = 5
                count += 1
            else:
                missing += 1

        msg = f"Completed {count}/{len(stage_keys)} stages for {quest_name}"
        if missing:
            msg += f" ({missing} not found in save)"
        self._qe_stage_status.setText(msg)
        self._qe_show_stages(None)
        self._mark_modified()

    def _qe_reset_quest_stages(self):
        if not self._save_data or not self._qe_deep_data:
            return
        quest_key = self._qe_get_selected_quest_key()
        if not quest_key:
            QMessageBox.information(self, "Stages", "Select a quest first.")
            return
        stage_keys = self._qe_deep_data.quest_to_stages.get(quest_key, [])
        if not stage_keys:
            QMessageBox.information(self, "Stages",
                f"Quest {quest_key} has no stage cross-refs in pabgb data.")
            return

        quest_name = self._quest_names.get(quest_key, self._quest_names.get(str(quest_key), f'Unknown_{quest_key}'))
        reply = QMessageBox.question(self, "Reset Quest Stages",
            f"Reset ALL {len(stage_keys)} stages for:\n{quest_name} ({quest_key})\n\n"
            f"This sets every linked stage to Available (state=2).\n"
            f"The quest can then be re-triggered in game.",
            QMessageBox.Yes | QMessageBox.No)
        if reply != QMessageBox.Yes:
            return

        raw = self._save_data.decompressed_blob
