    def _qe_stage_context_menu(self, pos):
        from PySide6.QtWidgets import QMenu
        rows = self._qe_stage_table.selectionModel().selectedRows()
        if not rows:
            return

        menu = QMenu(self)
        complete_act = menu.addAction(f"Complete {len(rows)} selected stages")
        reset_act = menu.addAction(f"Reset {len(rows)} stages to Available")
        menu.addSeparator()
        info_act = menu.addAction("Show stage details")

        action = menu.exec(self._qe_stage_table.viewport().mapToGlobal(pos))
        if action == complete_act:
            self._qe_complete_stages()
        elif action == reset_act:
            self._qe_reset_stages()
        elif action == info_act:
            item = self._qe_stage_table.item(rows[0].row(), 0)
            if item:
                stage = item.data(Qt.UserRole)
                if stage:
                    from quest_deep_parser import get_gimmicks_for_stage, QUEST_STATES
                    gimmicks = get_gimmicks_for_stage(self._qe_deep_data, stage.key)
                    info = (
                        f"Stage Key: {stage.key}\n"
                        f"State: {QUEST_STATES.get(stage.state, '?')} ({stage.state})\n"
                        f"Completed Count: {stage.completed_count or 0}\n"
                        f"Completed Time: {stage.completed_time or 0}\n"
                        f"Branched Time: {stage.branched_time or 0}\n"
                        f"Delayed Time: {stage.delayed_time or 0}\n"
                        f"Wait Branch: {stage.is_wait_branch}\n"
                        f"Skip Complete: {stage.is_skip_complete}\n"
                        f"Position: {stage.position}\n"
                        f"Connected Actors: {len(stage.connected_actors)}\n"
                        f"Linked Gimmicks: {len(gimmicks)}\n"
                    )
                    for i, a in enumerate(stage.connected_actors):
                        info += f"  Actor {i}: char={a.character_key} merc={a.mercenary_no}\n"
                    for i, g in enumerate(gimmicks[:10]):
                        info += f"  Gimmick {i}: key={g.gimmick_info_key} broken={g.is_broken} locked={g.is_lock_state}\n"
                    QMessageBox.information(self, "Stage Details", info)

    def _qe_load_char_names(self):
        if hasattr(self, '_qe_char_names'):
            return self._qe_char_names
        self._qe_char_names = {}
        try:
            import sys as _sys
            base = getattr(_sys, '_MEIPASS', os.path.dirname(os.path.abspath(__file__)))
            gm_path = os.path.join(base, 'game_map.json')
            if os.path.exists(gm_path):
                with open(gm_path, 'r', encoding='utf-8') as f:
                    gm = json.load(f)
                chars = gm.get('characters', {})
                if isinstance(chars, dict):
                    for k, v in chars.items():
                        if isinstance(v, dict):
                            self._qe_char_names[int(k)] = v.get('name', '')
        except Exception:
            pass
        return self._qe_char_names

    def _qe_load_gimmick_names(self):
        if hasattr(self, '_qe_gimmick_names'):
            return self._qe_gimmick_names
        self._qe_gimmick_names = {}
        try:
            import sys as _sys
            base = getattr(_sys, '_MEIPASS', os.path.dirname(os.path.abspath(__file__)))
            gp = os.path.join(base, 'gimmick_respawn_timers.json')
            if os.path.exists(gp):
                with open(gp, 'r', encoding='utf-8') as f:
                    for e in json.load(f):
                        if isinstance(e, dict) and 'key' in e:
                            self._qe_gimmick_names[e['key']] = e.get('name', '')
        except Exception:
            pass
        return self._qe_gimmick_names

    def _qe_filter_gimmicks(self, *_args):
        if not self._qe_deep_data or not self._qe_deep_data.gimmick_links:
            self._qe_gimmick_table.setRowCount(0)
            self._qe_gimmick_status.setText("No gimmick data loaded")
            return

        gimmick_names = self._qe_load_gimmick_names()
        REASON_NAMES = {1: 'Initial', 2: 'Interact', 4: 'Spawned', 5: 'Broken',
                        6: 'Looted', 7: 'Opened', 11: 'Locked', 12: 'Unlocked',
                        13: 'Activated', 15: 'Completed'}

        filt = self._qe_gimmick_filter.currentText()
        filtered = []
        for g in self._qe_deep_data.gimmick_links:
            if "State Tracked" in filt:
                has_state = (g.is_broken is not None or g.is_lock_state is not None
                             or g.field_save_reason is not None)
                if not has_state:
                    continue
            filtered.append(g)
            if len(filtered) >= 2000:
                break

        self._qe_gimmick_table.setRowCount(len(filtered))
        for i, g in enumerate(filtered):
            gk = QTableWidgetItem(str(g.gimmick_key or 0))
            gk.setData(Qt.UserRole, g)
            self._qe_gimmick_table.setItem(i, 0, gk)

            name = gimmick_names.get(g.gimmick_info_key, gimmick_names.get(g.gimmick_key, ''))
            name_item = QTableWidgetItem(name)
            name_item.setToolTip(f"Info Key: {g.gimmick_info_key or 0}")
            self._qe_gimmick_table.setItem(i, 1, name_item)

            state_parts = []
            if g.is_broken is not None:
                state_parts.append("Broken" if g.is_broken else "Was-Broken")
            if g.is_lock_state is not None:
                state_parts.append("Locked" if g.is_lock_state else "Was-Locked")
            if not state_parts:
                state_parts.append("Tracked")
            state_text = ", ".join(state_parts)
            state_item = QTableWidgetItem(state_text)
            if g.is_broken:
                state_item.setForeground(QColor(COLORS['error']))
            elif g.is_lock_state:
                state_item.setForeground(QColor(COLORS['warning']))
            else:
                state_item.setForeground(QColor(COLORS['text_dim']))
            self._qe_gimmick_table.setItem(i, 2, state_item)

            reason = g.field_save_reason
            reason_text = REASON_NAMES.get(reason, str(reason)) if reason is not None else ""
            self._qe_gimmick_table.setItem(i, 3, QTableWidgetItem(reason_text))

        self._qe_gimmick_table.resizeColumnsToContents()
        total = len(self._qe_deep_data.gimmick_links)
        tracked = sum(1 for g in self._qe_deep_data.gimmick_links
                      if g.is_broken is not None or g.is_lock_state is not None or g.field_save_reason is not None)
        cap = " (capped 2000)" if len(filtered) >= 2000 else ""
        self._qe_gimmick_status.setText(
            f"{len(filtered)} shown{cap} | {tracked} state-tracked / {total} total")

    def _qe_reset_bosses(self):
        if not self._save_data:
            QMessageBox.warning(self, "Reset Encounters", "Load a save file first.")
            return

        reply = QMessageBox.question(self, "Reset All Encounters",
            "Reset ALL encounter completion states?\n\n"
            "This will:\n"
            "  - Zero completedCount + timestamps on ALL stages\n"
            "  - Zero FactionSpawnStageManager (boss triggers)\n\n"
            "Bosses respawn, encounters re-trigger.\n"
            "NPCs, shops, and world life are NOT affected.\n"
            "Your inventory/gear stays.\n\n"
            "MAKE SURE YOU HAVE A BACKUP!",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No)
        if reply != QMessageBox.Yes:
            return

        try:
            import sys as _sys
            _sys.path.insert(0, 'Communitydump/desktopeditor')
            import save_parser as _sp

            self._qe_status.setText("Resetting encounters...")
            QApplication.processEvents()

            raw = self._save_data.decompressed_blob
            result = _sp.build_result_from_raw(bytes(raw), {'input_kind': 'raw_blob'})

            stage_count = 0
            faction_count = 0

            for obj in result['objects']:
                if obj.class_name == 'QuestSaveData':
                    for field in obj.fields:
                        if field.name == '_stageStateData' and field.list_elements:
                            for elem in field.list_elements:
                                cfs = getattr(elem, 'child_fields', None) or []
                                has_cc = False
                                for cf in cfs:
                                    if not cf.present:
                                        continue
                                    if cf.name == '_completedCount':
                                        cc = struct.unpack_from('<H', raw, cf.start_offset)[0]
                                        if cc > 0:
                                            struct.pack_into('<H', raw, cf.start_offset, 0)
                                            has_cc = True
                                    elif cf.name == '_completedTime':
                                        if struct.unpack_from('<Q', raw, cf.start_offset)[0] > 0:
                                            struct.pack_into('<Q', raw, cf.start_offset, 0)
                                    elif cf.name == '_branchedTime':
                                        if struct.unpack_from('<Q', raw, cf.start_offset)[0] > 0:
                                            struct.pack_into('<Q', raw, cf.start_offset, 0)
                                if has_cc:
                                    stage_count += 1


                elif obj.class_name == 'FactionSpawnStageManagerSaveData':
                    for field in obj.fields:
                        if field.list_elements:
                            start = field.start_offset
                            prefix = raw[start]
                            count_off = start + 1 if prefix == 0 else start + 2
                            old = struct.unpack_from('<H', raw, count_off)[0]
                            struct.pack_into('<H', raw, count_off, 0)
                            faction_count = old

            try:
                self._mark_modified()
            except AttributeError:
                pass

            self._qe_status.setText(
                f"Reset: {stage_count} stages, {faction_count} faction spawns")
            QMessageBox.information(self, "Encounters Reset",
                f"World state reverted:\n\n"
                f"  {stage_count} stage completions zeroed\n"
                f"  {faction_count} faction spawn entries cleared\n\n"
                f"Save the file and restart the game.\n"
                f"Bosses, encounters, and events will re-trigger.\n"
                f"NPCs and shops are unaffected.")

        except Exception as e:
            import traceback; traceback.print_exc()
            QMessageBox.critical(self, "Error", f"Failed: {e}")

    _GETOUT_KEYS = {1000542, 195000100, 195000200, 195000400}

    def _qe_disable_boundaries(self):
        if not self._save_data:
            QMessageBox.warning(self, "Boundaries", "Load a save file first.")
            return

        import sys as _sys
        _sys.path.insert(0, 'Communitydump/desktopeditor')
        import save_parser as _sp
        from quest_deep_parser import parse_quest_deep

        try:
            raw = self._save_data.decompressed_blob
            result = _sp.build_result_from_raw(bytes(raw), {'input_kind': 'raw_blob'})
            data = parse_quest_deep(bytes(raw), result)
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to parse save: {e}")
            return

        _names = {1000542: 'GetOut_Region_III', 195000100: 'GetOut_Region_I',
                  195000200: 'GetOut_Region_II', 195000400: 'GetOut_Region_IV'}
        _state_names = {1: 'Locked', 2: 'Available', 3: 'InProgress',
                        4: 'Ready', 5: 'Completed'}

        targets = []
        for stage in data.stages:
            if stage.key in self._GETOUT_KEYS and stage.state_offset:
                targets.append(stage)

        if not targets:
            QMessageBox.warning(self, "Boundaries",
                "GetOut_Region stages not found in this save.")
            return

        status_lines = []
        flippable = 0
        for s in sorted(targets, key=lambda x: x.key):
            name = _names.get(s.key, f'key={s.key}')
            st = _state_names.get(s.state, str(s.state))
            status_lines.append(f"  {name}: {st}")
            if s.state in (1, 2):
                flippable += 1

        if flippable == 0:
            QMessageBox.information(self, "Boundaries",
                "All GetOut_Region stages are already Ready/Completed.\n\n"
                + "\n".join(status_lines))
            return

        reply = QMessageBox.question(self, "Disable Boundaries",
            f"Flip {flippable} GetOut_Region stages to Ready?\n\n"
            f"Current state:\n" + "\n".join(status_lines) + "\n\n"
            f"This disables invisible walls and boundary teleportation.\n"
            f"Does NOT affect NPCs, quests, or world state.\n\n"
            f"Continue?",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No)
        if reply != QMessageBox.Yes:
            return

        flipped = 0
        for stage in targets:
            if stage.state in (1, 2):
                raw[stage.state_offset] = 4
                flipped += 1

        try:
            self._mark_modified()
        except AttributeError:
            pass

        self._qe_status.setText(f"Boundaries disabled: {flipped} GetOut_Region stages flipped")
        QMessageBox.information(self, "Boundaries Disabled",
            f"Flipped {flipped} GetOut_Region stages to Ready(4).\n\n"
            f"Save the file and restart the game.\n"
            f"Invisible walls are now disabled. NPCs unaffected.")


    def _qe_newgame_plus(self):
        if not self._save_data:
            QMessageBox.warning(self, "NewGame+", "Load a save file first.")
            return

        reply = QMessageBox.question(self, "NewGame+",
            "Reset the entire world to replay everything?\n\n"
            "This will:\n"
            "  1. Reset ALL completed stages to Available (in save)\n"
            "  2. Unbreak ALL broken gimmicks — chests, objects (in save)\n"
            "  3. Unlock ALL locked gimmicks (in save)\n"
            "  4. Apply ForceSpawnAfterRetreat to game data (stageinfo.pabgb)\n\n"
            "Your inventory, gear, skills, and quest progress stay.\n"
            "Camps will respawn, bosses return, chests refill.\n\n"
            "MAKE SURE YOU HAVE A BACKUP!",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No)
        if reply != QMessageBox.Yes:
            return

        self._qe_status.setText("Applying NewGame+...")
        QApplication.processEvents()

        results = []
        raw = self._save_data.decompressed_blob

        try:
            import sys as _sys
            _sys.path.insert(0, 'Communitydump/desktopeditor')
            import save_parser as _sp
            _result = _sp.build_result_from_raw(bytes(raw), {'input_kind': 'raw_blob'})

            stage_reset = 0
            for obj in _result['objects']:
                if obj.class_name == 'QuestSaveData':
                    for field in obj.fields:
                        if field.name == '_stageStateData' and field.list_elements:
                            for elem in field.list_elements:
                                for cf in (getattr(elem, 'child_fields', None) or []):
                                    if cf.name == '_state' and cf.present:
                                        state = raw[cf.start_offset]
                                        if state == 5:
                                            raw[cf.start_offset] = 2
                                            stage_reset += 1
            results.append(f"{stage_reset} stages reset (Completed -> Available)")

            gimmick_unbroken = 0
            gimmick_unlocked = 0
            for obj in _result['objects']:
                if obj.class_name == 'FieldSaveData':
                    for field in obj.fields:
                        if field.name == '_fieldGimmickSaveDataList' and field.list_elements:
                            for elem in field.list_elements:
                                for cf in (getattr(elem, 'child_fields', None) or []):
                                    if cf.name == '_isBroken' and cf.present and raw[cf.start_offset]:
                                        raw[cf.start_offset] = 0
                                        gimmick_unbroken += 1
                                    elif cf.name == '_isLockState' and cf.present and raw[cf.start_offset]:
                                        raw[cf.start_offset] = 0
                                        gimmick_unlocked += 1
            results.append(f"{gimmick_unbroken} gimmicks unbroken (chests, objects)")
            results.append(f"{gimmick_unlocked} gimmicks unlocked")

            try:
                self._mark_modified()
            except AttributeError:
                pass

            game_path = self._config.get("game_install_path", "")
            if game_path and os.path.isdir(game_path):
                try:
                    import crimson_rs
                    dp = "gamedata/binary__/client/bin"
                    stage_body = crimson_rs.extract_file(game_path, "0008", dp, "stageinfo.pabgb")
                    stage_gh = crimson_rs.extract_file(game_path, "0008", dp, "stageinfo.pabgh")

                    from stageinfo_parser import parse_all_stages
                    stage_data = bytearray(stage_body)
                    entries, failures = parse_all_stages(stage_data, stage_gh)

                    force_count = 0
                    for e in entries:
                        off = e.get('is_force_spawn_after_retreat_offset', -1)
                        if off > 0 and stage_data[off] == 0:
                            stage_data[off] = 1
                            force_count += 1

                    results.append(f"{force_count} stages: ForceSpawnAfterRetreat enabled")
                    results.append(f"({failures} stages couldn't be parsed — skipped)")

                    import crimson_rs.pack_mod
                    import shutil, tempfile
                    from pathlib import Path

                    with tempfile.TemporaryDirectory() as tmp_dir:
                        mod_dir = os.path.join(tmp_dir, "gamedata", "binary__", "client", "bin")
                        os.makedirs(mod_dir, exist_ok=True)
                        with open(os.path.join(mod_dir, "stageinfo.pabgb"), "wb") as f:
                            f.write(stage_data)

                        if hasattr(self, '_spawn_data') and self._spawn_data:
                            with open(os.path.join(mod_dir, "terrainregionautospawninfo.pabgb"), "wb") as f:
                                f.write(self._spawn_data)
                        if hasattr(self, '_spawn_fnode_ops_data') and self._spawn_fnode_ops_data:
                            with open(os.path.join(mod_dir, "factionnode.pabgb"), "wb") as f:
                                f.write(self._spawn_fnode_ops_data)
                        if hasattr(self, '_spawn_life_data') and self._spawn_life_data:
                            with open(os.path.join(mod_dir, "spawningpoolautospawninfo.pabgb"), "wb") as f:
                                f.write(self._spawn_life_data)

                        pack_out = os.path.join(tmp_dir, "output")
                        os.makedirs(pack_out, exist_ok=True)
                        crimson_rs.pack_mod.pack_mod(
                            game_dir=game_path, mod_folder=tmp_dir,
                            output_dir=pack_out, group_name="0037")

                        gp = Path(game_path)
                        paz_dst = gp / "Paz" / "0037"
                        meta_dst = gp / "Paz" / "meta"
                        paz_dst.mkdir(parents=True, exist_ok=True)

                        papgt = gp / "meta" / "0.papgt"
                        backup = papgt.with_suffix(".papgt.spawn_bak")
                        if papgt.exists() and not backup.exists():
                            shutil.copy2(papgt, backup)

                        for f in os.listdir(os.path.join(pack_out, "0037")):
                            shutil.copy2(os.path.join(pack_out, "0037", f),
                                         str(paz_dst / f))
                        if os.path.isdir(os.path.join(pack_out, "meta")):
                            meta_dst.mkdir(parents=True, exist_ok=True)
                            for f in os.listdir(os.path.join(pack_out, "meta")):
                                shutil.copy2(os.path.join(pack_out, "meta", f),
                                             str(meta_dst / f))

                    results.append("Game data deployed to Paz/0037/")
                except Exception as ge:
                    import traceback; traceback.print_exc()
                    results.append(f"Game data mod failed: {ge}")
            else:
                results.append("Game data mod skipped (set game path first)")

            summary = "\n  ".join(results)
            self._qe_status.setText(f"NewGame+ applied! Save the file, then restart game.")

            QMessageBox.information(self, "NewGame+ Applied",
                f"World reset complete:\n\n  {summary}\n\n"
                f"Next steps:\n"
                f"  1. File > Save to write the save changes\n"
                f"  2. Restart the game\n\n"
                f"Existing spawn mods (if any) are preserved.")

        except Exception as e:
            import traceback; traceback.print_exc()
            self._qe_status.setText(f"NewGame+ error: {e}")
            QMessageBox.critical(self, "NewGame+ Failed", str(e))

    def _qe_diagnose(self) -> None:
        entry = self._qe_get_selected_entry()
        if not entry:
            QMessageBox.information(self, "Diagnose", "Select a quest first.")
            return
        if not self._save_data:
            return

        import struct as _s
        quest_key = entry['key']
        quest_name = entry.get('display', entry['name'])
        blob = self._save_data.decompressed_blob
        raw = bytes(blob)

        try:
            _mydir = os.path.dirname(os.path.abspath(__file__))
            for d in ['Communitydump/desktopeditor', 'desktopeditor']:
                p = os.path.join(_mydir, d)
                if os.path.isdir(p) and p not in sys.path:
                    sys.path.insert(0, p)
            from save_parser import build_result_from_raw
            result = build_result_from_raw(raw, {'input_kind': 'raw_blob'})
        except Exception as e:
            QMessageBox.critical(self, "Diagnose", f"Parse error: {e}")
            return

        VALID_STATES_1B = {1, 2, 3, 4, 5}
        VALID_STATES_4B = {0x0D01, 0x0902, 0x0903, 0x0905, 0x1102, 0x1105, 0x1502, 0x1905}

        lines = [f"Quest Diagnosis: {quest_name} (key={quest_key})", "=" * 50]
        occurrences = []

        for obj in result['objects']:
            if obj.class_name not in ('QuestSaveData', 'MissionSaveData'):
                continue
            for f in obj.fields:
                if not f.list_elements:
                    continue
                for elem in f.list_elements:
                    if not elem.child_fields:
                        continue
                    qk = None
                    for cf in elem.child_fields:
                        if cf.name in ('_key', '_questKey') and cf.present:
                            qk = _s.unpack_from('<I', raw, cf.start_offset)[0]
                    if qk != quest_key:
                        continue
                    occurrences.append((obj.class_name, elem))

        if not occurrences:
            lines.append("\nNOT FOUND in save — quest does not exist.")
            lines.append("Use 'Add Quest to Save as Complete' in Quest Database to insert it.")
        else:
            lines.append(f"\nFound {len(occurrences)} occurrence(s):")
            if len(occurrences) > 1:
                lines.append("  *** DUPLICATE ENTRIES — this can cause bugs! ***")

            for idx, (cls_name, elem) in enumerate(occurrences):
                lines.append(f"\n--- Entry #{idx+1} in {cls_name} ---")
                lines.append(f"  Offset: {elem.start_offset} - {elem.end_offset} ({elem.end_offset - elem.start_offset}B)")
                issues = []

                for cf in elem.child_fields:
                    if cf.present:
                        size = cf.end_offset - cf.start_offset
                        rb = raw[cf.start_offset:cf.end_offset]
                        if size <= 8:
                            val = int.from_bytes(rb, 'little')
                            lines.append(f"  {cf.name}: {rb.hex()} = {val} (0x{val:X}) [{size}B]")

                            if cf.name == '_state':
                                if size == 1 and val not in VALID_STATES_1B:
                                    issues.append(f"CORRUPTED STATE: 0x{val:X} is not a valid 1-byte state")
                                elif size >= 2 and val not in VALID_STATES_4B:
                                    issues.append(f"CORRUPTED STATE: 0x{val:X} is not a valid quest state")
                        else:
                            lines.append(f"  {cf.name}: {rb[:16].hex()}{'...' if size > 16 else ''} [{size}B]")
                    else:
                        lines.append(f"  {cf.name}: NOT PRESENT")
                        if cf.name == '_completedTime':
                            issues.append("MISSING _completedTime — quest cannot be properly completed")
                        if cf.name == '_branchedTime':
                            issues.append("MISSING _branchedTime — quest was never started")

                if issues:
                    lines.append("\n  ISSUES:")
                    for iss in issues:
                        lines.append(f"    ! {iss}")
                else:
                    lines.append("\n  No issues detected.")

        report = "\n".join(lines)
        dlg = QDialog(self)
        dlg.setWindowTitle(f"Quest Diagnosis: {quest_name}")
        dlg.resize(650, 500)
        dl = QVBoxLayout(dlg)
        txt = QTextEdit()
        txt.setReadOnly(True)
        txt.setFont(QFont("Consolas", 10))
        txt.setPlainText(report)
        dl.addWidget(txt)
        copy_btn = QPushButton("Copy to Clipboard")
        copy_btn.clicked.connect(lambda: QApplication.clipboard().setText(report))
        dl.addWidget(copy_btn)
        dlg.exec()

    def _qe_scan_slots(self) -> None:
        entry = self._qe_get_selected_entry()
        if not entry:
            QMessageBox.information(self, "Scan Slots", "Select a quest first.")
            return

        import struct as _s
        import glob
        quest_key = entry['key']
        quest_name = entry.get('display', entry['name'])

        if not self._loaded_path:
            QMessageBox.warning(self, "Scan Slots", "Load a save file first.")
            return
        save_dir = os.path.dirname(os.path.dirname(self._loaded_path))

        self._qe_status.setText(f"Scanning all slots for quest {quest_key}...")
        QApplication.processEvents()

        STATE_NAMES = {
            0x01: "Locked", 0x02: "Available", 0x03: "Available+",
            0x04: "Unknown(4)", 0x05: "Completed",
            0x0D01: "Locked", 0x0902: "Available", 0x0903: "Available+",
            0x0905: "In Progress", 0x1102: "In Progress+",
            0x1105: "Completed", 0x1502: "Side Content", 0x1905: "Fully Completed",
        }

        lines = [f"Cross-Slot Scan: {quest_name} (key={quest_key})", "=" * 50, ""]

        try:
            _mydir = os.path.dirname(os.path.abspath(__file__))
            for d in ['Communitydump/desktopeditor', 'desktopeditor']:
                p = os.path.join(_mydir, d)
                if os.path.isdir(p) and p not in sys.path:
                    sys.path.insert(0, p)
            from save_parser import build_result_from_raw

            slot_names = {"slot0": "Auto 1", "slot1": "Auto 2", "slot2": "Auto 3"}
            for i in range(100, 110):
                slot_names[f"slot{i}"] = f"Manual {i-99}"

            for slot_path in sorted(glob.glob(os.path.join(save_dir, 'slot*', 'save.save'))):
                slot_id = os.path.basename(os.path.dirname(slot_path))
                slot_label = slot_names.get(slot_id, slot_id)
                is_loaded = os.path.abspath(slot_path) == os.path.abspath(self._loaded_path)

                try:
                    sd = load_save_file(slot_path)
                    raw = bytes(sd.decompressed_blob)
                    result = build_result_from_raw(raw, {'input_kind': 'raw_blob'})

                    found = []
                    for obj in result['objects']:
                        if obj.class_name not in ('QuestSaveData', 'MissionSaveData'):
                            continue
                        for f in obj.fields:
                            if not f.list_elements:
                                continue
                            for elem in f.list_elements:
                                if not elem.child_fields:
                                    continue
                                qk = None
                                state = None
                                has_ct = False
                                has_bt = False
                                for cf in elem.child_fields:
                                    if cf.name in ('_key', '_questKey') and cf.present:
                                        qk = _s.unpack_from('<I', raw, cf.start_offset)[0]
                                    if cf.name == '_state' and cf.present:
                                        sz = cf.end_offset - cf.start_offset
                                        state = raw[cf.start_offset] if sz == 1 else _s.unpack_from('<I', raw, cf.start_offset)[0]
                                    if cf.name == '_completedTime' and cf.present:
                                        has_ct = True
                                    if cf.name == '_branchedTime' and cf.present:
                                        has_bt = True
                                if qk == quest_key:
                                    sn = STATE_NAMES.get(state, f"0x{state:X}")
                                    flags = []
                                    if has_ct:
                                        flags.append("completedTime")
                                    if has_bt:
                                        flags.append("branchedTime")
                                    flag_str = f" [{', '.join(flags)}]" if flags else " [no timestamps]"
                                    found.append(f"state=0x{state:X} ({sn}){flag_str}")

                    marker = " <<< LOADED" if is_loaded else ""
                    if found:
                        for f in found:
                            lines.append(f"  {slot_id} ({slot_label}): {f}{marker}")
                    else:
                        lines.append(f"  {slot_id} ({slot_label}): NOT FOUND{marker}")
                except Exception as e:
                    lines.append(f"  {slot_id}: error ({e})")

        except Exception as e:
            lines.append(f"Error: {e}")

        self._qe_status.setText(f"Scan complete")

        report = "\n".join(lines)
        dlg = QDialog(self)
        dlg.setWindowTitle(f"Cross-Slot Scan: {quest_name}")
        dlg.resize(650, 450)
        dl = QVBoxLayout(dlg)
        txt = QTextEdit()
        txt.setReadOnly(True)
        txt.setFont(QFont("Consolas", 10))
        txt.setPlainText(report)
        dl.addWidget(txt)
        copy_btn = QPushButton("Copy to Clipboard")
        copy_btn.clicked.connect(lambda: QApplication.clipboard().setText(report))
        dl.addWidget(copy_btn)
        dlg.exec()

    def _qe_health_check(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Health Check", "Load a save file first.")
            return
        if not self._qe_entries:
            QMessageBox.warning(self, "Health Check", "Load quests first (click 'Load Quests').")
            return

        import struct as _s
        blob = self._save_data.decompressed_blob
        raw = bytes(blob)

        try:
            _mydir = os.path.dirname(os.path.abspath(__file__))
            for d in ['Communitydump/desktopeditor', 'desktopeditor']:
                p = os.path.join(_mydir, d)
                if os.path.isdir(p) and p not in sys.path:
                    sys.path.insert(0, p)
            from save_parser import build_result_from_raw
            result = build_result_from_raw(raw, {'input_kind': 'raw_blob'})
        except Exception as e:
            QMessageBox.critical(self, "Health Check", f"Parse error: {e}")
            return

        self._qe_status.setText("Running health check...")
        QApplication.processEvents()

        VALID_STATES_1B = {1, 2, 3, 4, 5}
        VALID_STATES_4B = {0x0D01, 0x0902, 0x0903, 0x0905, 0x1102, 0x1105, 0x1502, 0x1905}

        all_quests = {}
        for obj in result['objects']:
            if obj.class_name not in ('QuestSaveData', 'MissionSaveData'):
                continue
            for f in obj.fields:
                if not f.list_elements:
                    continue
                for elem in f.list_elements:
                    if not elem.child_fields:
                        continue
                    qk = None
                    state = None
                    state_sz = 0
                    has_ct = False
                    has_bt = False
                    for cf in elem.child_fields:
                        if cf.name in ('_key', '_questKey') and cf.present:
                            qk = _s.unpack_from('<I', raw, cf.start_offset)[0]
                        if cf.name == '_state' and cf.present:
                            state_sz = cf.end_offset - cf.start_offset
                            state = raw[cf.start_offset] if state_sz == 1 else _s.unpack_from('<I', raw, cf.start_offset)[0]
                        if cf.name == '_completedTime' and cf.present:
                            has_ct = True
                        if cf.name == '_branchedTime' and cf.present:
                            has_bt = True
                    if qk is not None:
                        all_quests.setdefault(qk, []).append({
                            'class': obj.class_name, 'state': state,
                            'state_size': state_sz, 'has_ct': has_ct, 'has_bt': has_bt,
                        })

        corrupted = []
        duplicates = []
        completed_no_ct = []
        total = len(all_quests)

        quest_names = {}
        for e in self._qe_entries:
            quest_names[e['key']] = e.get('display', e['name'])

        for qk, entries in all_quests.items():
            name = quest_names.get(qk, f"Unknown_{qk}")

            if len(entries) > 1:
                duplicates.append((qk, name, len(entries)))

            for ent in entries:
                st = ent['state']
                sz = ent['state_size']

                if sz == 1 and st not in VALID_STATES_1B:
                    corrupted.append((qk, name, f"0x{st:02X}", sz))
                elif sz >= 2 and st not in VALID_STATES_4B:
                    corrupted.append((qk, name, f"0x{st:04X}", sz))

                completed_vals = {5, 0x1105, 0x1905}
                if st in completed_vals and not ent['has_ct']:
                    completed_no_ct.append((qk, name))

        lines = ["Quest Health Check Report", "=" * 50]
        lines.append(f"\nTotal quests/missions in save: {total}")
        lines.append(f"Total entries (including duplicates): {sum(len(v) for v in all_quests.values())}")

        if corrupted:
            lines.append(f"\n{'!'*50}")
            lines.append(f"CORRUPTED STATES ({len(corrupted)}):")
            lines.append(f"{'!'*50}")
            for qk, name, state_hex, sz in corrupted:
                lines.append(f"  {qk} {name}: state={state_hex} ({sz}B) — INVALID")
        else:
            lines.append(f"\nNo corrupted states found.")

        if duplicates:
            lines.append(f"\nDUPLICATE ENTRIES ({len(duplicates)}):")
            for qk, name, count in duplicates:
                lines.append(f"  {qk} {name}: {count} copies")
        else:
            lines.append(f"No duplicate entries found.")

        if completed_no_ct:
            lines.append(f"\nCOMPLETED WITHOUT TIMESTAMP ({len(completed_no_ct)}):")
            for qk, name in completed_no_ct[:20]:
                lines.append(f"  {qk} {name}")
            if len(completed_no_ct) > 20:
                lines.append(f"  ... and {len(completed_no_ct) - 20} more")
        else:
            lines.append(f"All completed quests have timestamps.")

        self._qe_status.setText(
            f"Health: {len(corrupted)} corrupted, {len(duplicates)} dupes, "
            f"{len(completed_no_ct)} missing timestamps")

        report = "\n".join(lines)
        dlg = QDialog(self)
        dlg.setWindowTitle("Quest Health Check")
        dlg.resize(650, 500)
        dl = QVBoxLayout(dlg)
        txt = QTextEdit()
        txt.setReadOnly(True)
        txt.setFont(QFont("Consolas", 10))
        txt.setPlainText(report)
        dl.addWidget(txt)
        copy_btn = QPushButton("Copy to Clipboard")
        copy_btn.clicked.connect(lambda: QApplication.clipboard().setText(report))
        dl.addWidget(copy_btn)
        dlg.exec()

    def _qe_advanced_edit(self) -> None:
        entry = self._qe_get_selected_entry()
        if not entry:
            QMessageBox.information(self, "Advanced Edit", "Select a quest first.")
            return
        if not self._save_data:
            return

        import struct as _s
        quest_key = entry['key']
        quest_name = entry.get('display', entry['name'])
        blob = self._save_data.decompressed_blob
        raw = bytes(blob)

        try:
            _mydir = os.path.dirname(os.path.abspath(__file__))
            for d in ['Communitydump/desktopeditor', 'desktopeditor']:
                p = os.path.join(_mydir, d)
                if os.path.isdir(p) and p not in sys.path:
                    sys.path.insert(0, p)
            from save_parser import build_result_from_raw
            result = build_result_from_raw(raw, {'input_kind': 'raw_blob'})
        except Exception as e:
            QMessageBox.critical(self, "Advanced Edit", f"Parse error: {e}")
            return

        occurrences = []
        for obj in result['objects']:
            if obj.class_name not in ('QuestSaveData', 'MissionSaveData'):
                continue
            for f in obj.fields:
                if not f.list_elements:
                    continue
                for elem in f.list_elements:
                    if not elem.child_fields:
                        continue
                    qk = None
                    for cf in elem.child_fields:
                        if cf.name in ('_key', '_questKey') and cf.present:
                            qk = _s.unpack_from('<I', raw, cf.start_offset)[0]
                    if qk == quest_key:
                        occurrences.append((obj.class_name, elem))

        if not occurrences:
            QMessageBox.warning(self, "Advanced Edit",
                f"Quest {quest_key} not found in save.\n"
                f"Use Quest Database > 'Add Quest to Save' first.")
            return

        occ_idx = 0
        if len(occurrences) > 1:
            items_list = []
            for i, (cls, elem) in enumerate(occurrences):
                state_str = "?"
                for cf in elem.child_fields:
                    if cf.name == '_state' and cf.present:
                        sz = cf.end_offset - cf.start_offset
                        sv = raw[cf.start_offset] if sz == 1 else _s.unpack_from('<I', raw, cf.start_offset)[0]
                        state_str = f"0x{sv:X}"
                items_list.append(f"Entry #{i+1} in {cls} — state={state_str} @ offset {elem.start_offset}")

            from PySide6.QtWidgets import QInputDialog
            choice, ok = QInputDialog.getItem(
                self, "Multiple Entries",
                f"Quest {quest_key} has {len(occurrences)} entries.\nPick one to edit:",
                items_list, 0, False)
            if not ok:
                return
            occ_idx = items_list.index(choice)

        cls_name, elem = occurrences[occ_idx]

        STATE_NAMES = {
            1: "Locked", 2: "Available", 3: "Available+", 4: "Unknown(4)", 5: "Completed",
            0x0D01: "Locked", 0x0902: "Available", 0x0903: "Available+",
            0x0905: "In Progress", 0x1102: "In Progress+",
            0x1105: "Completed", 0x1502: "Side Content", 0x1905: "Fully Completed",
        }

        fields = []
        for cf in elem.child_fields:
            size = cf.end_offset - cf.start_offset if cf.present else 0
            if cf.present:
                rb = raw[cf.start_offset:cf.end_offset]
                val = int.from_bytes(rb, 'little')
                hint = ""
                if cf.name == '_state':
                    hint = STATE_NAMES.get(val, "UNKNOWN/CORRUPTED")
                elif cf.name in ('_completedTime', '_branchedTime', '_delayedTime'):
                    if val > 0:
                        h, rem = divmod(val, 3600)
                        m, s = divmod(rem, 60)
                        hint = f"{h}h {m:02d}m {s:02d}s game-world time"
                elif cf.name == '_completedCount':
                    hint = f"{val} time(s)"
                elif cf.name in ('_isWaitBranch', '_isSkipComplete'):
                    hint = "True" if val else "False"
                fields.append({
                    'name': cf.name, 'present': True, 'offset': cf.start_offset,
                    'size': size, 'raw': rb.hex(), 'value': val, 'hint': hint,
                })
            else:
                fields.append({
                    'name': cf.name, 'present': False, 'offset': 0,
                    'size': 0, 'raw': '', 'value': 0, 'hint': 'NOT IN SAVE',
                })

        dlg = QDialog(self)
        dlg.setWindowTitle(f"Advanced Quest Edit: {quest_name} (Entry #{occ_idx+1})")
        dlg.resize(700, 500)
        dl = QVBoxLayout(dlg)

        info = QLabel(
            f"Quest: {quest_name}  |  Key: {quest_key}  |  Class: {cls_name}\n"
            f"Offset: {elem.start_offset} - {elem.end_offset} ({elem.end_offset - elem.start_offset}B)"
        )
        info.setStyleSheet(f"color: {COLORS['accent']}; padding: 4px; font-weight: bold;")
        dl.addWidget(info)

        table = QTableWidget()
        table.setColumnCount(6)
        table.setHorizontalHeaderLabels(["Field", "Present", "Size", "Raw Hex", "Value", "Hint"])
        table.setRowCount(len(fields))
        table.horizontalHeader().setSectionResizeMode(0, QHeaderView.Interactive)
        table.setColumnWidth(0, 140)
        table.horizontalHeader().setSectionResizeMode(3, QHeaderView.Interactive)
        table.setColumnWidth(3, 180)
        table.horizontalHeader().setSectionResizeMode(5, QHeaderView.Interactive)
        table.setColumnWidth(5, 120)
        table.verticalHeader().setDefaultSectionSize(24)

        editable_widgets = {}

        for row, fd in enumerate(fields):
            name_w = QTableWidgetItem(fd['name'])
            name_w.setFlags(name_w.flags() & ~Qt.ItemIsEditable)
            if not fd['present']:
                name_w.setForeground(QBrush(QColor(COLORS['text_dim'])))
            table.setItem(row, 0, name_w)

            pres_w = QTableWidgetItem("Yes" if fd['present'] else "No")
            pres_w.setFlags(pres_w.flags() & ~Qt.ItemIsEditable)
            if not fd['present']:
                pres_w.setForeground(QBrush(QColor(COLORS['text_dim'])))
            table.setItem(row, 1, pres_w)

            size_w = QTableWidgetItem(f"{fd['size']}B" if fd['present'] else "-")
            size_w.setFlags(size_w.flags() & ~Qt.ItemIsEditable)
            table.setItem(row, 2, size_w)

            if fd['present']:
                raw_w = QTableWidgetItem(fd['raw'])
                raw_w.setFont(QFont("Consolas", 10))
                raw_w.setToolTip(f"Offset: {fd['offset']} (0x{fd['offset']:X})")
                table.setItem(row, 3, raw_w)
            else:
                raw_w = QTableWidgetItem("-")
                raw_w.setFlags(raw_w.flags() & ~Qt.ItemIsEditable)
                raw_w.setForeground(QBrush(QColor(COLORS['text_dim'])))
                table.setItem(row, 3, raw_w)

            val_w = QTableWidgetItem(str(fd['value']) if fd['present'] else "-")
            val_w.setFlags(val_w.flags() & ~Qt.ItemIsEditable)
            val_w.setFont(QFont("Consolas", 10))
            table.setItem(row, 4, val_w)

            hint_w = QTableWidgetItem(fd['hint'])
            hint_w.setFlags(hint_w.flags() & ~Qt.ItemIsEditable)
            hint_w.setForeground(QBrush(QColor(COLORS['warning'])))
            table.setItem(row, 5, hint_w)

        dl.addWidget(table, 1)

        btn_row = QHBoxLayout()

        apply_btn = QPushButton("Apply Changes")
        apply_btn.setObjectName("accentBtn")
        apply_btn.setStyleSheet("background-color: #cc3333; color: white; font-weight: bold;")
        apply_btn.setToolTip("Write edited hex values back to the save blob")
        btn_row.addWidget(apply_btn)

        cancel_btn = QPushButton("Cancel")
        cancel_btn.clicked.connect(dlg.reject)
        btn_row.addWidget(cancel_btn)

        btn_row.addStretch()

        help_lbl = QLabel(
            "Edit the 'Raw Hex' column to change values. "
            "Little-endian byte order. e.g. state 0x1905 = '0519'."
        )
        help_lbl.setStyleSheet(f"color: {COLORS['text_dim']}; font-size: 11px;")
        btn_row.addWidget(help_lbl)

        dl.addLayout(btn_row)

        def _apply():
            changes = []
            for row, fd in enumerate(fields):
                if not fd['present']:
                    continue
                raw_cell = table.item(row, 3)
                new_hex = raw_cell.text().strip().replace(' ', '')
                if new_hex == fd['raw']:
                    continue

                try:
                    new_bytes = bytes.fromhex(new_hex)
                except ValueError:
                    QMessageBox.warning(dlg, "Invalid Hex",
                        f"Field '{fd['name']}': '{new_hex}' is not valid hex.")
                    return

                if len(new_bytes) != fd['size']:
                    QMessageBox.warning(dlg, "Size Mismatch",
                        f"Field '{fd['name']}': expected {fd['size']} bytes, "
                        f"got {len(new_bytes)}.\n"
                        f"Cannot change field sizes — only values.")
                    return

                changes.append((fd['name'], fd['offset'], fd['size'], fd['raw'], new_hex, new_bytes))

            if not changes:
                QMessageBox.information(dlg, "No Changes", "No fields were modified.")
                return

            detail = "\n".join(
                f"  {name}: {old} → {new}" for name, _, _, old, new, _ in changes
            )
            reply = QMessageBox.question(
                dlg, "Confirm Changes",
                f"Apply {len(changes)} change(s) to quest {quest_key}?\n\n{detail}\n\n"
                f"This directly modifies the save blob.",
                QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
            )
            if reply != QMessageBox.Yes:
                return

            for name, offset, size, old, new_hex, new_bytes in changes:
                blob[offset:offset + size] = new_bytes
                log.info("Quest %d field %s: %s -> %s @ offset %d",
                         quest_key, name, old, new_hex, offset)

            self._dirty = True
            self._qe_load()
            dlg.accept()
            self._update_status(f"Applied {len(changes)} changes to quest {quest_key}")

        apply_btn.clicked.connect(_apply)
        dlg.exec()

    def _qe_context_menu(self, pos) -> None:
        item = self._qe_table.itemAt(pos)
        if item and item.row() >= 0:
            if not self._qe_table.selectedIndexes():
                self._qe_table.selectRow(item.row())

        menu = QMenu(self)

        add_menu = menu.addMenu("Add to Pack")
        pack_dir = os.path.join(self._app_dir(), 'quest_packs')
        existing_packs = []
        if os.path.isdir(pack_dir):
            import json as _json
            for fname in sorted(os.listdir(pack_dir)):
                if fname.endswith('.json'):
                    try:
                        fpath = os.path.join(pack_dir, fname)
                        with open(fpath, 'r') as f:
                            p = _json.load(f)
                        pname = p.get('name', fname.replace('.json', ''))
                        act = add_menu.addAction(pname)
                        existing_packs.append((act, fpath, p))
                    except Exception:
                        pass
        if not existing_packs:
            add_menu.addAction("(no packs — use New Pack in sidebar)").setEnabled(False)

        menu.addSeparator()
        complete_act = menu.addAction("Mark Completed")
        reset_prog_act = menu.addAction("Reset to In Progress")
        reset_avail_act = menu.addAction("Reset to Available")
        menu.addSeparator()
        copy_act = menu.addAction("Copy Key(s)")

        action = menu.exec(self._qe_table.mapToGlobal(pos))
        if not action:
            return

        if action == complete_act:
            self._qe_mark_completed()
        elif action == reset_prog_act:
            self._qe_reset_progress()
        elif action == reset_avail_act:
            self._qe_reset_available()
        elif action == copy_act:
            rows = set(idx.row() for idx in self._qe_table.selectedIndexes())
            keys = []
            for r in sorted(rows):
                itm = self._qe_table.item(r, 0)
                if itm:
                    keys.append(itm.text())
            if keys:
                QApplication.clipboard().setText(", ".join(keys))
        else:
            for act, fpath, pack in existing_packs:
                if action == act:
                    self._qe_add_to_existing_pack(fpath, pack)
                    break

    def _qe_get_selected_entries_multi(self) -> list:
        rows = set(idx.row() for idx in self._qe_table.selectedIndexes())
        entries = []
        for r in sorted(rows):
            item = self._qe_table.item(r, 0)
            if item:
                entry = item.data(Qt.UserRole)
                if entry:
                    entries.append(entry)
        return entries

    def _qe_export_pack(self) -> None:
        entries = self._qe_get_selected_entries_multi()
        if not entries:
            QMessageBox.warning(self, "Quest Pack",
                "No quests selected.\n\n"
                "How to select:\n"
                "- Click a row to select one\n"
                "- Ctrl+Click to add more\n"
                "- Shift+Click for a range\n\n"
                "Then right-click > Start New Pack.")
            return

        pack_name, ok = QInputDialog.getText(
            self, "Quest Pack Name",
            f"Name this quest pack ({len(entries)} quests):",
        )
        if not ok or not pack_name.strip():
            return

        pack_entries = []
        for e in entries:
            pack_entries.append({
                'key': e['key'],
                'name': e.get('name', ''),
                'display': e.get('display', ''),
            })

        pack = {
            'name': pack_name.strip(),
            'type': 'quest',
            'quest_count': len(pack_entries),
            'quests': pack_entries,
        }

        pack_dir = os.path.join(self._app_dir(), 'quest_packs')
        os.makedirs(pack_dir, exist_ok=True)
        safe_name = "".join(c if c.isalnum() or c in ' _-' else '_' for c in pack_name.strip())
        path = os.path.join(pack_dir, f"{safe_name}.json")

        import json as _json
        with open(path, 'w') as f:
            _json.dump(pack, f, indent=2)

        self._pack_browser_refresh()
        QMessageBox.information(self, "Quest Pack Exported",
            f"Saved '{pack_name}' with {len(pack_entries)} quests.\n\nFile: {path}")

    def _qe_add_to_existing_pack(self, pack_path: str, pack: dict) -> None:
        entries = self._qe_get_selected_entries_multi()
        if not entries:
            return

        existing_keys = {e['key'] for e in pack.get('quests', [])}
        new_entries = []
        for e in entries:
            if e['key'] not in existing_keys:
                new_entries.append({
                    'key': e['key'],
                    'name': e.get('name', ''),
                    'display': e.get('display', ''),
                })

        if not new_entries:
            QMessageBox.information(self, "Pack", "All selected quests are already in this pack.")
            return

        pack.setdefault('quests', []).extend(new_entries)
        pack['quest_count'] = len(pack['quests'])

        import json as _json
        with open(pack_path, 'w') as f:
            _json.dump(pack, f, indent=2)

        self._pack_browser_refresh()
        QMessageBox.information(self, "Pack Updated",
            f"Added {len(new_entries)} quests to '{pack.get('name', '')}'.\n"
            f"Total: {pack['quest_count']} quests.")

    STATE_TRANSITIONS = {
        0: 1,
        1: 2,
        2: 5,
        3: 5,
        4: 5,
    }
    STATE_NAMES_SHORT = {0: 'Default', 1: 'Locked', 2: 'Available', 3: 'State 3', 4: 'State 4', 5: 'Completed'}

    def _qe_advance_state(self) -> None:
        entry = self._qe_get_selected_entry()
        if not entry:
            QMessageBox.information(self, "Quest Editor", "Select a quest first.")
            return

        cur = entry.get('state', 0) & 0xFF
        if cur >= 5:
            QMessageBox.information(self, "Quest Editor",
                f"'{entry.get('display', entry['name'])}' is already at state {cur} (Completed).")
            return

        nxt = self.STATE_TRANSITIONS.get(cur, 5)
        cur_name = self.STATE_NAMES_SHORT.get(cur, f'State {cur}')
        nxt_name = self.STATE_NAMES_SHORT.get(nxt, f'State {nxt}')

        chain = entry.get('chain')
        chain_text = ""
        if chain and isinstance(chain, list) and chain:
            c = chain[0]
            chain_text = f"\n\nChain: {c.get('chain_name', '?')} ({c.get('chain_size', '?')} sub-quests)"

        reply = QMessageBox.question(
            self, "Advance State",
            f"Advance '{entry.get('display', entry['name'])}'?\n\n"
            f"{cur_name} (state {cur}) → {nxt_name} (state {nxt}){chain_text}",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        if self._qe_set_state(entry, nxt):
            self._dirty = True
            self._qe_filter()
            self._update_status(f"Advanced: {entry.get('display', entry['name'])} → {nxt_name}")

    def _qe_mark_completed(self) -> None:
        entry = self._qe_get_selected_entry()
        if not entry:
            QMessageBox.information(self, "Quest Editor", "Select a quest first.")
            return

        name = entry.get('display', entry['name'])
        cur_state = entry.get('state', 0) & 0xFF
        needs_expand = entry.get('needs_parc_expand', False)

        if entry.get('is_mission') and entry.get('state_size', 4) == 1:
            reply = QMessageBox.question(
                self, "Mark Completed",
                f"Set '{name}' to Completed (state 5)?\n\n"
                f"Current state: {cur_state}\n"
                f"This is a simple 1-byte change — no PARC insertion needed.",
                QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
            )
            if reply != QMessageBox.Yes:
                return
            if self._qe_set_state(entry, 5):
                self._dirty = True
                self._qe_filter()
                self._update_status(f"Completed: {name}")
            return

        if needs_expand and not entry.get('has_completed', False):
            reply = QMessageBox.question(
                self, "Complete (PARC Insertion)",
                f"'{name}' needs _completedTime/_branchedTime timestamps to be truly completed.\n\n"
                f"This requires PARC insertion (adds ~16 bytes to the save).\n"
                f"A backup is recommended before proceeding.\n\n"
                f"Complete with timestamp insertion?",
                QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
            )
            if reply != QMessageBox.Yes:
                return
            try:
                import parc_inserter3 as pi
                mission_key = entry.get('key', 0)
                blob = bytearray(self._save_data.decompressed_blob)
                ok, new_blob, msg = pi.complete_mission(blob, mission_key)
                if ok:
                    self._save_data.decompressed_blob = bytearray(new_blob)
                    self._dirty = True
                    self._qe_load()
                    self._update_status(f"Completed with PARC: {name}")
                    return
                else:
                    QMessageBox.warning(self, "PARC Completion Failed",
                        f"Timestamp insertion failed:\n{msg}\n\n"
                        f"Falling back to state-only change.")
            except Exception as e:
                import traceback; traceback.print_exc()
                QMessageBox.warning(self, "PARC Error",
                    f"Timestamp insertion error: {e}\n\nFalling back to state-only change.")

        if self._qe_set_state(entry, 0x1905):
            self._dirty = True
            self._qe_filter()
            self._update_status(f"Completed: {name}")

    def _qe_reset_progress(self) -> None:
        entry = self._qe_get_selected_entry()
        if not entry:
            return
        if self._qe_set_state(entry, 0x0905):
            self._dirty = True
            self._qe_filter()
            self._update_status(f"Reset: {entry.get('display', entry['name'])}")

    def _qe_reset_available(self) -> None:
        entry = self._qe_get_selected_entry()
        if not entry:
            QMessageBox.information(self, "Quest Editor", "Select a quest first.")
            return
        state_name = {0x0902: "Available", 0x0905: "In Progress", 0x1905: "Completed"}.get(
            entry.get('state', 0), f"0x{entry.get('state', 0):04X}")
        reply = QMessageBox.question(
            self, "Reset to Available",
            f"Reset '{entry.get('display', entry['name'])}' to Available (not started)?\n\nCurrent: {state_name}",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return
        if self._qe_set_state(entry, 0x0902):
            self._dirty = True
            self._qe_filter()
            self._update_status(f"Reset to Available: {entry.get('display', entry['name'])}")

    def _qe_insert_completed(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Quest Editor", "Load a save first.")
            return
        key, ok = QInputDialog.getInt(
            self, "Add Quest as Completed",
            "Enter the quest key to insert as completed.\n"
            "Find keys in the Quest Database tab.\n\n"
            "Example: 1000212 = Shattered Ties (Dragon unlock)",
            1000212, 1, 9999999,
        )
        if not ok:
            return
        try:
            import parc_inserter3 as pi
            blob = bytearray(self._save_data.decompressed_blob)
            ok, new_blob, msg = pi.insert_quest_completed(blob, key)
            if ok:
                self._save_data.decompressed_blob = bytearray(new_blob)
                self._dirty = True
                self._update_status(f"Quest {key} inserted as completed")
                QMessageBox.information(self, "Quest Inserted", msg)
                self._qe_load()
            else:
                QMessageBox.warning(self, "Quest Insert Failed", msg)
        except Exception as e:
            import traceback; traceback.print_exc()
            QMessageBox.critical(self, "Error", str(e))

    def _qe_show_chain_hint(self, *_args) -> None:
        entry = self._qe_get_selected_entry()
        if not entry or not self._qe_entries:
            self._qe_chain_hint.setVisible(False)
            return

        name = entry.get('name', '')
        import re
        prefix_match = re.match(r'^(.+?)_?\d{1,3}$', name)
        if not prefix_match:
            parts = name.rsplit('_', 1)
            prefix = parts[0] if len(parts) > 1 and len(parts[0]) > 5 else ''
        else:
            prefix = prefix_match.group(1)

        if not prefix or len(prefix) < 5:
            self._qe_chain_hint.setVisible(False)
            return

        related = []
        prefix_lower = prefix.lower()
        for e in self._qe_entries:
            if prefix_lower in e.get('name', '').lower() and e['key'] != entry['key']:
                state = e.get('state', 0)
                tag = "Done" if state in (0x1105, 0x1905) else "InProg" if state in (0x0905, 0x1102) else "Other"
                display = e.get('display', e['name'])
                related.append(f"  {e['key']}  {display} [{tag}]")

        if not related:
            self._qe_chain_hint.setVisible(False)
            return

        hint = f"Related quests (search '{prefix}'):\n" + '\n'.join(related[:8])
        if len(related) > 8:
            hint += f"\n  ... +{len(related) - 8} more"
        self._qe_chain_hint.setText(hint)
        self._qe_chain_hint.setVisible(True)

    def _qe_batch_complete(self) -> None:
        if not self._qe_entries:
            return
        count = self._qe_table.rowCount()
        if count == 0:
            return
        reply = QMessageBox.question(
            self, "Complete All",
            f"Mark all {count} visible quests/missions as completed?",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return
        completed = 0
        for row in range(count):
            w = self._qe_table.item(row, 0)
            if w:
                entry = w.data(Qt.UserRole)
                if entry and self._qe_set_state(entry, 0x1905):
                    completed += 1
        self._dirty = True
        self._qe_filter()
        self._update_status(f"Completed {completed} quests/missions")


    def _build_quest_database_tab(self) -> None:
        tab = QWidget()
        layout = QVBoxLayout(tab)
        layout.setContentsMargins(8, 8, 8, 8)
        layout.setSpacing(6)
        layout.addWidget(self._make_scope_label("readonly"))

        info = QLabel(
            "QUEST DATABASE — All 898 quests from game data.\n"
            "Search by name to find quest keys. Use the Quest Editor tab in World to modify quest states."
        )
        info.setWordWrap(True)
        info.setStyleSheet(
            f"color: {COLORS['text']}; padding: 8px; "
            f"border: 1px solid {COLORS['accent']}; border-radius: 4px; "
            f"background-color: rgba(79,195,247,0.08);"
        )
        layout.addWidget(info)

        top = QHBoxLayout()
        top.addWidget(QLabel("Search:"))
        self._qdb_search = QLineEdit()
        self._qdb_search.setPlaceholderText("Search by quest name, display name, or key...")
        self._qdb_search.textChanged.connect(self._filter_quest_db)
        top.addWidget(self._qdb_search, 1)

        self._qdb_count = QLabel("")
        self._qdb_count.setStyleSheet(f"color: {COLORS['accent']}; font-weight: bold;")
        top.addWidget(self._qdb_count)
        layout.addLayout(top)

        self._qdb_table = QTableWidget()
        self._qdb_table.setColumnCount(3)
        self._qdb_table.setHorizontalHeaderLabels(["Key", "Internal Name", "Display Name"])
        self._qdb_table.setSelectionBehavior(QAbstractItemView.SelectRows)
        self._qdb_table.setSelectionMode(QAbstractItemView.ExtendedSelection)
        self._qdb_table.setEditTriggers(QAbstractItemView.NoEditTriggers)
        self._qdb_table.horizontalHeader().setSectionResizeMode(1, QHeaderView.Interactive)
        self._qdb_table.setColumnWidth(1, 180)
        self._qdb_table.horizontalHeader().setSectionResizeMode(2, QHeaderView.Interactive)
        self._qdb_table.setColumnWidth(2, 220)
        self._qdb_table.verticalHeader().setDefaultSectionSize(22)
        self._qdb_table.setSortingEnabled(True)
        self._qdb_table.setContextMenuPolicy(Qt.CustomContextMenu)
        self._qdb_table.customContextMenuRequested.connect(self._qdb_context_menu)
        layout.addWidget(self._qdb_table)

        pack_row = QHBoxLayout()

        add_complete_btn = QPushButton("Add Quest to Save as Complete")
        add_complete_btn.setToolTip(
            "Insert selected quests into your save as completed.\n"
            "Uses PARC insertion — for quests NOT already in your save."
        )
        add_complete_btn.clicked.connect(self._qdb_mark_selected_complete)
        pack_row.addWidget(add_complete_btn)

        add_available_btn = QPushButton("Add Quest to Save as Available")
        add_available_btn.setToolTip(
            "Insert selected quests into your save as available (state=2).\n"
            "The quest will appear in your journal ready to start."
        )
        add_available_btn.clicked.connect(self._qdb_add_selected_available)
        pack_row.addWidget(add_available_btn)

        pack_row.addStretch()
        layout.addLayout(pack_row)

        self._tabs.addTab(tab, tr("tab.quest_db"))

        self._qdb_entries = []
        try:
            import json as _json
            from localization import get_localized_name
            for base in [os.path.dirname(os.path.abspath(__file__)), getattr(sys, '_MEIPASS', '')]:
                p = os.path.join(base, 'quest_names.json')
                if os.path.isfile(p):
                    with open(p, 'r') as f:
                        self._qdb_entries = _json.load(f)
                    for e in self._qdb_entries:
                        loc = get_localized_name('quests', e.get('key', ''), '')
                        if loc:
                            e['display'] = loc
                    break
        except Exception:
            pass

        self._qdb_mission_entries = []
        try:
            import json as _json
            from localization import get_localized_name
            for base in [os.path.dirname(os.path.abspath(__file__)), getattr(sys, '_MEIPASS', '')]:
                p = os.path.join(base, 'mission_names.json')
                if os.path.isfile(p):
                    with open(p, 'r') as f:
                        self._qdb_mission_entries = _json.load(f)
                    for e in self._qdb_mission_entries:
                        loc = get_localized_name('missions', e.get('key', ''), '')
                        if loc:
                            e['display'] = loc
                    break
        except Exception:
            pass

        self._filter_quest_db("")

    def _filter_quest_db(self, text: str) -> None:
        table = self._qdb_table
        table.setSortingEnabled(False)
        search = text.strip().lower()

        all_entries = self._qdb_entries + self._qdb_mission_entries

        if search:
            filtered = [e for e in all_entries
                        if search in e.get('name', '').lower()
                        or search in e.get('display', '').lower()
                        or search in str(e.get('key', ''))]
        else:
            filtered = all_entries[:500]

        table.setRowCount(len(filtered))
        for row, e in enumerate(filtered):
            table.setItem(row, 0, QTableWidgetItem(str(e.get('key', ''))))

            name_item = QTableWidgetItem(e.get('name', ''))
            name_item.setForeground(QBrush(QColor(COLORS['text_dim'])))
            table.setItem(row, 1, name_item)

            display = e.get('display', e.get('name', ''))
            disp_item = QTableWidgetItem(display)
            if display != e.get('name', ''):
                disp_item.setForeground(QBrush(QColor(COLORS['accent'])))
            table.setItem(row, 2, disp_item)

        table.setSortingEnabled(True)
        total = len(self._qdb_entries) + len(self._qdb_mission_entries)
        self._qdb_count.setText(
            f"{len(self._qdb_entries)} quests + {len(self._qdb_mission_entries)} missions = {total}  |  "
            f"Showing {len(filtered)}"
        )

    def _qdb_context_menu(self, pos) -> None:
        item = self._qdb_table.itemAt(pos)
        if item and item.row() >= 0:
            if not self._qdb_table.selectedIndexes():
                self._qdb_table.selectRow(item.row())

        menu = QMenu(self)

        add_menu = menu.addMenu("Add to Pack")
        pack_dir = os.path.join(self._app_dir(), 'quest_packs')
        existing_packs = []
        if os.path.isdir(pack_dir):
            import json as _json
            for fname in sorted(os.listdir(pack_dir)):
                if fname.endswith('.json'):
                    try:
                        fpath = os.path.join(pack_dir, fname)
                        with open(fpath, 'r') as f:
                            p = _json.load(f)
                        pname = p.get('name', fname.replace('.json', ''))
                        act = add_menu.addAction(pname)
                        existing_packs.append((act, fpath, p))
                    except Exception:
                        pass
        if not existing_packs:
            add_menu.addAction("(no packs — use New Pack in sidebar)").setEnabled(False)

        menu.addSeparator()
        complete_act = menu.addAction("Mark Selected Complete")
        copy_key_act = menu.addAction("Copy Key(s)")

        action = menu.exec(self._qdb_table.mapToGlobal(pos))
        if not action:
            return

        if action == complete_act:
            self._qdb_mark_selected_complete()
        elif action == copy_key_act:
            rows = set(idx.row() for idx in self._qdb_table.selectedIndexes())
            keys = [self._qdb_table.item(r, 0).text() for r in sorted(rows) if self._qdb_table.item(r, 0)]
            if keys:
                QApplication.clipboard().setText(", ".join(keys))
        else:
            for act, fpath, pack in existing_packs:
                if action == act:
                    self._qdb_add_to_existing_pack(fpath, pack)
                    break

    def _qdb_add_to_existing_pack(self, pack_path: str, pack: dict) -> None:
        entries = self._qdb_get_selected_entries()
        if not entries:
            return

        existing_keys = {e['key'] for e in pack.get('quests', [])}
        new_entries = [e for e in entries if e['key'] not in existing_keys]

        if not new_entries:
            QMessageBox.information(self, "Pack", "All selected quests are already in this pack.")
            return

        pack.setdefault('quests', []).extend(new_entries)
        pack['quest_count'] = len(pack['quests'])

        import json as _json
        with open(pack_path, 'w') as f:
            _json.dump(pack, f, indent=2)

        self._pack_browser_refresh()
        QMessageBox.information(self, "Pack Updated",
            f"Added {len(new_entries)} quests to '{pack.get('name', '')}'.\n"
            f"Total: {pack['quest_count']} quests.")

    def _qdb_get_selected_entries(self) -> list:
        rows = set(idx.row() for idx in self._qdb_table.selectedIndexes())
        entries = []
        for r in sorted(rows):
            key_item = self._qdb_table.item(r, 0)
            name_item = self._qdb_table.item(r, 1)
            disp_item = self._qdb_table.item(r, 2)
            if key_item:
                entries.append({
                    'key': int(key_item.text()),
                    'name': name_item.text() if name_item else '',
                    'display': disp_item.text() if disp_item else '',
                })
        return entries

    def _qdb_export_pack(self) -> None:
        entries = self._qdb_get_selected_entries()
        if not entries:
            QMessageBox.warning(self, "Quest Pack",
                "No quests selected.\n\n"
                "How to select:\n"
                "- Click a row to select one\n"
                "- Ctrl+Click to add more\n"
                "- Shift+Click for a range\n\n"
                "Then right-click > Start New Pack.")
            return

        pack_name, ok = QInputDialog.getText(
            self, "Quest Pack Name",
            f"Name this quest pack ({len(entries)} quests):",
        )
        if not ok or not pack_name.strip():
            return

        pack = {
            'name': pack_name.strip(),
            'quest_count': len(entries),
            'quests': entries,
        }

        pack_dir = os.path.join(self._app_dir(), 'quest_packs')
        os.makedirs(pack_dir, exist_ok=True)

        safe_name = "".join(c if c.isalnum() or c in ' _-' else '_' for c in pack_name.strip())
        path = os.path.join(pack_dir, f"{safe_name}.json")

        import json as _json
        with open(path, 'w') as f:
            _json.dump(pack, f, indent=2)

        QMessageBox.information(self, "Quest Pack Exported",
            f"Saved '{pack_name}' with {len(entries)} quests.\n\n"
            f"File: {path}\n\n"
            f"Share this .json file with the community!")

    def _qdb_import_pack(self) -> None:
        pack_dir = os.path.join(self._app_dir(), 'quest_packs')

        path, _ = QFileDialog.getOpenFileName(
            self, "Import Quest Pack", pack_dir, "Quest Pack (*.json)")
        if not path:
            return

        try:
            import json as _json
            with open(path, 'r') as f:
                pack = _json.load(f)

            pack_name = pack.get('name', os.path.basename(path))
            quests = pack.get('quests', [])
            keys = {q['key'] for q in quests}

            self._qdb_search.setText("")
            self._filter_quest_db("")

            self._qdb_table.clearSelection()
            selected = 0
            for row in range(self._qdb_table.rowCount()):
                item = self._qdb_table.item(row, 0)
                if item and int(item.text()) in keys:
                    self._qdb_table.selectRow(row)
                    selected += 1

            self._qdb_count.setText(
                f"Pack: '{pack_name}' — {selected}/{len(keys)} quests found in database"
            )

        except Exception as e:
            QMessageBox.critical(self, "Import Error", str(e))

    def _qdb_mark_selected_complete(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Quest", "Load a save file first.")
            return

        entries = self._qdb_get_selected_entries()
        if not entries:
            QMessageBox.information(self, "Quest", "Select quests first.")
            return

        names = [f"  {e['display'] or e['name']}" for e in entries[:10]]
        more = f"\n  ... and {len(entries) - 10} more" if len(entries) > 10 else ""

        reply = QMessageBox.question(
            self, "Mark Complete",
            f"Mark {len(entries)} quests as completed?\n\n"
            + "\n".join(names) + more + "\n\n"
            f"This modifies quest states in the loaded save.\n"
            f"Save (Ctrl+S) afterward.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        try:
            import struct
            blob = self._save_data.decompressed_blob

            sys_path = __import__('sys').path
            for d in ['Communitydump/desktopeditor', 'desktopeditor']:
                p = os.path.join(os.path.dirname(__file__), d)
                if os.path.isdir(p) and p not in sys_path:
                    sys_path.insert(0, p)
            from save_parser import build_result_from_raw

            raw = bytes(blob)
            result = build_result_from_raw(raw, {'input_kind': 'raw_blob'})

            target_keys = {e['key'] for e in entries}
            completed = 0

            for obj in result['objects']:
                if obj.class_name in ('QuestSaveData', 'MissionSaveData'):
                    for f in obj.fields:
                        if f.name == '_list' and f.list_elements:
                            for elem in f.list_elements:
                                if hasattr(elem, 'child_fields') and elem.child_fields:
                                    quest_key = None
                                    state_offset = -1
                                    for cf in elem.child_fields:
                                        if cf.name == '_key' and cf.present:
                                            quest_key = struct.unpack_from('<I', raw, cf.start_offset)[0]
                                        elif cf.name == '_state' and cf.present:
                                            state_offset = cf.start_offset
                                    if quest_key in target_keys and state_offset >= 0:
                                        current = struct.unpack_from('<I', blob, state_offset)[0]
                                        if current != 0x1905:
                                            struct.pack_into('<I', blob, state_offset, 0x1905)
                                            completed += 1
                                            target_keys.discard(quest_key)

            inserted = 0
            insert_failed = []
            if target_keys:
                try:
                    from parc_inserter3 import insert_quest_completed
                    for qk in list(target_keys):
                        ok_ins, new_blob, msg = insert_quest_completed(bytearray(blob), qk)
                        if ok_ins:
                            self._save_data.decompressed_blob = bytearray(new_blob)
                            blob = self._save_data.decompressed_blob
                            inserted += 1
                            target_keys.discard(qk)
                            log.info("PARC inserted quest %d: %s", qk, msg)
                        else:
                            insert_failed.append((qk, msg))
                            log.warning("PARC insert failed for quest %d: %s", qk, msg)
                except ImportError:
                    log.warning("parc_inserter3 not available for quest insertion")
                except Exception as ie:
                    log.warning("PARC insert error: %s", ie)

            self._dirty = True
            parts = []
            if completed:
                parts.append(f"{completed} state-changed")
            if inserted:
                parts.append(f"{inserted} PARC-inserted")
            if insert_failed:
                parts.append(f"{len(insert_failed)} failed")
            if target_keys:
                parts.append(f"{len(target_keys)} not insertable")
            self._qdb_count.setText(f"Completed: {' | '.join(parts)}")

            if insert_failed:
                fail_detail = "\n".join(f"  {k}: {m}" for k, m in insert_failed[:5])
                QMessageBox.warning(self, "Some Inserts Failed",
                    f"{len(insert_failed)} quest(s) could not be inserted:\n\n{fail_detail}")

        except Exception as e:
            import traceback; traceback.print_exc()
            QMessageBox.critical(self, "Error", str(e))

    def _qdb_add_selected_available(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Quest", "Load a save file first.")
            return

        entries = self._qdb_get_selected_entries()
        if not entries:
            QMessageBox.information(self, "Quest", "Select quests first.")
            return

        names = [f"  {e.get('display', '') or e['name']}" for e in entries[:10]]
        more = f"\n  ... and {len(entries) - 10} more" if len(entries) > 10 else ""

        reply = QMessageBox.question(
            self, "Add as Available",
            f"Add {len(entries)} quests to save as Available (state=2)?\n\n"
            + "\n".join(names) + more + "\n\n"
            f"Quests already in save will have their state set to 2.\n"
            f"New quests will be inserted via PARC insertion.\n"
            f"Save (Ctrl+S) afterward.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        try:
            import struct as _struct
            blob = self._save_data.decompressed_blob

            _mydir = os.path.dirname(os.path.abspath(__file__))
            for d in ['Communitydump/desktopeditor', 'desktopeditor']:
                p = os.path.join(_mydir, d)
                if os.path.isdir(p) and p not in sys.path:
                    sys.path.insert(0, p)
            from save_parser import build_result_from_raw

            raw = bytes(blob)
            result = build_result_from_raw(raw, {'input_kind': 'raw_blob'})

            target_keys = {e['key'] for e in entries}
            set_count = 0

            for obj in result['objects']:
                if obj.class_name != 'QuestSaveData':
                    continue
                for f in obj.fields:
                    if not f.list_elements:
                        continue
                    for elem in f.list_elements:
                        if not elem.child_fields:
                            continue
                        quest_key = None
                        state_offset = -1
                        state_size = 4
                        for cf in elem.child_fields:
                            if cf.name in ('_key', '_questKey') and cf.present:
                                quest_key = _struct.unpack_from('<I', raw, cf.start_offset)[0]
                            elif cf.name == '_state' and cf.present:
                                state_offset = cf.start_offset
                                state_size = cf.end_offset - cf.start_offset
                        if quest_key in target_keys and state_offset >= 0:
                            if state_size == 1:
                                blob[state_offset] = 2
                            elif state_size == 2:
                                _struct.pack_into('<H', blob, state_offset, 0x0902)
                            else:
                                _struct.pack_into('<I', blob, state_offset, 0x0902)
                            set_count += 1
                            target_keys.discard(quest_key)

            not_found = len(target_keys)

            self._dirty = True
            msg = f"Set {set_count} quests to Available"
            if not_found > 0:
                msg += f" | {not_found} not in save (PARC insertion needed — not yet implemented for Available state)"
            self._qdb_count.setText(msg)

        except Exception as e:
            import traceback; traceback.print_exc()
            QMessageBox.critical(self, "Error", str(e))

