    def _know_scan(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Knowledge", "Load a save file first.")
            return

        self._know_status.setText("Scanning...")
        QApplication.processEvents()

        try:
            import sys
            for d in ['Communitydump/desktopeditor', 'desktopeditor']:
                p = os.path.join(os.path.dirname(__file__), d)
                if os.path.isdir(p) and p not in sys.path:
                    sys.path.append(p)
            from save_parser import build_result_from_raw, parse_schema, parse_toc
            import struct as _st

            blob = bytes(self._save_data.decompressed_blob)
            schema = parse_schema(blob)
            toc = parse_toc(blob, schema['schema_end'], [t.name for t in schema['types']])

            self._know_learned_keys = set()
            for e in toc['entries']:
                if e.class_name == 'KnowledgeSaveData':
                    block = blob[e.data_offset:e.data_offset + e.data_size]
                    for off in range(0, len(block) - 3, 4):
                        v = _st.unpack_from('<I', block, off)[0]
                        if 1000000 <= v <= 1999999:
                            self._know_learned_keys.add(v)
                    break

            know_path = os.path.join(
                getattr(sys, '_MEIPASS', os.path.dirname(__file__)),
                'knowledge_keys_all.json'
            )
            if not os.path.isfile(know_path):
                know_path = os.path.join(os.path.dirname(__file__), 'knowledge_keys_all.json')

            with open(know_path, 'r') as f:
                all_know = json.load(f)

            self._know_all_entries = []
            from localization import get_localized_name
            for entry in all_know:
                key = entry['key']
                internal_name = entry['name']
                display_name = entry.get('display_name', '')
                display_name = get_localized_name('knowledge', key, display_name)
                parts = internal_name.replace('Knowledge_', '').split('_')
                cat = parts[0] if parts else "Other"
                learned = key in self._know_learned_keys
                self._know_all_entries.append((key, internal_name, cat, learned, display_name))

            learned_count = sum(1 for e in self._know_all_entries if e[3])
            self._know_status.setText(
                f"{learned_count}/{len(self._know_all_entries)} learned"
            )
            self._know_filter()

        except Exception as e:
            import traceback; traceback.print_exc()
            self._know_status.setText(f"Error: {e}")

    def _know_filter_live(self, *_args) -> None:
        self._know_filter(max_rows=100)

    def _know_filter(self, *_args, max_rows: int = 0) -> None:
        if not self._know_all_entries:
            return

        cat_filter = self._know_cat_combo.currentData() or ""
        search = self._know_search.text().lower().strip()
        show_unlearned = self._know_show_unlearned.isChecked()
        show_learned = self._know_show_learned.isChecked()

        filtered = []
        total_matched = 0
        for entry in self._know_all_entries:
            key, internal_name, cat, learned = entry[0], entry[1], entry[2], entry[3]
            display_name = entry[4] if len(entry) > 4 else ''
            if cat_filter and cat != cat_filter:
                continue
            searchable = f"{internal_name} {display_name} {key} {cat}".lower()
            if search and search not in searchable:
                continue
            if show_unlearned and learned:
                continue
            if show_learned and not learned:
                continue
            total_matched += 1
            if max_rows <= 0 or len(filtered) < max_rows:
                filtered.append((key, internal_name, cat, learned, display_name))

        table = self._know_table
        table.setSortingEnabled(False)
        table.setRowCount(len(filtered))

        for row, (key, internal_name, cat, learned, display_name) in enumerate(filtered):
            color = QColor(COLORS['success']) if learned else QColor(COLORS['text_dim'])

            key_w = QTableWidgetItem()
            key_w.setData(Qt.DisplayRole, key)
            key_w.setData(Qt.UserRole, key)
            table.setItem(row, 0, key_w)

            dn_label = display_name if display_name else "(no translation)"
            dn_w = QTableWidgetItem(dn_label)
            dn_w.setForeground(QBrush(color))
            table.setItem(row, 1, dn_w)

            clean = internal_name.replace('Knowledge_', '').replace('_', ' ')
            int_w = QTableWidgetItem(clean)
            int_w.setToolTip(internal_name)
            int_w.setForeground(QBrush(QColor(COLORS['text_dim'])))
            table.setItem(row, 2, int_w)

            cat_w = QTableWidgetItem(cat)
            table.setItem(row, 3, cat_w)

            status_w = QTableWidgetItem("Learned" if learned else "-")
            status_w.setForeground(QBrush(color))
            table.setItem(row, 4, status_w)

        table.setSortingEnabled(True)
        learned_shown = sum(1 for e in filtered if e[3])
        truncated = total_matched > len(filtered)
        trunc_msg = f" (showing {len(filtered)}/{total_matched} — press Enter for all)" if truncated else ""
        self._know_count_label.setText(
            f"Showing {len(filtered)} ({learned_shown} learned, {len(filtered)-learned_shown} unlearned){trunc_msg}"
        )

    def _know_get_selected_keys(self) -> list:
        rows = set(idx.row() for idx in self._know_table.selectedIndexes())
        keys = []
        for row in sorted(rows):
            w = self._know_table.item(row, 0)
            if w:
                keys.append(w.data(Qt.UserRole))
        return keys

    def _know_learn_selected(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Knowledge", "Load a save first.")
            return

        selected = self._know_get_selected_keys()
        to_inject = [k for k in selected if k not in self._know_learned_keys]
        if not to_inject:
            QMessageBox.information(self, "Knowledge", "All selected entries are already learned.")
            return

        reply = QMessageBox.question(
            self, "Learn Knowledge",
            f"Inject {len(to_inject)} knowledge entries into your save?\n\n"
            f"Save (Ctrl+S) afterward for changes to take effect.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        self._know_inject_keys(to_inject)

    def _know_unlearn_selected(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Knowledge", "Load a save first.")
            return

        selected = self._know_get_selected_keys()
        to_unlearn = [k for k in selected if k in self._know_learned_keys]
        if not to_unlearn:
            QMessageBox.information(self, "Knowledge", "No learned entries selected to unlearn.")
            return

        reply = QMessageBox.question(
            self, "Unlearn Knowledge",
            f"Unlearn {len(to_unlearn)} knowledge entries?\n\n"
            f"This sets their level to 0 (unlearned).\n"
            f"Save (Ctrl+S) afterward.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        try:
            import struct as _st
            entry, raw = self._find_parc_block("KnowledgeSaveData")
            if not entry or not raw:
                QMessageBox.warning(self, "Knowledge", "KnowledgeSaveData block not found.")
                return

            target_keys = set(to_unlearn)
            abs_base = entry.data_offset
            blob = self._save_data.decompressed_blob
            patches = []
            unlearned = 0

            for i in range(len(raw) - 14):
                key = _st.unpack_from("<I", raw, i)[0]
                level = _st.unpack_from("<I", raw, i + 4)[0]
                ts = _st.unpack_from("<Q", raw, i + 8)[0]
                if key in target_keys and 1 <= level <= 5 and ts > 1000000:
                    abs_off = abs_base + i + 4
                    old_bytes = bytes(blob[abs_off:abs_off + 4])
                    new_bytes = _st.pack("<I", 0)
                    blob[abs_off:abs_off + 4] = new_bytes
                    patches.append((abs_off, old_bytes, new_bytes))
                    target_keys.discard(key)
                    unlearned += 1

            if unlearned > 0:
                self._undo_stack.append(UndoEntry(
                    description=f"Unlearn {unlearned} knowledge entries",
                    patches=patches,
                ))
                self._dirty = True
                self._know_learned_keys -= set(to_unlearn)
                self._know_all_entries = [
                    (k, n, c, k in self._know_learned_keys, d)
                    for k, n, c, _, d in self._know_all_entries
                ]
                learned_count = sum(1 for e in self._know_all_entries if e[3])
                self._know_status.setText(f"Unlearned {unlearned} entries | {learned_count}/{len(self._know_all_entries)} learned")
                self._know_filter()
            else:
                QMessageBox.information(self, "Knowledge", "Could not find matching entries in save data.")

        except Exception as e:
            import traceback; traceback.print_exc()
            QMessageBox.critical(self, "Error", str(e))

