    def _know_context_menu(self, pos) -> None:
        item = self._know_table.itemAt(pos)
        if item and item.row() >= 0:
            if not self._know_table.selectedIndexes():
                self._know_table.selectRow(item.row())

        menu = QMenu(self)

        add_menu = menu.addMenu("Add to Pack")
        pack_dir = os.path.join(self._app_dir(), 'knowledge_packs')
        existing_packs = []
        if os.path.isdir(pack_dir):
            import json as _json
            for fname in sorted(os.listdir(pack_dir)):
                if fname.endswith('.json'):
                    try:
                        fpath = os.path.join(pack_dir, fname)
                        with open(fpath, 'r') as f:
                            p = _json.load(f)
                        pname = p.get('name', fname.replace('.json', ''))
                        act = add_menu.addAction(pname)
                        existing_packs.append((act, fpath, p))
                    except Exception:
                        pass
        if not existing_packs:
            add_menu.addAction("(no packs — use New Pack in sidebar)").setEnabled(False)

        menu.addSeparator()
        learn_act = menu.addAction("Learn Selected")
        unlearn_act = menu.addAction("Unlearn Selected")
        copy_act = menu.addAction("Copy Key(s)")

        action = menu.exec(self._know_table.mapToGlobal(pos))
        if not action:
            return

        if action == learn_act:
            self._know_learn_selected()
        elif action == unlearn_act:
            self._know_unlearn_selected()
        elif action == copy_act:
            keys = self._know_get_selected_keys()
            if keys:
                QApplication.clipboard().setText(", ".join(str(k) for k in keys))
        else:
            for act, fpath, pack in existing_packs:
                if action == act:
                    self._know_add_to_existing_pack(fpath, pack)
                    break

    def _know_add_to_existing_pack(self, pack_path: str, pack: dict) -> None:
        selected = self._know_get_selected_keys()
        if not selected:
            return

        key_to_info = {e[0]: (e[1], e[4] if len(e) > 4 else '') for e in self._know_all_entries}
        existing_keys = {e['key'] for e in pack.get('entries', [])}
        new_entries = []
        for k in selected:
            if k not in existing_keys:
                name, display = key_to_info.get(k, ('', ''))
                new_entries.append({'key': k, 'name': name, 'display': display})

        if not new_entries:
            QMessageBox.information(self, "Pack", "All selected entries are already in this pack.")
            return

        pack.setdefault('entries', []).extend(new_entries)
        pack['count'] = len(pack['entries'])

        import json as _json
        with open(pack_path, 'w') as f:
            _json.dump(pack, f, indent=2)

        self._pack_browser_refresh()
        QMessageBox.information(self, "Pack Updated",
            f"Added {len(new_entries)} entries to '{pack.get('name', '')}'.\n"
            f"Total: {pack['count']} entries.")

    def _know_export_pack(self) -> None:
        selected = self._know_get_selected_keys()
        if not selected:
            QMessageBox.warning(self, "Knowledge Pack",
                "No entries selected.\n\n"
                "How to select:\n"
                "- Click a row to select one\n"
                "- Ctrl+Click to add more\n"
                "- Shift+Click for a range\n\n"
                "Then right-click > Start New Pack.")
            return

        key_to_info = {e[0]: (e[1], e[4] if len(e) > 4 else '') for e in self._know_all_entries}
        entries = []
        for k in selected:
            name, display = key_to_info.get(k, ('', ''))
            entries.append({'key': k, 'name': name, 'display': display})

        pack_name, ok = QInputDialog.getText(
            self, "Knowledge Pack Name",
            f"Name this knowledge pack ({len(entries)} entries):\n\n"
            f"Examples: 'All Dyes', 'Hernand Teleporters', 'Combat Skills'",
        )
        if not ok or not pack_name.strip():
            return

        pack = {
            'name': pack_name.strip(),
            'type': 'knowledge',
            'count': len(entries),
            'entries': entries,
        }

        pack_dir = os.path.join(self._app_dir(), 'knowledge_packs')
        os.makedirs(pack_dir, exist_ok=True)

        safe_name = "".join(c if c.isalnum() or c in ' _-' else '_' for c in pack_name.strip())
        path = os.path.join(pack_dir, f"{safe_name}.json")

        import json as _json
        with open(path, 'w') as f:
            _json.dump(pack, f, indent=2)

        QMessageBox.information(self, "Knowledge Pack Exported",
            f"Saved '{pack_name}' with {len(entries)} knowledge entries.\n\n"
            f"File: {path}\n\n"
            f"Share this .json file with the community!")

    def _know_inject_pack(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Knowledge", "Load a save first.")
            return

        pack_dir = os.path.join(self._app_dir(), 'knowledge_packs')
        os.makedirs(pack_dir, exist_ok=True)

        path, _ = QFileDialog.getOpenFileName(
            self, "Load Knowledge Pack", pack_dir, "Knowledge Pack (*.json)")
        if not path:
            return

        try:
            import json as _json
            with open(path, 'r') as f:
                pack = _json.load(f)

            pack_name = pack.get('name', os.path.basename(path))
            entries = pack.get('entries', [])
            keys = [e['key'] for e in entries]

            if not keys:
                QMessageBox.information(self, "Knowledge", "Pack is empty.")
                return

            to_inject = [k for k in keys if k not in self._know_learned_keys]
            if not to_inject:
                QMessageBox.information(self, "Knowledge",
                    f"All {len(keys)} entries from '{pack_name}' are already learned.")
                return

            reply = QMessageBox.question(
                self, f"Inject '{pack_name}'",
                f"Inject {len(to_inject)} knowledge entries from '{pack_name}'?\n"
                f"({len(keys) - len(to_inject)} already learned, {len(to_inject)} new)\n\n"
                f"Save (Ctrl+S) afterward.",
                QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
            )
            if reply != QMessageBox.Yes:
                return

            self._know_inject_keys(to_inject)

        except Exception as e:
            import traceback; traceback.print_exc()
            QMessageBox.critical(self, "Pack Error", str(e))

    def _know_import_pack(self) -> None:
        pack_dir = os.path.join(self._app_dir(), 'knowledge_packs')
        os.makedirs(pack_dir, exist_ok=True)

        path, _ = QFileDialog.getOpenFileName(
            self, "Import Knowledge Pack", pack_dir, "Knowledge Pack (*.json)")
        if not path:
            return

        try:
            import json as _json
            with open(path, 'r') as f:
                pack = _json.load(f)

            pack_name = pack.get('name', os.path.basename(path))
            entries = pack.get('entries', [])
            keys = {e['key'] for e in entries}

            self._know_search.setText("")
            self._know_filter()

            self._know_table.clearSelection()
            selected = 0
            for row in range(self._know_table.rowCount()):
                item = self._know_table.item(row, 0)
                if item:
                    try:
                        k = int(item.text())
                        if k in keys:
                            self._know_table.selectRow(row)
                            selected += 1
                    except ValueError:
                        pass

            learned = sum(1 for k in keys if k in self._know_learned_keys)
            self._know_status.setText(
                f"Pack '{pack_name}': {selected}/{len(keys)} found | "
                f"{learned} learned, {len(keys) - learned} not learned"
            )

        except Exception as e:
            QMessageBox.critical(self, "Import Error", str(e))

    def _know_learn_category(self, category: str) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Knowledge", "Load a save first.")
            return

        to_inject = [
            e[0] for e in self._know_all_entries
            if e[2] == category and not e[3]
        ]
        if not to_inject:
            QMessageBox.information(self, "Knowledge", f"All {category} entries already learned.")
            return

        reply = QMessageBox.question(
            self, f"Learn All {category}",
            f"Inject {len(to_inject)} {category} knowledge entries?\n\n"
            f"Save (Ctrl+S) afterward.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        self._know_inject_keys(to_inject)

    def _know_learn_all(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Knowledge", "Load a save first.")
            return
        all_keys = [e[0] for e in self._know_all_entries if not e[3]]
        if not all_keys:
            QMessageBox.information(self, "Knowledge", "All entries already learned.")
            return
        self._know_inject_keys(all_keys)

    def _know_inject_pack_fast(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Knowledge", "Load a save first.")
            return

        pack_dir = os.path.join(self._app_dir(), 'knowledge_packs')
        os.makedirs(pack_dir, exist_ok=True)

        path, _ = QFileDialog.getOpenFileName(
            self, "Load Knowledge Pack (Fast)", pack_dir, "Knowledge Pack (*.json)")
        if not path:
            return

        try:
            import json as _json
            with open(path, 'r') as f:
                pack = _json.load(f)

            pack_name = pack.get('name', os.path.basename(path))
            entries = pack.get('entries', [])
            keys = [e['key'] for e in entries]

            if not keys:
                QMessageBox.information(self, "Knowledge", "Pack is empty.")
                return

            to_inject = [k for k in keys if k not in self._know_learned_keys]
            if not to_inject:
                QMessageBox.information(self, "Knowledge",
                    f"All {len(keys)} entries from '{pack_name}' are already learned.")
                return

            reply = QMessageBox.question(
                self, f"Fast Inject '{pack_name}'",
                f"Inject {len(to_inject)} knowledge entries using fast inserter?\n"
                f"({len(keys) - len(to_inject)} already learned, {len(to_inject)} new)\n\n"
                f"Save (Ctrl+S) afterward.",
                QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
            )
            if reply != QMessageBox.Yes:
                return

            self._know_status.setText(f"Fast injecting {len(to_inject)} entries...")
            QApplication.processEvents()

            import threading

            self._fast_inject_keys = to_inject
            self._fast_inject_done = False
            self._fast_inject_result = (False, None, "")

            def _do_fast_inject():
                try:
                    from parc_inserter3 import inject_knowledge_fast
                    blob = bytearray(self._save_data.decompressed_blob)
                    ok, new_blob, msg = inject_knowledge_fast(blob, keys_filter=self._fast_inject_keys)
                    self._fast_inject_result = (ok, new_blob, msg)
                except Exception as e:
                    self._fast_inject_result = (False, None, str(e))
                self._fast_inject_done = True

            thread = threading.Thread(target=_do_fast_inject, daemon=True)
            thread.start()

            from PySide6.QtCore import QTimer
            def _check_done():
                if not self._fast_inject_done:
                    self._know_status.setText(f"Fast injecting {len(to_inject)} entries... (working)")
                    QTimer.singleShot(200, _check_done)
                    return

                ok, new_blob, msg = self._fast_inject_result
                if ok and new_blob is not None:
                    self._save_data.decompressed_blob = bytearray(new_blob)
                    self._dirty = True
                    self._know_learned_keys.update(self._fast_inject_keys)
                    self._know_all_entries = [
                        (k, n, c, k in self._know_learned_keys, d)
                        for k, n, c, _, d in self._know_all_entries
                    ]
                    learned_count = sum(1 for e in self._know_all_entries if e[3])
                    self._know_status.setText(
                        f"{msg} | {learned_count}/{len(self._know_all_entries)} learned")
                    QMessageBox.information(self, "Fast Inject Complete",
                        f"{msg}\n\nSave (Ctrl+S) for changes to take effect.\n"
                        f"Table will refresh when you switch tabs.")
                else:
                    self._know_status.setText(f"Failed: {msg}")
                    QMessageBox.critical(self, "Injection Failed", msg)

            QTimer.singleShot(200, _check_done)

        except Exception as e:
            import traceback; traceback.print_exc()
            QMessageBox.critical(self, "Pack Error", str(e))

    def _know_inject_keys(self, keys: list) -> None:
        self._know_status.setText(f"Injecting {len(keys)} entries...")
        QApplication.processEvents()

        try:
            from parc_inserter3 import inject_all_knowledge

            blob = bytearray(self._save_data.decompressed_blob)
            ok, new_blob, msg = inject_all_knowledge(blob, keys_filter=keys)

            if ok:
                self._save_data.decompressed_blob = bytearray(new_blob)
                self._dirty = True

                self._know_learned_keys.update(keys)
                self._know_all_entries = [
                    (k, n, c, k in self._know_learned_keys, d)
                    for k, n, c, _, d in self._know_all_entries
                ]
                learned_count = sum(1 for e in self._know_all_entries if e[3])
                self._know_status.setText(
                    f"{msg} | {learned_count}/{len(self._know_all_entries)} learned"
                )

                QMessageBox.information(self, "Knowledge Injected",
                    f"{msg}\n\nSave (Ctrl+S) for changes to take effect.")
            else:
                self._know_status.setText(f"Failed: {msg}")
                QMessageBox.critical(self, "Injection Failed", msg)

        except Exception as e:
            import traceback; traceback.print_exc()
            self._know_status.setText(f"Error: {e}")
            QMessageBox.critical(self, "Error", str(e))


