    def _player_load(self):
        if not self._save_data:
            QMessageBox.warning(self, "Player", "Load a save file first.")
            return

        deep = getattr(self, '_qe_deep_data', None)
        if not deep or (not deep.skills_learned and not deep.friendships):
            try:
                import save_parser as _sp
                from quest_deep_parser import parse_quest_deep
                self._player_skills_status.setText("Parsing save...")
                QApplication.processEvents()

                raw = bytes(self._save_data.decompressed_blob)
                result = _sp.build_result_from_raw(raw, {'input_kind': 'raw_blob'})
                deep = parse_quest_deep(raw, result,
                                        quest_names=getattr(self, '_quest_names', {}),
                                        mission_names=getattr(self, '_mission_names', {}))
                self._qe_deep_data = deep
            except Exception as e:
                import traceback; traceback.print_exc()
                QMessageBox.critical(self, "Player", f"Failed to parse: {e}")
                return

        skills = deep.skills_learned
        self._player_skills_table.setSortingEnabled(False)
        self._player_skills_table.setRowCount(len(skills))
        for i, sk in enumerate(skills):
            key = sk.get('key', 0)
            kinfo = self._knowledge_names.get(key, {})

            item = QTableWidgetItem(str(key))
            item.setData(Qt.UserRole, sk)
            self._player_skills_table.setItem(i, 0, item)

            self._player_skills_table.setItem(i, 1, QTableWidgetItem(kinfo.get('name', '')))
            self._player_skills_table.setItem(i, 2, QTableWidgetItem(kinfo.get('display', '')))

            count_item = QTableWidgetItem(str(sk.get('artifact_count', 0)))
            count_item.setTextAlignment(Qt.AlignRight | Qt.AlignVCenter)
            self._player_skills_table.setItem(i, 3, count_item)

        self._player_skills_table.setSortingEnabled(True)
        self._player_skills_table.resizeColumnsToContents()
        self._player_skills_status.setText(f"{len(skills)} skills/knowledge learned")

        friends = deep.friendships
        char_names = {}
        try:
            import sys as _sys
            base = getattr(_sys, '_MEIPASS', os.path.dirname(os.path.abspath(__file__)))
            gm_path = os.path.join(base, 'game_map.json')
            if os.path.exists(gm_path):
                with open(gm_path, 'r', encoding='utf-8') as f:
                    gm = json.load(f)
                for entry in gm.get('characterinfo', []):
                    if isinstance(entry, dict) and '_key' in entry:
                        char_names[entry['_key']] = entry.get('_stringKey', '')
        except Exception:
            pass

        self._player_friend_table.setSortingEnabled(False)
        self._player_friend_table.setRowCount(len(friends))
        for i, fr in enumerate(friends):
            ckey = fr.get('character_key', 0)
            item = QTableWidgetItem(str(ckey))
            item.setData(Qt.UserRole, fr)
            self._player_friend_table.setItem(i, 0, item)

            name = char_names.get(ckey, '')
            self._player_friend_table.setItem(i, 1, QTableWidgetItem(name))

            threat = QTableWidgetItem("Yes" if fr.get('threat_rewarded') else "No")
            if fr.get('threat_rewarded'):
                threat.setForeground(QColor(COLORS['success']))
            self._player_friend_table.setItem(i, 2, threat)

            memory = QTableWidgetItem("Yes" if fr.get('read_memory_rewarded') else "No")
            if fr.get('read_memory_rewarded'):
                memory.setForeground(QColor(COLORS['success']))
            self._player_friend_table.setItem(i, 3, memory)

        self._player_friend_table.setSortingEnabled(True)
        self._player_friend_table.resizeColumnsToContents()
        self._player_friend_status.setText(f"{len(friends)} NPC friendships")


