    @staticmethod
    def _find_fog_codelist(raw: bytes) -> Optional[Tuple[int, int]]:
        size = len(raw)
        for i in range(size - 8):
            count = struct.unpack_from("<I", raw, i)[0]
            if count < 500 or count > 100000:
                continue
            end1 = i + 4 + count
            off2 = end1 + 1
            if off2 + 4 + count > size:
                continue
            count2 = struct.unpack_from("<I", raw, off2)[0]
            if count2 != count:
                continue
            sample = raw[i + 4 : i + 4 + min(200, count)]
            fog_like = sum(1 for b in sample if b in (0x00, 0xFF))
            if fog_like * 100 // max(len(sample), 1) >= 90:
                return (i, count)
        return None

    def _find_parc_block(self, class_name: str):
        if not self._save_data:
            return None, None
        try:
            import parc_serializer as ps
            parc = ps.parse_parc_blob(bytes(self._save_data.decompressed_blob))
            for e in parc.toc_entries:
                if e.class_index < len(parc.types):
                    if parc.types[e.class_index].name == class_name:
                        return e, parc.block_raw[e.index]
            return None, None
        except Exception as exc:
            log.warning("PARC lookup for %s failed: %s", class_name, exc)
            return None, None

    def _populate_debug_tab(self) -> None:
        if not self._save_data:
            return
        blob = self._save_data.decompressed_blob


        entry_eq, raw_eq = self._find_parc_block("EquipmentSaveData")
        if entry_eq and raw_eq:
            abs_off = entry_eq.data_offset
            self._debug_equip_offset = abs_off
            try:
                import parc_serializer as ps
                parc = ps.parse_parc_blob(bytes(blob))
                td = parc.type_by_index[entry_eq.class_index]
                reader = ps.BlockParser(parc)
                parsed = reader.parse_root_block(entry_eq.index)
                for f in parsed["fields"]:
                    if f["name"] == "_equipCacheSequenceNo" and f["present"]:
                        val = f["value"]
                        if isinstance(val, int):
                            self._debug_eqseq_cur.setText(str(val))
                            self._debug_eqseq_spin.setValue(min(val, 999999999))
                            self._debug_eqseq_field_offset = f["start"]
                            self._debug_eqseq_field_size = f["end"] - f["start"]
                            break
                else:
                    self._debug_eqseq_cur.setText("field not present")
                    self._debug_eqseq_field_offset = -1
            except Exception as exc:
                log.warning("Equip cache seq read failed: %s", exc)
                self._debug_eqseq_cur.setText("parse error")
                self._debug_eqseq_field_offset = -1
        else:
            self._debug_equip_offset = -1
            self._debug_eqseq_cur.setText("not found")
            self._debug_eqseq_field_offset = -1

        try:
            entry_fog, raw_fog = self._find_parc_block("FogSaveData")
            if entry_fog and raw_fog:
                result = self._find_fog_codelist(raw_fog)
                if result:
                    idx, codelist_count = result
                    data_start = idx + 4
                    code_bytes = raw_fog[data_start:data_start + codelist_count]
                    revealed = sum(1 for b in code_bytes if b == 0xFF)
                    fog_text = f"{revealed}/{codelist_count} pixels revealed"
                    self._debug_fog_status.setText(fog_text)
                    if hasattr(self, '_waypoint_fog_status'):
                        self._waypoint_fog_status.setText(fog_text)
                else:
                    self._debug_fog_status.setText("_codeList not found")
            else:
                self._debug_fog_status.setText("FogSaveData not found")
        except Exception as exc:
            log.warning("Fog status read failed: %s", exc)
            self._debug_fog_status.setText("parse error")

        try:
            entry_k, raw_k = self._find_parc_block("KnowledgeSaveData")
            if entry_k and raw_k:
                abs_off = entry_k.data_offset
                total = 0
                maxed = 0
                for i in range(len(raw_k) - 16):
                    key = struct.unpack_from("<I", raw_k, i)[0]
                    level = struct.unpack_from("<I", raw_k, i + 4)[0]
                    if i + 16 > len(raw_k):
                        break
                    ts = struct.unpack_from("<Q", raw_k, i + 8)[0]
                    if key > 0 and 1 <= level <= 5 and ts > 1000000:
                        total += 1
                        if level == 5:
                            maxed += 1
                self._debug_knowledge_status.setText(f"{total} entries ({maxed} at Lv 5)")
            else:
                self._debug_knowledge_status.setText("KnowledgeSaveData not found")
        except Exception as exc:
            log.warning("Knowledge status read failed: %s", exc)
            self._debug_knowledge_status.setText("parse error")

    def _debug_set_eqseq(self) -> None:
        if not self._save_data or not hasattr(self, '_debug_eqseq_field_offset') or self._debug_eqseq_field_offset < 0:
            QMessageBox.warning(self, "Debug", "EquipmentSaveData _equipCacheSequenceNo not found.")
            return
        blob = self._save_data.decompressed_blob
        off = self._debug_eqseq_field_offset
        size = self._debug_eqseq_field_size
        old_bytes = bytes(blob[off:off + size])
        new_val = self._debug_eqseq_spin.value()
        new_bytes = struct.pack("<I", new_val)
        blob[off:off + size] = new_bytes
        self._undo_stack.append(UndoEntry(
            description=f"Debug: set equipCacheSequenceNo to {new_val}",
            patches=[(off, old_bytes, bytes(new_bytes))],
        ))
        self._dirty = True
        self._debug_eqseq_cur.setText(str(new_val))
        self._update_status(f"Equip cache sequence set to {new_val}")

    def _debug_reveal_map(self) -> None:
        self._set_fog(0xFF, "Reveal Entire Map",
            "This will set all fog-of-war bytes to fully revealed (0xFF).")

    def _debug_refog_map(self) -> None:
        self._set_fog(0x00, "Re-Fog Entire Map",
            "This will set all fog-of-war bytes to hidden (0x00).\n"
            "Your entire map will be covered in fog again.")

    def _set_fog(self, value: int, title: str, description: str) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Debug", "No save loaded.")
            return
        entry, raw = self._find_parc_block("FogSaveData")
        if not entry or not raw:
            QMessageBox.warning(self, "Debug", "FogSaveData block not found in save.")
            return
        result = self._find_fog_codelist(raw)
        if not result:
            QMessageBox.warning(self, "Debug", "_codeList fog array not found in FogSaveData.")
            return
        idx, codelist_count = result
        reply = QMessageBox.question(
            self, title,
            f"{description}\n\n"
            f"{codelist_count} fog bytes will be changed.\n"
            "This change can be undone. Continue?",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return
        blob = self._save_data.decompressed_blob
        abs_data_start = entry.data_offset + idx + 4
        old_bytes = bytes(blob[abs_data_start:abs_data_start + codelist_count])
        new_bytes = bytes([value] * codelist_count)
        blob[abs_data_start:abs_data_start + codelist_count] = new_bytes
        self._undo_stack.append(UndoEntry(
            description=f"{'Reveal' if value == 0xFF else 'Re-fog'} map ({codelist_count} fog bytes)",
            patches=[(abs_data_start, old_bytes, new_bytes)],
        ))
        self._dirty = True
        if value == 0xFF:
            self._debug_fog_status.setText(f"{codelist_count}/{codelist_count} pixels revealed")
        else:
            self._debug_fog_status.setText(f"0/{codelist_count} pixels revealed (fogged)")
        self._update_status(f"Map {'revealed' if value == 0xFF else 're-fogged'} ({codelist_count} fog bytes)")
        save_reply = QMessageBox.question(
            self, "Map Modified",
            f"Map {'revealed' if value == 0xFF else 're-fogged'}.\n\n"
            f"Save to disk now?",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.Yes,
        )
        if save_reply == QMessageBox.Yes:
            self._save_file()

    def _debug_max_knowledge(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Debug", "No save loaded.")
            return
        entry, raw = self._find_parc_block("KnowledgeSaveData")
        if not entry or not raw:
            QMessageBox.warning(self, "Debug", "KnowledgeSaveData block not found in save.")
            return
        matches = []
        for i in range(len(raw) - 14):
            key = struct.unpack_from("<I", raw, i)[0]
            level = struct.unpack_from("<I", raw, i + 4)[0]
            ts = struct.unpack_from("<Q", raw, i + 8)[0]
            if key > 0 and 1 <= level <= 5 and ts > 1000000:
                matches.append((i, level))
        if not matches:
            QMessageBox.warning(self, "Debug", "No knowledge entries found in KnowledgeSaveData.")
            return
        need_upgrade = [(off, lvl) for off, lvl in matches if lvl < 5]
        if not need_upgrade:
            QMessageBox.information(self, "Debug", f"All {len(matches)} knowledge entries are already at Lv 5.")
            return
        reply = QMessageBox.question(
            self, "Max All Knowledge",
            f"Found {len(matches)} knowledge entries, {len(need_upgrade)} below Lv 5.\n\n"
            f"Set all to Lv 5? This change can be undone.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return
        blob = self._save_data.decompressed_blob
        abs_base = entry.data_offset
        patches = []
        new_level_bytes = struct.pack("<I", 5)
        for rel_off, old_lvl in need_upgrade:
            abs_off = abs_base + rel_off + 4
            old_bytes = bytes(blob[abs_off:abs_off + 4])
            blob[abs_off:abs_off + 4] = new_level_bytes
            patches.append((abs_off, old_bytes, bytes(new_level_bytes)))
        self._undo_stack.append(UndoEntry(
            description=f"Debug: max all knowledge ({len(need_upgrade)} entries to Lv 5)",
            patches=patches,
        ))
        self._dirty = True
        self._debug_knowledge_status.setText(f"{len(matches)} entries ({len(matches)} at Lv 5)")
        self._update_status(f"Knowledge maxed: {len(need_upgrade)} entries set to Lv 5")


    def _populate_bag_space(self) -> None:
        self._bag_categories = []
        self._bag_table.setRowCount(0)
        if not self._save_data:
            return
        try:
            import parc_serializer as ps
            blob = self._save_data.decompressed_blob
            parc = ps.parse_parc_blob(bytes(blob))
            inv_toc = ps.find_inventory_toc_index(parc)
            if inv_toc is None:
                return
            cats = ps._find_inventory_categories(parc, inv_toc)
            self._bag_table.setRowCount(len(cats))
            for i, cat in enumerate(cats):
                inv_key = cat["inventory_key"]
                mask_bytes = cat["mask_bytes"]
                has_expand = ps._field_present(mask_bytes, 1)
                expand_val = 0
                expand_abs = -1
                if has_expand:
                    ppos = cat["payload_abs"] + 4
                    if ps._field_present(mask_bytes, 0):
                        ppos += 2
                    expand_abs = ppos
                    expand_val = struct.unpack_from("<H", blob, ppos)[0]

                self._bag_categories.append({
                    "inventory_key": inv_key,
                    "expand_abs": expand_abs,
                    "expand_val": expand_val,
                    "has_expand": has_expand,
                })

                cat_item = QTableWidgetItem(str(inv_key))
                cat_item.setTextAlignment(Qt.AlignCenter)
                self._bag_table.setItem(i, 0, cat_item)

                slots_item = QTableWidgetItem(str(expand_val) if has_expand else "N/A")
                slots_item.setTextAlignment(Qt.AlignCenter)
                self._bag_table.setItem(i, 1, slots_item)

                if not has_expand:
                    status = "No expand field"
                    color = COLORS["text_dim"]
                elif expand_val > 240:
                    status = f"DANGER (>240)"
                    color = COLORS["error"]
                else:
                    status = "OK"
                    color = COLORS["success"]
                status_item = QTableWidgetItem(status)
                status_item.setTextAlignment(Qt.AlignCenter)
                status_item.setForeground(QBrush(QColor(color)))
                self._bag_table.setItem(i, 2, status_item)

                if has_expand and expand_val > 240:
                    for col in range(3):
                        item = self._bag_table.item(i, col)
                        if item:
                            item.setForeground(QBrush(QColor(COLORS["error"])))

        except Exception as exc:
            log.warning("Bag space populate failed: %s", exc)

    def _debug_fix_bag_space(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Debug", "No save loaded.")
            return
        if not self._bag_categories:
            QMessageBox.warning(self, "Debug", "No inventory categories found. Load a save first.")
            return

        safe_val = self._bag_safe_spin.value()
        unsafe = [c for c in self._bag_categories if c["has_expand"] and c["expand_val"] > 240]

        if not unsafe:
            QMessageBox.information(self, "Bag Space Fix",
                                    "All categories are within safe limits (<=240). Nothing to fix.")
            return

        reply = QMessageBox.question(
            self, "Fix Bag Space",
            f"Found {len(unsafe)} category(ies) with expand slots > 240.\n\n"
            f"Reset them to {safe_val}? This change can be undone.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        blob = self._save_data.decompressed_blob
        patches = []
        for cat in unsafe:
            abs_off = cat["expand_abs"]
            old_bytes = bytes(blob[abs_off:abs_off + 2])
            new_bytes = struct.pack("<H", safe_val)
            blob[abs_off:abs_off + 2] = new_bytes
            patches.append((abs_off, old_bytes, bytes(new_bytes)))
            cat["expand_val"] = safe_val

        self._undo_stack.append(UndoEntry(
            description=f"Debug: fix bag space ({len(unsafe)} categories reset to {safe_val})",
            patches=patches,
        ))
        self._dirty = True
        self._populate_bag_space()
        self._update_status(f"Bag space fixed: {len(unsafe)} categories reset to {safe_val}")


