    def _get_export_dir(self) -> str:
        import sys as _sys
        if getattr(_sys, 'frozen', False):
            base = os.path.dirname(os.path.abspath(_sys.executable))
        else:
            base = os.path.dirname(os.path.abspath(__file__))
        export_dir = os.path.join(base, "Exports")
        os.makedirs(export_dir, exist_ok=True)
        return export_dir

    def _export_mod_json(self) -> None:
        try:
            from mod_export import ModExporter
            from paz_patcher import PazPatchManager
            game_path = PazPatchManager.find_game_path()
            if not game_path:
                QMessageBox.warning(self, "Export", "Game installation not found.")
                return

            exporter = ModExporter(game_path)
            summary = exporter.get_summary()
            if "No modifications" in summary:
                QMessageBox.information(self, "Export", summary)
                return

            export_dir = self._get_export_dir()
            path = os.path.join(export_dir, "crimson_save_editor_patch.json")

            self._export_status.setText("EXPORTING JSON — DO NOT CLOSE. This may take a few minutes...")
            self._export_status.setStyleSheet(f"color: {COLORS['error']}; font-weight: bold; font-size: 13px; padding: 4px;")
            if hasattr(self, '_center_status'):
                self._center_status.setText("EXPORTING JSON — DO NOT CLOSE")
            QApplication.processEvents()

            ok, msg = exporter.export_nexus_json(path, lambda s: (
                self._export_status.setText(s), QApplication.processEvents()
            ))

            self._export_status.setStyleSheet(f"color: {COLORS['accent']}; padding: 4px;")
            if hasattr(self, '_center_status'):
                self._center_status.setText("Export complete")
            if ok:
                ok_v, msg_v = exporter.verify_nexus_json(path)
                self._export_status.setText(msg)
                QMessageBox.information(self, "Export Complete",
                    f"{msg}\n\nVerification: {msg_v}\n\nSaved to:\n{path}")
            else:
                self._export_status.setText(msg)
                QMessageBox.warning(self, "Export Failed", msg)
        except Exception as e:
            import traceback; traceback.print_exc()
            self._export_status.setStyleSheet(f"color: {COLORS['accent']}; padding: 4px;")
            QMessageBox.critical(self, "Export Error", str(e))

    def _export_mod_zip(self) -> None:
        try:
            from mod_export import ModExporter
            from paz_patcher import PazPatchManager
            game_path = PazPatchManager.find_game_path()
            if not game_path:
                QMessageBox.warning(self, "Export", "Game installation not found.")
                return

            exporter = ModExporter(game_path)
            summary = exporter.get_summary()
            if "No modifications" in summary:
                QMessageBox.information(self, "Export", summary)
                return

            reply = QMessageBox.question(
                self, "Export CDUMM ZIP",
                "This exports your game file modifications as a ZIP\n"
                "compatible with CrimsonDesert Ultimate Mods Manager.\n\n"
                "WARNING: This takes 5-10 MINUTES and the window\n"
                "WILL FREEZE during export (packaging ~250MB+ PAZ file).\n"
                "DO NOT CLOSE the program while exporting.\n\n"
                "The ZIP will be saved to the Exports folder next to the exe.\n\n"
                "Continue?",
                QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
            )
            if reply != QMessageBox.Yes:
                return

            export_dir = self._get_export_dir()
            path = os.path.join(export_dir, "CrimsonSaveEditor_Patches.zip")

            self._export_status.setText("EXPORTING — DO NOT CLOSE. This takes 5-10 minutes...")
            self._export_status.setStyleSheet(f"color: {COLORS['error']}; font-weight: bold; font-size: 13px; padding: 4px;")
            if hasattr(self, '_center_status'):
                self._center_status.setText("EXPORTING ZIP — DO NOT CLOSE (5-10 minutes)")
            QApplication.processEvents()

            ok, msg = exporter.export_cdumm_zip(
                path, mod_name="CrimsonSaveEditor Patches",
                progress_callback=lambda s: (
                    self._export_status.setText(s), QApplication.processEvents()
                )
            )

            self._export_status.setStyleSheet(f"color: {COLORS['accent']}; padding: 4px;")
            self._export_status.setText(msg)
            if hasattr(self, '_center_status'):
                self._center_status.setText("Export complete")
            if ok:
                QMessageBox.information(self, "Export Complete",
                    f"{msg}\n\nSaved to:\n{path}\n\n"
                    f"Drag this ZIP into CDUMM to import.")
            else:
                QMessageBox.warning(self, "Export Failed", msg)
        except Exception as e:
            import traceback; traceback.print_exc()
            self._export_status.setStyleSheet(f"color: {COLORS['accent']}; padding: 4px;")
            QMessageBox.critical(self, "Export Error", str(e))


    def _cmod_get_loader(self):
        if self._cmod_loader is None:
            game_path = self._paz_game_path.text().strip()
            if not game_path or not os.path.isdir(game_path):
                from paz_patcher import PazPatchManager
                game_path = PazPatchManager.find_game_path()
            if not game_path:
                QMessageBox.warning(self, "Community Mods",
                    "Game installation not found. Set path using the Browse button at the top.")
                return None
            from mod_loader import CommunityModLoader
            self._cmod_loader = CommunityModLoader(game_path)
            self._cmod_loader.ensure_folders()
        return self._cmod_loader

    def _cmod_refresh(self) -> None:
        if not hasattr(self, '_cmod_table'):
            return
        loader = self._cmod_get_loader()
        if not loader:
            return

        try:
            loader.scan_mods()
        except Exception as ex:
            try:
                self._cmod_status.setText(f"Scan error: {ex}")
            except RuntimeError:
                pass
            return

        table = getattr(self, '_cmod_table', None)
        if table is None:
            return
        try:
            import shiboken6
            if not shiboken6.isValid(table):
                return
        except ImportError:
            pass
        try:
            table.setRowCount(len(loader.mods))
        except RuntimeError:
            return

        for row, mod in enumerate(loader.mods):
            cb = QCheckBox()
            cb.setChecked(mod.enabled)
            cb.stateChanged.connect(
                lambda state, r=row: self._cmod_toggle(r, state))
            cell_widget = QWidget()
            cell_layout = QHBoxLayout(cell_widget)
            cell_layout.addWidget(cb)
            cell_layout.setAlignment(cb, Qt.AlignCenter)
            cell_layout.setContentsMargins(0, 0, 0, 0)
            table.setCellWidget(row, 0, cell_widget)

            name_item = QTableWidgetItem(mod.name)
            name_item.setToolTip(mod.filename)
            table.setItem(row, 1, name_item)

            table.setItem(row, 2, QTableWidgetItem(mod.author))

            if mod.status == "error":
                status_text = f"Error: {mod.error_msg[:40]}"
                color = COLORS['error']
            elif not mod.enabled:
                status_text = "Disabled"
                color = COLORS['text_dim']
            else:
                try:
                    status_text = loader.get_mod_status_summary(mod)
                except Exception:
                    status_text = "Unknown"
                color = COLORS['accent'] if "Applied" in status_text else COLORS['text']
                if "Conflict" in status_text:
                    color = COLORS['warning']

            status_item = QTableWidgetItem(status_text)
            status_item.setForeground(QColor(color))
            table.setItem(row, 3, status_item)

            desc = mod.description or mod.version or ""
            table.setItem(row, 4, QTableWidgetItem(desc))

        count = len(loader.mods)
        enabled = sum(1 for m in loader.mods if m.enabled)
        self._cmod_status.setText(
            f"{count} mod(s) found, {enabled} enabled")

    def _cmod_toggle(self, row: int, state: int) -> None:
        loader = self._cmod_get_loader()
        if not loader or row >= len(loader.mods):
            return
        loader.mods[row].enabled = bool(state)
        loader.save_config()
        self._cmod_refresh()

    def _cmod_apply_all(self) -> None:
        loader = self._cmod_get_loader()
        if not loader:
            return

        if not loader.mods:
            loader.scan_mods()

        enabled = [m for m in loader.mods if m.enabled]
        if not enabled:
            self._cmod_status.setText("No mods enabled")
            return

        warnings = loader.detect_all_conflicts()
        if warnings:
            msg = "Conflicts detected between mods:\n\n"
            msg += "\n".join(f"  • {w}" for w in warnings[:5])
            if len(warnings) > 5:
                msg += f"\n  ... and {len(warnings) - 5} more"
            msg += "\n\nConflicting changes will be skipped. Continue?"
            reply = QMessageBox.question(
                self, "Mod Conflicts Detected", msg,
                QMessageBox.Yes | QMessageBox.No, QMessageBox.Yes)
            if reply != QMessageBox.Yes:
                return

        def backup_cb(paz_path):
            self._paz_manager.game_path = loader.game_path
            self._paz_manager.create_backup(paz_path)

        self._cmod_status.setText("Applying community mods...")
        QApplication.processEvents()

        applied, skipped, errors = loader.apply_all_enabled(
            backup_callback=backup_cb)

        self._cmod_update_checksums(loader)

        loader.save_config()

        if errors:
            msg = f"Applied {applied}, skipped {skipped}, errors: {len(errors)}"
            self._cmod_status.setText(msg)
            detail = "\n".join(errors[:10])
            QMessageBox.warning(self, "Community Mods — Partial", f"{msg}\n\n{detail}")
        else:
            msg = f"Applied {applied} mod(s) successfully"
            if skipped:
                msg += f", {skipped} disabled"
            self._cmod_status.setText(msg)

        self._cmod_refresh()

    def _cmod_update_checksums(self, loader) -> None:
        try:
            game_path = loader.game_path
            touched_dirs = set()
            for mod in loader.mods:
                if mod.status != "applied":
                    continue
                for patch in mod.patches:
                    if patch.paz_path:
                        paz_dir = os.path.basename(os.path.dirname(patch.paz_path))
                        touched_dirs.add(paz_dir)

            if not touched_dirs:
                return

            self._paz_manager.game_path = game_path
            for paz_dir in touched_dirs:
                pamt_path = os.path.join(game_path, paz_dir, "0.pamt")
                if os.path.isfile(pamt_path):
                    ok, msg = self._paz_manager.update_pamt_checksum(pamt_path)
                    if ok:
                        log.info("Updated PAMT checksum for %s", paz_dir)
                    else:
                        log.warning("PAMT checksum update failed for %s: %s",
                                    paz_dir, msg)

            ok, msg = self._paz_manager.update_papgt()
            if ok:
                log.info("Updated PAPGT integrity chain")
            else:
                log.warning("PAPGT update: %s", msg)
        except Exception as ex:
            log.warning("Checksum update failed: %s", ex)

    def _cmod_open_folder(self) -> None:
        loader = self._cmod_get_loader()
        if not loader:
            return
        json_dir = loader.json_dir
        os.makedirs(json_dir, exist_ok=True)
        if os.name == 'nt':
            os.startfile(json_dir)
        else:
            import subprocess
            subprocess.Popen(["xdg-open", json_dir])


    def _asi_get_manager(self):
        if self._asi_manager is None:
            game_path = self._paz_game_path.text().strip()
            if not game_path or not os.path.isdir(game_path):
                from paz_patcher import PazPatchManager
                game_path = PazPatchManager.find_game_path()
            if not game_path:
                return None
            from mod_loader import AsiManager
            self._asi_manager = AsiManager(game_path)
        return self._asi_manager

    def _asi_refresh(self) -> None:
        if not hasattr(self, '_asi_table'):
            return
        mgr = self._asi_get_manager()
        if not mgr:
            return

        plugins = mgr.scan()
        table = getattr(self, '_asi_table', None)
        if table is None:
            return
        try:
            import shiboken6
            if not shiboken6.isValid(table):
                return
        except ImportError:
            pass
        try:
            table.setRowCount(len(plugins))
        except RuntimeError:
            return

        has_loader = mgr.has_loader()

        for row, plugin in enumerate(plugins):
            cb = QCheckBox()
            cb.setChecked(plugin.enabled)
            cb.setEnabled(plugin.installed)
            cb.stateChanged.connect(
                lambda state, r=row: self._asi_toggle(r, state))
            cell_widget = QWidget()
            cell_layout = QHBoxLayout(cell_widget)
            cell_layout.addWidget(cb)
            cell_layout.setAlignment(cb, Qt.AlignCenter)
            cell_layout.setContentsMargins(0, 0, 0, 0)
            table.setCellWidget(row, 0, cell_widget)

            table.setItem(row, 1, QTableWidgetItem(plugin.name))

            if not plugin.installed:
                status = "Available (not installed)"
                color = COLORS['text_dim']
            elif plugin.enabled:
                status = "Enabled"
                color = COLORS['success']
            else:
                status = "Disabled"
                color = COLORS['text_dim']

            status_item = QTableWidgetItem(status)
            status_item.setForeground(QColor(color))
            table.setItem(row, 2, status_item)

            table.setItem(row, 3, QTableWidgetItem(str(plugin.path)))

        loader_msg = "ASI Loader: Found" if has_loader else "ASI Loader: Not found (winmm.dll)"
        count = len(plugins)
        installed = sum(1 for p in plugins if p.installed)
        self._asi_status.setText(
            f"{count} plugin(s), {installed} installed | {loader_msg}")

    def _asi_toggle(self, row: int, state: int) -> None:
        mgr = self._asi_get_manager()
        if not mgr or row >= len(mgr.plugins):
            return
        plugin = mgr.plugins[row]
        if not plugin.installed:
            return
        try:
            if state:
                mgr.enable_plugin(plugin)
            else:
                mgr.disable_plugin(plugin)
        except Exception as ex:
            self._asi_status.setText(f"Error: {ex}")
        self._asi_refresh()

    def _asi_install_selected(self) -> None:
        mgr = self._asi_get_manager()
        if not mgr:
            return
        rows = self._asi_table.selectionModel().selectedRows()
        if not rows:
            QMessageBox.information(self, "No Selection",
                                    "Select a plugin from the table first.")
            return
        row = rows[0].row()
        if row >= len(mgr.plugins):
            return
        plugin = mgr.plugins[row]
        if plugin.installed:
            self._asi_status.setText(f"{plugin.name} already installed")
            return
        try:
            msg = mgr.install_plugin(plugin)
            self._asi_status.setText(msg)
        except Exception as ex:
            QMessageBox.critical(self, "Install Failed", str(ex))
        self._asi_refresh()

    def _asi_uninstall_selected(self) -> None:
        mgr = self._asi_get_manager()
        if not mgr:
            return
        rows = self._asi_table.selectionModel().selectedRows()
        if not rows:
            QMessageBox.information(self, "No Selection",
                                    "Select a plugin from the table first.")
            return
        row = rows[0].row()
        if row >= len(mgr.plugins):
            return
        plugin = mgr.plugins[row]
        if not plugin.installed:
            self._asi_status.setText(f"{plugin.name} not installed")
            return
        reply = QMessageBox.question(
            self, "Uninstall ASI",
            f"Remove {plugin.name} from bin64/?",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No)
        if reply != QMessageBox.Yes:
            return
        try:
            msg = mgr.uninstall_plugin(plugin)
            self._asi_status.setText(msg)
        except Exception as ex:
            QMessageBox.critical(self, "Uninstall Failed", str(ex))
        self._asi_refresh()

    def _asi_open_folder(self) -> None:
        mgr = self._asi_get_manager()
        if not mgr:
            loader = self._cmod_get_loader()
            if loader:
                asi_dir = loader.asi_dir
            else:
                return
        else:
            asi_dir = str(mgr.asi_source)
        os.makedirs(asi_dir, exist_ok=True)
        if os.name == 'nt':
            os.startfile(asi_dir)
        else:
            import subprocess
            subprocess.Popen(["xdg-open", asi_dir])


