    def _cmod_restore_all(self) -> None:
        game_path = self._paz_game_path.text().strip()
        if not game_path or not os.path.isdir(game_path):
            QMessageBox.warning(self, "Restore", "Set a valid game path first.")
            return

        import shutil

        targets = []
        for sub in ["0008", "meta"]:
            d = os.path.join(game_path, sub)
            if not os.path.isdir(d):
                continue
            for f in os.listdir(d):
                if f.endswith('.sebak'):
                    targets.append(os.path.join(d, f))

        if not targets:
            QMessageBox.information(self, "Restore",
                "No .sebak backups found.\n\n"
                "Use Steam → Verify integrity of game files.")
            return

        summary = "Restore from backup:\n"
        for t in targets:
            summary += f"  {os.path.relpath(t[:-6], game_path)}\n"

        reply = QMessageBox.question(
            self, "Restore All",
            summary + "\nProceed?",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No)
        if reply != QMessageBox.Yes:
            return

        restored = []
        for t in targets:
            orig = t[:-6]
            try:
                shutil.copy2(t, orig)
                restored.append(os.path.relpath(orig, game_path))
            except Exception as e:
                log.warning("Restore failed for %s: %s", t, e)

        self._cmod_status.setText(f"Restored {len(restored)} file(s)")
        QMessageBox.information(self, "Restored",
            f"Restored {len(restored)} file(s).\n"
            f"Restart the game for changes to take effect.")

