    def _paz_populate_table(self) -> None:
        table = self._paz_patch_table
        patches = self._paz_patches
        table.setRowCount(len(patches))

        for row, patch in enumerate(patches):
            name_item = QTableWidgetItem(patch.name)
            name_item.setFont(QFont("Consolas", 11, QFont.Bold))
            table.setItem(row, 0, name_item)

            status_item = QTableWidgetItem("...")
            status_item.setForeground(QBrush(QColor(COLORS["text_dim"])))
            table.setItem(row, 1, status_item)

            table.setItem(row, 2, QTableWidgetItem(patch.description))

            table.setItem(row, 3, QTableWidgetItem("..."))

        QTimer.singleShot(100, self._paz_refresh_status)

    def _launch_visibility_editor(self) -> None:
        import subprocess
        import os

        candidates = []
        if hasattr(sys, '_MEIPASS'):
            candidates.append(os.path.join(sys._MEIPASS, 'Communitydump', 'source', 'Visibility_changer.py'))
        candidates.append(os.path.join(os.path.dirname(os.path.abspath(__file__)),
                                        'Communitydump', 'source', 'Visibility_changer.py'))
        candidates.append(os.path.join(os.getcwd(), 'Communitydump', 'source', 'Visibility_changer.py'))

        script = None
        for c in candidates:
            if os.path.isfile(c):
                script = c
                break

        if not script:
            QMessageBox.warning(self, "Not Found",
                                "Weapon Visibility Editor not found.\n\n"
                                "Looked in:\n" + "\n".join(candidates))
            return
        try:
            subprocess.Popen([sys.executable, script], cwd=os.path.dirname(script))
            self._update_status("Launched Weapon Visibility Editor")
        except Exception as e:
            QMessageBox.warning(self, "Launch Failed", f"Could not launch:\n{e}")

    def _paz_refresh_status(self) -> None:
        if not hasattr(self, '_paz_patch_table'):
            return
        if not self._paz_manager.game_path:
            self._paz_status_label.setText("No game path set. Use Auto-Detect or Browse.")
            return

        self._paz_status_label.setText("Scanning PAZ files...")
        QApplication.processEvents()

        from paz_patcher import PatchStatus

        table = self._paz_patch_table
        for row, patch in enumerate(self._paz_patches):
            try:
                if patch.name == "Mount Death Respawn (1s)":
                    if self._config.get("patch_mount_cooldown_applied"):
                        status = PatchStatus("Mount Death Respawn (1s)", "Applied",
                                             "Patch applied (per config)")
                    else:
                        status = PatchStatus("Mount Death Respawn (1s)", "Not Applied", "")
                else:
                    status = self._paz_manager.get_detailed_status(patch)

                status_item = table.item(row, 1)
                if status_item is None:
                    status_item = QTableWidgetItem()
                    table.setItem(row, 1, status_item)

                status_item.setText(status.status)

                if status.status == "Applied":
                    status_item.setForeground(QBrush(QColor(COLORS["success"])))
                elif status.status == "Not Applied":
                    status_item.setForeground(QBrush(QColor(COLORS["text"])))
                elif status.status == "Partial":
                    status_item.setForeground(QBrush(QColor(COLORS["warning"])))
                else:
                    status_item.setForeground(QBrush(QColor(COLORS["error"])))

                status_item.setToolTip(status.detail)

                has_backup = self._paz_manager.has_backup(patch)
                bak_item = table.item(row, 3)
                if bak_item is None:
                    bak_item = QTableWidgetItem()
                    table.setItem(row, 3, bak_item)
                bak_item.setText("Yes" if has_backup else "No")
                if has_backup:
                    bak_item.setForeground(QBrush(QColor(COLORS["success"])))
                else:
                    bak_item.setForeground(QBrush(QColor(COLORS["text_dim"])))

            except Exception as e:
                log.warning("Status check failed for %s: %s", patch.name, e)
                status_item = table.item(row, 1)
                if status_item:
                    status_item.setText("Error")
                    status_item.setForeground(QBrush(QColor(COLORS["error"])))
                    status_item.setToolTip(str(e))

        self._paz_status_label.setText("Status check complete.")

    def _set_game_path(self, path: str) -> None:
        self._config["game_install_path"] = path
        self._save_config()
        if hasattr(self, '_paz_game_path'):
            self._paz_game_path.setText(path)
        if hasattr(self, '_paz_manager'):
            self._paz_manager.game_path = path
        if hasattr(self, '_global_game_path'):
            self._global_game_path.setText(path)
            self._global_game_path.setToolTip(path)
        if hasattr(self, '_gd_editor'):
            self._gd_editor = None
        if hasattr(self, '_store_parser_v2'):
            self._store_parser_v2 = None
        self._cmod_loader = None
        self._asi_manager = None
        if hasattr(self, '_cmod_refresh'):
            self._cmod_refresh()
        if hasattr(self, '_asi_refresh'):
            self._asi_refresh()
        if hasattr(self, '_paz_refresh_status'):
            self._paz_refresh_status()

    def _validate_game_path(self, path: str) -> bool:
        paz = os.path.join(path, "0008", "0.paz")
        paz_bak = os.path.join(path, "0008", "0.paz.sebak")
        if os.path.isfile(paz) or os.path.isfile(paz_bak):
            return True
        return False

    def _toggle_global_info(self, checked):
        self._center_status.setVisible(not checked)
        for w in self._global_info_widget.findChildren(QWidget):
            if w is not self._global_hide_btn:
                w.setVisible(not checked)
        self._global_hide_btn.setText("+" if checked else "X")

    def _global_browse_game_path(self) -> None:
        current = self._config.get("game_install_path", "")
        path = QFileDialog.getExistingDirectory(
            self, "Select Crimson Desert Install Folder",
            current or "C:\\"
        )
        if not path:
            return
        if not self._validate_game_path(path):
            QMessageBox.warning(
                self, "Invalid Path",
                f"Could not find game files in:\n{path}\n\n"
                f"Expected: 0008/0.paz\n\n"
                f"Select the Crimson Desert root folder\n"
                f"(the one containing 0008/, meta/, bin64/)."
            )
            return
        self._set_game_path(path)

    def _global_auto_detect_path(self) -> None:
        detected = PazPatchManager.find_game_path()
        if detected:
            self._set_game_path(detected)
        else:
            QMessageBox.warning(self, "Not Found",
                "Could not auto-detect Crimson Desert.\n"
                "Use Browse to set the path manually.")

    def _paz_browse_game_path(self) -> None:
        current = self._paz_game_path.text().strip() or self._config.get("game_install_path", "")
        path = QFileDialog.getExistingDirectory(
            self, "Select Crimson Desert Install Folder",
            current or "C:\\"
        )
        if path:
            if not self._validate_game_path(path):
                QMessageBox.warning(
                    self, "Invalid Path",
                    f"Could not find game files in:\n{path}\n\n"
                    f"Expected: 0008/0.paz or 0008/0.paz.sebak\n\n"
                    f"Make sure you selected the Crimson Desert root folder."
                )
                return
            self._set_game_path(path)

    def _paz_auto_detect_path(self) -> None:
        detected = PazPatchManager.find_game_path()
        if detected:
            self._set_game_path(detected)
            self._paz_status_label.setText(f"Game found at: {detected}")
        else:
            self._paz_status_label.setText(
                "Could not auto-detect game installation. Use Browse to set the path manually."
            )

    def _paz_get_selected_patch(self) -> Optional[PazPatch]:
        rows = self._paz_patch_table.selectionModel().selectedRows()
        if not rows:
            QMessageBox.information(self, "No Selection", "Select a patch from the table first.")
            return None
        row = rows[0].row()
        if 0 <= row < len(self._paz_patches):
            return self._paz_patches[row]
        return None

    def _paz_apply_selected(self) -> None:
        if not self._paz_manager.game_path:
            QMessageBox.warning(self, "No Game Path",
                                "Set the game install path first (Auto-Detect or Browse).")
            return

        patch = self._paz_get_selected_patch()
        if not patch:
            return

        reply = QMessageBox.question(
            self, "Apply Patch",
            f"Apply '{patch.name}'?\n\n"
            f"{patch.description}\n\n"
            f"A backup will be created automatically if one doesn't exist.\n"
            f"You can restore the original file at any time.",
            QMessageBox.Yes | QMessageBox.No,
            QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        self._paz_status_label.setText(f"Applying '{patch.name}'...")
        QApplication.processEvents()

        if patch.name == "Mount Death Respawn (1s)":
            ok, msg = self._paz_apply_mount_cooldown()
        else:
            ok, msg = self._paz_manager.apply_patch(patch)

        if ok:
            self._paz_status_label.setText(f"Success: {msg}")
            QMessageBox.information(self, "Patch Applied", msg)
        else:
            self._paz_status_label.setText(f"Failed: {msg}")
            QMessageBox.critical(self, "Patch Failed", msg)

        self._paz_refresh_status()

    def _paz_apply_mount_cooldown(self) -> Tuple[bool, str]:
        game_path = self._paz_manager.game_path
        if not game_path:
            return False, "No game path set."

        try:
            self._vehicle_patcher = VehiclePatcher(game_path)
            ok, msg = self._vehicle_patcher.apply_no_cooldown(cooldown_value=1)
            if ok:
                self._config["patch_mount_cooldown_applied"] = True
                self._save_config()
            return ok, msg
        except Exception as e:
            log.exception("Mount cooldown patch failed")
            return False, f"Mount cooldown patch failed: {e}"

    def _paz_restore_selected(self) -> None:
        if not self._paz_manager.game_path:
            QMessageBox.warning(self, "No Game Path",
                                "Set the game install path first.")
            return

        patch = self._paz_get_selected_patch()
        if not patch:
            return

        if not self._paz_manager.has_backup(patch):
            QMessageBox.information(self, "No Backup",
                                    f"No backup exists for {patch.paz_file}.")
            return

        reply = QMessageBox.question(
            self, "Restore Backup",
            f"Restore {patch.paz_file} from backup?\n\n"
            f"This will overwrite the current PAZ file with the backup copy, "
            f"removing all patches applied to that file.",
            QMessageBox.Yes | QMessageBox.No,
            QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        self._paz_status_label.setText("Restoring from backup...")
        QApplication.processEvents()

        ok, msg = self._paz_manager.restore_backup(patch)

        if ok:
            if patch.name == "Mount Death Respawn (1s)":
                self._config.pop("patch_mount_cooldown_applied", None)
                self._save_config()
            self._paz_status_label.setText(f"Restored: {msg}")
            QMessageBox.information(self, "Backup Restored", msg)
        else:
            self._paz_status_label.setText(f"Restore failed: {msg}")
            QMessageBox.critical(self, "Restore Failed", msg)

        self._paz_refresh_status()

    def _paz_restore_all(self) -> None:
        if not self._paz_manager.game_path:
            QMessageBox.warning(self, "No Game Path",
                                "Set the game install path first.")
            return

        reply = QMessageBox.question(
            self, "Restore All Backups",
            "Restore ALL PAZ files from their backups?\n\n"
            "This will remove all patches and return game files to their "
            "original state.",
            QMessageBox.Yes | QMessageBox.No,
            QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        self._paz_status_label.setText("Restoring all backups...")
        QApplication.processEvents()

        ok, msg = self._paz_manager.restore_all_backups()

        if ok:
            self._config.pop("patch_mount_cooldown_applied", None)
            self._save_config()
            self._paz_status_label.setText(msg)
            QMessageBox.information(self, "Restore Complete", msg)
        else:
            self._paz_status_label.setText(msg)
            QMessageBox.warning(self, "Restore Result", msg)

        self._paz_refresh_status()

    def _paz_expand_storage(self) -> None:
        game_path = self._paz_game_path.text().strip()
        if not game_path:
            QMessageBox.warning(self, "No Game Path", "Set the game install path first.")
            return

        if not self._is_admin():
            QMessageBox.warning(self, "Admin Required",
                                "Writing to game files requires administrator privileges.\n\n"
                                "Right-click → Run as administrator")
            return

        reply = QMessageBox.question(
            self, "Expand Storage",
            "Expand all warehouse, bank, and camp storage to 700 slots?\n\n"
            "Targets: CampWareHouse, WareHouse, Bank, Recovery, Kuku\n"
            "Player inventory is NOT modified (avoids loot bugs).\n\n"
            "A backup will be created automatically.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        self._storage_status.setText("Patching storage...")
        QApplication.processEvents()

        try:
            sp = StoragePatcher(game_path)
            ok, msg = sp.apply(target_slots=700)
            self._storage_status.setText(msg.split('\n')[0] if ok else f"Failed: {msg}")
            if ok:
                QMessageBox.information(self, "Storage Expanded", msg)
            else:
                QMessageBox.critical(self, "Failed", msg)
        except Exception as e:
            self._storage_status.setText(f"Error: {e}")
            QMessageBox.critical(self, "Error", str(e))

    def _paz_check_storage(self) -> None:
        game_path = self._paz_game_path.text().strip()
        if not game_path:
            QMessageBox.warning(self, "No Game Path", "Set the game install path first.")
