    def _build_status_bar(self) -> None:
        self._status = self.statusBar()
        self._status_file_label = QLabel("No file loaded")
        self._status_items_label = QLabel("Items: 0")
        self._status_parc_label = QLabel("")
        self._status_parc_label.setStyleSheet(f"color: {COLORS['text_dim']}; padding: 0 8px;")
        self._status_action_label = QLabel("")

        self._status.addWidget(self._status_file_label, 2)
        self._status.addWidget(self._status_items_label, 1)
        self._status.addWidget(self._status_parc_label, 1)
        self._status.addPermanentWidget(self._status_action_label)

        discord_btn = QPushButton()
        discord_btn.setToolTip("Join the Crimson Desert Modding Discord")
        discord_btn.setCursor(Qt.PointingHandCursor)
        discord_btn.setFlat(True)
        discord_btn.setFixedSize(26, 26)
        try:
            _dc_path = os.path.join(
                getattr(sys, '_MEIPASS', os.path.dirname(__file__)), "icons", "discord.png"
            )
            if os.path.isfile(_dc_path):
                discord_btn.setIcon(QIcon(_dc_path))
                discord_btn.setIconSize(QSize(20, 20))
        except Exception:
            discord_btn.setText("DC")
        discord_btn.clicked.connect(lambda: __import__('PySide6.QtGui', fromlist=['QDesktopServices']).QDesktopServices.openUrl(
            __import__('PySide6.QtCore', fromlist=['QUrl']).QUrl("https://discord.gg/6wxX5xPS")
        ))
        self._status.addPermanentWidget(discord_btn)

    def _update_status(self, action: str = "") -> None:
        if self._loaded_path:
            name = os.path.basename(self._loaded_path)
            dirty_mark = " *" if self._dirty else ""
            self._status_file_label.setText(f"File: {name}{dirty_mark}")
        else:
            self._status_file_label.setText("No file loaded")

        self._status_items_label.setText(f"Items: {len(self._items)}")

        if action:
            self._status_action_label.setText(action)
            if hasattr(self, '_center_status'):
                self._center_status.setText(action)


    def _open_save_file(self) -> None:
        path, _ = QFileDialog.getOpenFileName(
            self, "Open Save File", "",
            "Save Files (*.save);;All Files (*)"
        )
        if not path:
            return
        self._load_save(path)

    def _open_raw_stream(self) -> None:
        path, _ = QFileDialog.getOpenFileName(
            self, "Open Raw Stream", "",
            "Binary Files (*.bin);;All Files (*)"
        )
        if not path:
            return
        try:
            self._save_data = load_raw_stream(path)
            self._loaded_path = path
            self._dirty = False
            self._undo_stack.clear()
            self._scan_and_populate()
            self._update_status(f"Loaded raw stream: {os.path.basename(path)}")
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to load raw stream:\n{e}")

    def _auto_find_save(self) -> None:
        saves = find_save_files()
        if not saves:
            QMessageBox.information(
                self, "Auto-Find",
                "No save files found in known locations.\n\n"
                "Searched:\n"
                "  %LOCALAPPDATA%/Pearl Abyss/CD/save/\n"
                "  %LOCALAPPDATA%/Pearl Abyss/CD_Epic/save/"
            )
            return

        dialog = QDialog(self)
        dialog.setWindowTitle("Select Save File")
        dialog.resize(700, 400)
        dlg_layout = QVBoxLayout(dialog)

        dlg_layout.addWidget(QLabel("Found save files:"))

        list_widget = QListWidget()
        for s in saves:
            list_widget.addItem(s["display"])
        dlg_layout.addWidget(list_widget, 1)

        buttons = QDialogButtonBox(
            QDialogButtonBox.Ok | QDialogButtonBox.Cancel
        )
        buttons.accepted.connect(dialog.accept)
        buttons.rejected.connect(dialog.reject)
        dlg_layout.addWidget(buttons)

        list_widget.setCurrentRow(0)

        if dialog.exec() == QDialog.Accepted and list_widget.currentRow() >= 0:
            idx = list_widget.currentRow()
            self._load_save(saves[idx]["path"])

    def _load_save(self, path: str) -> None:
        from PySide6.QtWidgets import QProgressDialog
        progress = QProgressDialog("Loading save file...", None, 0, 5, self)
        progress.setWindowTitle("Loading")
        progress.setMinimumDuration(0)
        progress.setWindowModality(Qt.WindowModal)
        progress.setValue(0)
        QApplication.processEvents()

        def _step(msg, val):
            progress.setLabelText(msg)
            progress.setValue(val)
            if hasattr(self, '_center_status'):
                self._center_status.setText(msg)
            QApplication.processEvents()

        try:
            _step("Decrypting save file...", 1)
            self._save_data = load_save_file(path)
            self._loaded_path = path
            self._dirty = False
            self._undo_stack.clear()

            _step("Creating backup...", 2)
            pristine = self._create_pristine_backup(path)
            if pristine:
                log.info("Pristine backup created: %s", pristine)

            _step("Scanning items...", 3)
            self._scan_and_populate()

            _step("Populating UI...", 4)

            slot_dir = os.path.basename(os.path.dirname(path))
            friendly = self._friendly_slot_name(slot_dir)
            self._config["last_save_path"] = path
            self._config["last_slot"] = friendly
            self._save_config()
            self._refresh_sidebar()

            self._quick_save_btn.setEnabled(True)
            self._quick_save_btn.setToolTip(f"Save to: {path}")

            self.setWindowTitle(f"Crimson Desert Save Editor — {friendly}")
            self._update_status(f"Loaded: {friendly} ({slot_dir})")

            progress.setValue(5)
        except Warning as w:
            self._update_status(f"Loaded (HMAC warning): {os.path.basename(path)}")
            progress.close()
        except Exception as e:
            progress.close()
            err_msg = str(e)
            hint = ""
            if "byte must be in range" in err_msg or "chacha20" in traceback.format_exc().lower():
                hint = (
                    "\n\nThis file appears to be corrupted or is not a valid save file.\n"
                    "If this is a backup, it may have been created from an already-broken save.\n"
                    "Try loading a different save or restoring from an earlier backup."
                )
            QMessageBox.critical(
                self, "Error",
                f"Failed to load save file:\n\n{e}{hint}\n\n{traceback.format_exc()}"
            )

    def _save_file(self) -> None:
        if not self._save_data or not self._loaded_path:
            QMessageBox.warning(self, "Save", "No file loaded.")
            return
        if self._save_data.is_raw_stream:
            QMessageBox.warning(
                self, "Save",
                "Cannot save as .save from a raw stream.\nUse 'Save As' to choose a .save path."
            )
            return
        self._do_save(self._loaded_path)

    def _save_file_as(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Save As", "No file loaded.")
            return
        path, _ = QFileDialog.getSaveFileName(
            self, "Save As", "",
            "Save Files (*.save);;All Files (*)"
        )
        if not path:
            return
        self._do_save(path)

    def _do_save(self, path: str) -> None:
        try:
            reply = QMessageBox.question(
                self, "Backup Save?",
                "Create a backup of your current save before writing changes?\n\n"
                "Highly recommended — you can restore from Backup/Restore tab if anything goes wrong.",
                QMessageBox.Yes | QMessageBox.No | QMessageBox.Cancel,
                QMessageBox.Yes,
            )
            if reply == QMessageBox.Cancel:
                return
            if reply == QMessageBox.Yes:
                backup_path = self._create_backup(path)
                if backup_path:
                    self._update_status(f"Backup created: {os.path.basename(backup_path)}")

            write_save_file(
                path,
                bytes(self._save_data.decompressed_blob),
                self._save_data.raw_header if self._save_data.raw_header else None,
            )
            self._loaded_path = path
            self._dirty = False

            slot_dir = os.path.basename(os.path.dirname(path))
            friendly = self._friendly_slot_name(slot_dir)
            self._config["last_save_path"] = path
            self._config["last_slot"] = friendly
            self._save_config()

            self._update_status(f"Saved: {friendly} ({slot_dir})")
            self._refresh_backups()
            self._refresh_sidebar()
            QMessageBox.warning(
                self, "Save",
                f"Save file written successfully.\n{path}\n\n"
                "WARNING: It is recommended to save again in game after loading\n"
                "the changes to have a new clean save to work with, before\n"
                "applying another change."
            )
        except Exception as e:
            QMessageBox.critical(
                self, "Save Error",
                f"Failed to save:\n\n{e}\n\n{traceback.format_exc()}"
            )


    def _fix_duplicate_item_nos(self) -> None:
        if not self._items or not self._save_data:
            return

        from collections import Counter
        no_counts = Counter(it.item_no for it in self._items)
        duplicated_nos = {no for no, count in no_counts.items() if count > 1}

        if not duplicated_nos:
            return

        max_no = get_max_itemno(self._items)
        next_no = max_no + 1
        fixed = 0

        for dup_no in duplicated_nos:
            sharing = [it for it in self._items if it.item_no == dup_no]
            for item in sharing[1:]:
                apply_itemno_edit(
                    self._save_data.decompressed_blob, item, next_no
                )
                next_no += 1
                fixed += 1

        if fixed > 0:
            self._dirty = True
            self._update_status(
                f"Fixed {fixed} duplicate ItemNo(s) across "
                f"{len(duplicated_nos)} group(s) — each item now has a unique ID."
            )

    def _scan_and_populate(self) -> None:
        if not self._save_data:
            return

        self._quest_entries = []
        self._mission_entries = []
        self._items = scan_items(self._save_data.decompressed_blob)

        for item in self._items:
            item.name = self._name_db.get_name(item.item_key)
            item.category = self._name_db.get_category(item.item_key)

        self._fix_duplicate_item_nos()

        self._status_parc_label.setText("Loading... (PARC enriching in background)")
        self._status_parc_label.setStyleSheet(f"color: {COLORS['warning']}; padding: 0 8px;")
        self._populate_inventory()
        self._populate_equipment()
        self._populate_socket_items()

        from PySide6.QtCore import QTimer
        QTimer.singleShot(100, self._deferred_parc_enrich)

    def _deferred_parc_enrich(self) -> None:
        if not self._save_data or not self._items:
            return

        try:
            enriched, parc_status = enrich_items_with_parc(
                self._save_data.decompressed_blob, self._items
            )
            self._parc_status = parc_status
            if enriched > 0:
                self._status_parc_label.setText(parc_status)
                self._status_parc_label.setStyleSheet(f"color: {COLORS['success']}; padding: 0 8px;")
            else:
                self._status_parc_label.setText("Legacy mode: pattern-based scanning")
                self._status_parc_label.setStyleSheet(f"color: {COLORS['text_dim']}; padding: 0 8px;")
        except Exception:
            self._parc_status = "Legacy mode: pattern-based scanning"
            self._status_parc_label.setText(self._parc_status)
            self._status_parc_label.setStyleSheet(f"color: {COLORS['text_dim']}; padding: 0 8px;")

        self._enrich_vendor_names()
        self._update_inv_subtab_counts()

        self._populate_inventory()
        self._populate_equipment()
        self._populate_repurchase()
        self._populate_socket_items()
        self._populate_repurchase()
        self._populate_faction_tab()
        self._refresh_backups()
        self._inv_count_label.setText(str(len(self._items)))


    def _populate_inventory(self) -> None:
        table = self._inv_table
        table.setSortingEnabled(False)
        table.setRowCount(0)

        search = self._inv_search.text().lower().strip()

        filtered = self._items
        subtab_idx = self._inv_subtabs.currentIndex() if hasattr(self, '_inv_subtabs') else 0
        if 0 <= subtab_idx < len(self._inv_subtab_filters):
            _, filter_type, filter_val = self._inv_subtab_filters[subtab_idx]
            if filter_type == "source":
                filtered = [i for i in filtered if i.source == filter_val]
            elif filter_type == "bag":
                filtered = [i for i in filtered if i.bag == filter_val]
            elif filter_type == "source_vendor":
                known = {"Equipment", "Inventory", "Mercenary"}
                filtered = [i for i in filtered if i.source not in known]
            elif filter_type == "source_other":
                filtered = [i for i in filtered if i.source == "Inventory" and not i.bag]
        if search:
            filtered = [
                i for i in filtered
                if search in i.name.lower()
                or search in str(i.item_key)
                or search in i.category.lower()
                or search in self._name_db.get_internal_name(i.item_key).lower()
            ]

        table.setRowCount(len(filtered))

        for row, item in enumerate(filtered):
            color = QColor(CATEGORY_COLORS.get(item.category, COLORS["text"]))

            icon_item = QTableWidgetItem()
            if self._icons_enabled:
                px = self._icon_cache.get_pixmap(item.item_key)
                if px:
                    icon_item.setIcon(QIcon(px))
                elif self._icon_cache.has_icon(item.item_key):
                    self._icon_cache.request_icon(item.item_key, self._on_icon_loaded)
            table.setItem(row, 0, icon_item)

            name_item = QTableWidgetItem(item.name)
            name_item.setForeground(QBrush(color))
            name_item.setData(Qt.UserRole, id(item))
            table.setItem(row, 1, name_item)

            no_item = _num_item(item.item_no)
            no_item.setForeground(QBrush(QColor(COLORS["text_dim"])))
            table.setItem(row, 2, no_item)

            source_item = QTableWidgetItem(item.source)
            table.setItem(row, 3, source_item)

            cat_item = QTableWidgetItem(item.category)
            cat_item.setForeground(QBrush(color))
            table.setItem(row, 4, cat_item)

            key_item = _num_item(item.item_key)
            key_item.setData(Qt.UserRole + 1, item.item_key)
            table.setItem(row, 5, key_item)

            slot_item = _num_item(item.slot_no)
            table.setItem(row, 6, slot_item)

            stack_item = _num_item(item.stack_count)
            table.setItem(row, 7, stack_item)

            enc_text = f"+{item.enchant_level}" if item.has_enchant else "-"
            enc_item = QTableWidgetItem(enc_text)
            if item.has_enchant:
                enc_item.setForeground(QBrush(QColor(COLORS["success"])))
            table.setItem(row, 8, enc_item)

        table.setSortingEnabled(True)

    def _filter_equipment(self) -> None:
        self._populate_equipment()

    def _populate_equipment(self) -> None:
        table = self._equip_table
        table.setSortingEnabled(False)
        table.setRowCount(0)

        search = self._equip_search.text().lower().strip()
        equip_items = [i for i in self._items if i.is_equipment or i.has_enchant]
        if search:
            equip_items = [
                i for i in equip_items
                if search in i.name.lower()
                or search in str(i.item_key)
                or search in i.category.lower()
                or search in self._name_db.get_internal_name(i.item_key).lower()
            ]
        table.setRowCount(len(equip_items))

        for row, item in enumerate(equip_items):
            color = QColor(CATEGORY_COLORS.get("Equipment", COLORS["text"]))

            icon_item = QTableWidgetItem()
            if self._icons_enabled:
                px = self._icon_cache.get_pixmap(item.item_key)
                if px:
                    icon_item.setIcon(QIcon(px))
            table.setItem(row, 0, icon_item)

            name_item = QTableWidgetItem(item.name)
            name_item.setForeground(QBrush(color))
            name_item.setData(Qt.UserRole, id(item))
            table.setItem(row, 1, name_item)

            table.setItem(row, 2, _num_item(item.item_key))
            table.setItem(row, 3, _num_item(item.slot_no))

            max_enc = self._get_max_enchant(item.item_key)
            if item.has_enchant:
                if max_enc >= 0:
                    enchant_text = f"+{item.enchant_level}/{max_enc}"
                else:
                    enchant_text = f"+{item.enchant_level}"
            else:
                enchant_text = "-"
            enchant_item = QTableWidgetItem(enchant_text)
            if item.has_enchant and max_enc >= 0 and item.enchant_level > max_enc:
                enchant_item.setForeground(QBrush(QColor(COLORS["error"])))
                enchant_item.setToolTip(f"OVER LIMIT! Max enchant is +{max_enc}. Game may crash!")
            elif item.has_enchant and item.enchant_level > 0:
                enchant_item.setForeground(QBrush(QColor(COLORS["accent"])))
            table.setItem(row, 4, enchant_item)

            endurance_item = _num_item(item.actual_endurance)
            if item.socket_count_from_endurance > 0:
                endurance_item.setText(f"{item.actual_endurance} ({item.socket_count_from_endurance}s)")
                endurance_item.setToolTip(f"Endurance={item.actual_endurance}, Sockets={item.socket_count_from_endurance} (raw=0x{item.endurance:04X})")
            table.setItem(row, 5, endurance_item)

            sharpness_item = _num_item(item.sharpness)
            table.setItem(row, 6, sharpness_item)

            table.setItem(row, 7, _num_item(item.stack_count))
            table.setItem(row, 8, _num_item(item.item_no))

        table.setSortingEnabled(True)

    def _toggle_icons(self) -> None:
        self._icons_enabled = not self._icons_enabled
        self._config["show_icons"] = self._icons_enabled
        self._save_config()

        btn_text = "Hide Icons" if self._icons_enabled else "Show Icons"
        row_h = max(ICON_SIZE + 2, 24) if self._icons_enabled else 24

        self._show_icons_btn.setText(btn_text)
        if hasattr(self, '_db_show_icons_btn'):
            self._db_show_icons_btn.setText(btn_text)
        if hasattr(self, '_global_icons_btn'):
            self._global_icons_btn.setText(btn_text)

        if self._icons_enabled and self._icon_cache.coverage < 100:
            reply = QMessageBox.question(
                self, "Download Icons",
                f"Only {self._icon_cache.coverage} icons cached locally.\n"
                f"Download all 6,000+ item icons + mount portraits from GitHub?\n\n"
                f"This requires internet (first time only, ~70 MB).\n"
                f"Already downloaded icons will be skipped.",
                QMessageBox.Yes | QMessageBox.No, QMessageBox.Yes,
            )
            if reply == QMessageBox.Yes:
                self._bulk_download_icons()

        for tbl in [self._inv_table, self._equip_table, self._repurch_table, self._db_table, self._swap_list, self._merc_table]:
            tbl.setColumnWidth(0, (ICON_SIZE + 16) if self._icons_enabled else 0)
            tbl.verticalHeader().setDefaultSectionSize(row_h)

        self._populate_inventory()
        self._populate_equipment()
        self._populate_repurchase()
        self._filter_database()
        self._merc_refresh()

    def _bulk_download_icons(self) -> None:
        self._update_status("Downloading icons from GitHub...")
        QApplication.processEvents()

        def _progress(folder, downloaded, skipped, errors, total):
            self._update_status(
                f"Icons [{folder}]: {downloaded} downloaded, {skipped} cached, "
                f"{errors} failed ({total} total)")
            QApplication.processEvents()

        import threading
        def _do_download():
            stats = self._icon_cache.bulk_download_all(progress_callback=_progress)
            from PySide6.QtCore import QMetaObject, Qt as _Qt
            self._update_status(
                f"Icons: {stats['downloaded']} downloaded, {stats['skipped']} cached, "
                f"{stats['errors']} failed")

        thread = threading.Thread(target=_do_download, daemon=True)
        thread.start()
        self._populate_swap_list(
            self._swap_search.text().strip() if hasattr(self, '_swap_search') else "",
            self._swap_category.currentText() if hasattr(self, '_swap_category') else "All",
        )

    def _on_icon_loaded(self, item_key: int, pixmap) -> None:
        self._icon_ready.emit(item_key)

    def _apply_icon_to_table(self, item_key: int) -> None:
        px = self._icon_cache.get_pixmap(item_key)
        if not px:
            return
        icon = QIcon(px)
        for row in range(self._inv_table.rowCount()):
            w = self._inv_table.item(row, 0)
            if w is not None and not w.icon().isNull():
                continue
            key_w = self._inv_table.item(row, 5)
            if key_w and key_w.text() == str(item_key):
                w = self._inv_table.item(row, 0)
                if w:
                    w.setIcon(icon)

    def _filter_inventory(self) -> None:
        self._populate_inventory()

    def _on_inv_subtab_changed(self, index: int) -> None:
        self._populate_inventory()

    def _update_inv_subtab_counts(self) -> None:
        if not hasattr(self, '_inv_subtabs') or not self._items:
            return
        known_sources = {"Equipment", "Inventory", "Mercenary"}
        for idx, (label, filter_type, filter_val) in enumerate(self._inv_subtab_filters):
            if filter_type is None:
                count = len(self._items)
            elif filter_type == "source":
                count = sum(1 for i in self._items if i.source == filter_val)
            elif filter_type == "bag":
                count = sum(1 for i in self._items if i.bag == filter_val)
            elif filter_type == "source_vendor":
                count = sum(1 for i in self._items if i.source not in known_sources)
            elif filter_type == "source_other":
                count = sum(1 for i in self._items if i.source == "Inventory" and not i.bag)
            else:
                count = 0
            self._inv_subtabs.setTabText(idx, f"{label} ({count})" if count else label)

    def _get_selected_items(self, table: QTableWidget) -> List[SaveItem]:
        rows = set(idx.row() for idx in table.selectedIndexes())
        result = []
        for row in sorted(rows):
            item_id = None
            for col in range(table.columnCount()):
                w = table.item(row, col)
                if w is not None:
                    d = w.data(Qt.UserRole)
                    if d is not None:
                        item_id = d
                        break
            if item_id is None:
                continue
            for item in self._items:
                if id(item) == item_id:
                    result.append(item)
                    break
        return result

    def _clone_vendor_item(self) -> None:
        try:
            if not self._save_data:
                QMessageBox.warning(self, "Clone Item", "No save loaded.")
                return
            if insert_item_to_store is None:
                QMessageBox.critical(self, "Clone Item", "PARC inserter not available.")
                return

            selected = self._get_repurch_selected()
            if not selected:
                QMessageBox.information(self, "Clone Item",
                    "Select an item from the repurchase list first.\n"
                    "This item will be used as the donor template.")
                return

            donor = selected[0]
            donor_name = donor.name
            donor_cat = self._name_db.get_category(donor.item_key)

            dlg = ItemSearchDialog(
                self._name_db,
                title=f"Clone to Vendor — Pick Target Item",
                prompt=(
                    f"Donor: {donor_name} (category: {donor_cat})\n\n"
                    f"IMPORTANT: Swap must be type-for-type!\n"
                    f"Glove -> Glove, Helm -> Helm, Sword -> Sword.\n"
                    f"Cross-type swaps will be unequippable.\n\n"
                    f"Search for the item you want:"
                ),
                parent=self,
            )
            if dlg.exec() != QDialog.Accepted or dlg.selected_key == 0:
                return

            key = dlg.selected_key
            stack = 1

            target_name = dlg.selected_name or self._name_db.get_name(key)
            reply = QMessageBox.question(
                self, "Clone to Vendor",
                f"Clone '{donor_name}' as '{target_name}' (key={key})?\n\n"
                f"It will appear in the vendor's buyback list.\n"
                f"Buy it back in-game — the game creates the correct item.",
                QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
            )
            if reply != QMessageBox.Yes:
                return

            self._update_status(f"Cloning {donor_name} -> {target_name}...")
            QApplication.processEvents()

            blob = bytearray(self._save_data.decompressed_blob)
            ok_ins, new_blob, msg = insert_item_to_store(
                blob, item_key=key, stack_count=stack,
            )
            if ok_ins:
                self._save_data.decompressed_blob = bytearray(new_blob)
                self._dirty = True
                self._populate_repurchase()
                self._update_status(f"Cloned: {target_name} x{stack}")
                QMessageBox.information(self, "Item Cloned",
                    f"Added {target_name} x{stack} to vendor buyback.\n\n{msg}\n\n"
                    f"Save (Ctrl+S), reload in-game (may require 2 reloads but not usually),\n"
                    f"go to the vendor and buy it back.")
            else:
                self._update_status(f"Clone failed: {msg}")
                QMessageBox.critical(self, "Clone Failed", msg)
        except Exception as e:
            import traceback; traceback.print_exc()
            QMessageBox.critical(self, "Clone Error", str(e))

    def _parc_add_to_vendor(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "PARC Vendor Insert", "No save loaded.")
            return
        if insert_item_to_store is None:
            QMessageBox.critical(self, "Vendor Insert", "PARC inserter module failed to load.")
            return

        dlg = ItemSearchDialog(
            self._name_db,
            title="Add New Item to Vendor",
            prompt=(
                "Search for the item to add to vendor buyback.\n"
                "You must have sold at least 1 item to a vendor first.\n"
                "Buy it back in-game after saving."
            ),
            parent=self,
            template_only=True,
        )
        if dlg.exec() != QDialog.Accepted or dlg.selected_key == 0:
            return

        key = dlg.selected_key
        from PySide6.QtWidgets import QInputDialog
        stack, ok2 = QInputDialog.getInt(
            self, "Vendor Insert — Stack Count",
            f"How many {dlg.selected_name}?",
            1, 1, 99999,
        )
        if not ok2:
            return

        name = dlg.selected_name or self._name_db.get_name(key)
        reply = QMessageBox.question(
            self, "PARC Vendor Insert",
            f"Insert {name} (key={key}) x{stack} into vendor buyback?\n\n"
            f"May require 2 reloads but not usually. Buy it back from the vendor in-game.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        self._update_status("Inserting to vendor via PARC...")
        QApplication.processEvents()

        try:
            blob = bytearray(self._save_data.decompressed_blob)
            ok, new_blob, msg = insert_item_to_store(
                blob, item_key=key, stack_count=stack,
            )
            if ok:
                self._save_data.decompressed_blob = bytearray(new_blob)
                self._dirty = True
                self._populate_repurchase()
                self._update_status(f"PARC Vendor Insert: {name} x{stack} — {msg}")
                QMessageBox.information(self, "Vendor Item Added",
                    f"Added {name} x{stack} to vendor buyback.\n\n{msg}\n\n"
                    f"Save (Ctrl+S), reload in-game (2x), check vendor buyback.")
            else:
                self._update_status(f"PARC Vendor Insert failed: {msg}")
                QMessageBox.critical(self, "Insert Failed", msg)
        except Exception as e:
            self._update_status(f"PARC Vendor Insert error: {e}")
            QMessageBox.critical(self, "Insert Error", str(e))


    def _tree_insert_item(self, item_key: int, stack_count: int) -> tuple[bool, str]:
        import sys, os, copy
        _de = os.path.join(os.path.dirname(os.path.abspath(__file__)),
                           'Communitydump', 'desktopeditor')
        if _de not in sys.path:
            sys.path.insert(0, _de)

        from save_parser import parse_schema, parse_toc, decode_object_blocks
        from parc_tree_serializer import serialize_object_block
        from parc_tree_ops import clone_element, build_item_element
        from parc_serializer import parse_parc_blob, replace_block_raw, serialize_parc

        raw_blob = bytes(self._save_data.decompressed_blob)

        schema = parse_schema(raw_blob)
        type_names = [t.name for t in schema['types']]
        toc = parse_toc(raw_blob, schema['schema_end'], type_names)
        blocks = decode_object_blocks(raw_blob, toc['entries'], schema['types'])
        schema_types = {t.index: t for t in schema['types']}

        parc = parse_parc_blob(raw_blob)

        inv_block = None
        inv_toc_idx = -1
        for i, b in enumerate(blocks):
            if b.class_name == 'InventorySaveData':
                inv_block = b
                inv_toc_idx = b.entry_index
                break
        if inv_block is None:
            return False, "No InventorySaveData block found in save"

        inv_list_field = None
        item_list_field = None
        target_inv_idx = 0

        for f in inv_block.fields:
            if f.name == '_inventorylist' and f.list_elements:
                inv_list_field = f
                break

        if inv_list_field is None:
            return False, "No _inventorylist found in InventorySaveData"

        for elem in inv_list_field.list_elements:
            if not elem.child_fields:
                continue
            for cf in elem.child_fields:
                if cf.name == '_itemList' and cf.list_elements and len(cf.list_elements) > 0:
                    item_list_field = cf
                    target_inv_idx = elem.field_index
                    break
            if item_list_field is not None:
                break

        if item_list_field is None:
            return False, "No _itemList with existing items found in inventory"

        target_limits = self._buff_item_limits.get(str(item_key), {}) if hasattr(self, '_buff_item_limits') else {}
        target_slot_type = target_limits.get('slotType', -1)
        is_equipment = target_slot_type not in (65535, -1)

        max_item_no = 0
        for it in item_list_field.list_elements:
            if it.child_fields:
                for cf in it.child_fields:
                    if cf.name == '_itemNo' and cf.present:
                        try:
                            v = int(cf.value_repr)
                            if v > max_item_no:
                                max_item_no = v
                        except (ValueError, TypeError):
                            pass
        new_item_no = max_item_no + 1

        item_type_idx = 17
        for t in schema['types']:
            if t.name == 'ItemSaveData':
                item_type_idx = t.index
                break

        cloned = build_item_element(
            item_key=item_key,
            item_no=new_item_no,
            stack_count=stack_count,
            slot_no=len(item_list_field.list_elements),
            is_equipment=is_equipment,
            type_index=item_type_idx,
        )

        log.info("Tree insert: building item key=%d (equipment=%s) itemNo=%d type_idx=%d",
                 item_key, is_equipment, new_item_no, item_type_idx)

        cloned.field_index = len(item_list_field.list_elements)
        cloned.name = f"[{cloned.field_index}]"
        item_list_field.list_elements.append(cloned)
        item_list_field.list_count = len(item_list_field.list_elements)
        item_list_field.note = (item_list_field.note or "") + " [modified]"

        new_block_bytes = serialize_object_block(
            inv_block, schema_types, raw_blob, inv_block.data_offset
        )

        replace_block_raw(parc, inv_toc_idx, new_block_bytes)
        new_blob = serialize_parc(parc)

        self._save_data.decompressed_blob = bytearray(new_blob)

        delta = len(new_blob) - len(raw_blob)
        return True, (
            f"Inserted item key={item_key} (itemNo={new_item_no}) x{stack_count} "
            f"into inventory[{target_inv_idx}]._itemList. "
            f"Blob: {len(raw_blob):,} → {len(new_blob):,} ({delta:+,} bytes)"
        )

    def _parc_add_item(self) -> None:
        try:
            self._parc_add_item_inner()
        except Exception as e:
            import traceback; traceback.print_exc()
            QMessageBox.critical(self, "PARC Add Item Error", f"Unexpected error:\n{e}")

    def _parc_add_item_inner(self, preset_key: int = 0, preset_stack: int = 0) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Add Item", "No save loaded.")
            return
        if insert_item_to_inventory is None:
            QMessageBox.critical(self, "Add Item",
                "PARC inserter module failed to load.\n"
                "This may be a bundled exe issue — the desktopeditor parser is missing.")
            return

        if preset_key > 0 and preset_stack > 0:
            key = preset_key
            stack = preset_stack
        else:
            dlg = ItemSearchDialog(
                self._name_db,
                title="Add New Item",
                prompt="Search for any item to add to your inventory.\n"
                       "The tree serializer clones from existing items — no templates needed.",
                parent=self,
                template_only=False,
            ) if hasattr(self, '_name_db') else None

            if dlg is None:
                from PySide6.QtWidgets import QInputDialog
                text, ok = QInputDialog.getText(self, "Add Item", "Enter item key:")
                if not ok or not text.strip():
                    return
                try:
                    key = int(text.strip())
                except ValueError:
                    QMessageBox.warning(self, "Invalid", "Enter a numeric item key.")
                    return
            else:
                if dlg.exec() != QDialog.Accepted or dlg.selected_key == 0:
                    return
                key = dlg.selected_key

            from PySide6.QtWidgets import QInputDialog
            stack, ok2 = QInputDialog.getInt(
                self, "Add Item — Stack Count",
                f"How many {self._name_db.get_name(key)}?",
                1, 1, 99999,
            )
            if not ok2:
                return

        name = self._name_db.get_name(key)
        reply = QMessageBox.question(
            self, "Add Item (Tree Serializer)",
            f"Insert {name} (key={key}) x{stack} into your inventory?\n\n"
            f"Uses the tree serializer — clones from an existing item\n"
            f"and re-serializes the inventory block with fresh offsets.\n\n"
            f"Save (Ctrl+S) after, then reload in-game.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        self._update_status("Inserting item via tree serializer...")
        QApplication.processEvents()

        try:
            ok, msg = self._tree_insert_item(key, stack)
            if ok:
                self._dirty = True
                self._scan_and_populate()
                self._update_status(f"Tree Insert: {name} x{stack} — {msg}")
                QMessageBox.information(self, "Item Added",
                    f"Added {name} x{stack} to inventory.\n\n{msg}\n\n"
                    f"Save the file (Ctrl+S), then reload in-game.")
            else:
                self._update_status(f"Insert failed: {msg}")
                QMessageBox.critical(self, "Insert Failed", msg)
        except Exception as e:
            import traceback; traceback.print_exc()
            self._update_status(f"Tree Insert error: {e}")
            QMessageBox.critical(self, "Insert Error",
                f"Tree serializer failed:\n{e}\n\n"
                f"Please report this with your save file.")

    def _set_stack(self) -> None:
        if not self._save_data:
            return
        selected = self._get_selected_items(self._inv_table)
        if not selected:
            QMessageBox.information(self, "Set Stack", "Select one or more items first.")
            return

        new_stack = self._inv_stack_input.value()
        read_only_sources = ("Mercenary",)

        edits = []
        skipped = 0
        for item in selected:
            if item.source in read_only_sources:
                skipped += 1
                continue
            old_bytes = apply_stack_edit(
                self._save_data.decompressed_blob, item, new_stack
            )
            edits.append((item.offset + 18, old_bytes, self._save_data.decompressed_blob[item.offset + 18:item.offset + 26]))

        if edits:
            undo = UndoEntry(
                description=f"Set stack to {new_stack} for {len(edits)} items",
                patches=[(off, old, new) for off, old, new in edits],
            )
            self._undo_stack.append(undo)
            self._dirty = True
            self._populate_inventory()
            self._populate_equipment()
            msg = f"Set stack to {new_stack} for {len(edits)} items."
            if skipped:
                msg += f" ({skipped} read-only items skipped)"
            self._update_status(msg)
        elif skipped:
            QMessageBox.information(
                self, "Set Stack",
                "Selected items are read-only (Store/Mercenary)."
            )

    def _split_stack_one(self) -> None:
        if not self._save_data:
            return
        selected = self._get_selected_items(self._inv_table)
        if not selected:
            QMessageBox.information(self, "Split", "Select a stacked item first.")
            return

        item = selected[0]
        if item.stack_count <= 1:
            QMessageBox.information(
                self, "Split",
                f"'{item.name}' has stack={item.stack_count}. Nothing to split.",
            )
            return

        if item.source == "Mercenary":
            QMessageBox.warning(self, "Split", "Cannot split mercenary items.")
            return

        new_stack = item.stack_count - 1
        old_stack_bytes = apply_stack_edit(
            self._save_data.decompressed_blob, item, new_stack
        )

        max_no = get_max_itemno(self._items)
        new_no = max_no + 1
        old_no_bytes = apply_itemno_edit(
            self._save_data.decompressed_blob, item, new_no
        )

        patches = [
            (item.offset + 18, old_stack_bytes,
             self._save_data.decompressed_blob[item.offset + 18:item.offset + 26]),
            (item.offset + 4, old_no_bytes,
             self._save_data.decompressed_blob[item.offset + 4:item.offset + 12]),
        ]

        self._undo_stack.append(UndoEntry(
            description=f"Split 1 from {item.name} (stack {new_stack+1}->{new_stack}, new ItemNo={new_no})",
            patches=patches,
        ))
        self._dirty = True
        self._populate_inventory()
        self._update_status(
            f"Split: {item.name} stack {new_stack+1} -> {new_stack}, "
            f"ItemNo={new_no}. Now swap the split item safely."
        )


    def _duplicate_all_equipment(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Duplicate", "No save loaded.")
            return

        equipped = [i for i in self._items if i.is_equipment or i.has_enchant]
        equipped = [i for i in equipped if i.item_key > 0 and "Mercenary" not in (i.source or "")]

        if not equipped:
            QMessageBox.information(self, "Duplicate", "No equipment items found.")
            return

        limit_active = self._dupe_limit_check.isChecked()
        if limit_active:
            max_items = self._dupe_limit_spin.value()
            if len(equipped) > max_items:
                equipped = equipped[:max_items]

        count = self._equip_stack.value()
        if count < 2:
            QMessageBox.information(self, "Duplicate", "Set the Stack value to 2 or higher first.")
            return

        limit_text = f" (limited to {len(equipped)})" if limit_active else ""
        names = [f"  {it.name}" for it in equipped[:10]]
        if len(equipped) > 10:
            names.append(f"  ... and {len(equipped) - 10} more")

        reply = QMessageBox.question(
            self, "Duplicate All Equipment",
            f"Set stack to {count} on {len(equipped)} items{limit_text}:\n\n"
            + "\n".join(names) + "\n\n"
            f"After saving:\n"
            f"1. Load the game\n"
            f"2. Unequip each item\n"
            f"3. The game will spawn {count - 1} extra copies\n"
            f"4. Come back here and swap them to whatever you want\n\n"
            f"Continue?",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        from item_scanner import apply_stack_edit
        blob = self._save_data.decompressed_blob
        edits = []
        for item in equipped:
            old = apply_stack_edit(blob, item, count)
            edits.append((item.offset + 18, old, blob[item.offset + 18:item.offset + 26]))

        self._undo_stack.append(UndoEntry(
            description=f"Duplicate all equipment: stack={count} on {len(equipped)} items",
            patches=edits,
        ))
        self._dirty = True
        self._populate_equipment()
        self._update_status(
            f"Set stack to {count} on {len(equipped)} items. "
            f"Save, load game, unequip to get copies, then swap them!"
        )

    def _delete_items(self) -> None:
        if not self._save_data:
            return
        selected = self._get_selected_items(self._inv_table)
        if not selected:
            QMessageBox.information(self, "Delete", "Select one or more items first.")
            return

        names = [f"  {self._name_db.get_name(i.item_key)} (no={i.item_no})" for i in selected[:10]]
        if len(selected) > 10:
            names.append(f"  ... +{len(selected)-10} more")

        reply = QMessageBox.warning(
            self, "Delete Items",
            f"Zero out {len(selected)} item(s)?\n\n"
            + "\n".join(names) + "\n\n"
            "This sets itemKey=0 and stack=0. The game will skip these items on load.\n"
            "You can undo this with Edit > Undo.",
            QMessageBox.Yes | QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        read_only = ("Mercenary",)
        edits = []
        skipped = 0
        for item in selected:
            if item.source in read_only:
                skipped += 1
                continue
            blob = self._save_data.decompressed_blob
            old_key = bytes(blob[item.offset + 12:item.offset + 16])
            old_stack = bytes(blob[item.offset + 18:item.offset + 26])
            struct.pack_into("<I", blob, item.offset + 12, 0)
            edits.append((item.offset + 12, old_key, bytes(blob[item.offset + 12:item.offset + 16])))
            struct.pack_into("<q", blob, item.offset + 18, 0)
            edits.append((item.offset + 18, old_stack, bytes(blob[item.offset + 18:item.offset + 26])))

        if edits:
            self._undo_stack.append(UndoEntry(
                description=f"Deleted {len(edits)//2} items (zeroed key+stack)",
                patches=edits,
            ))
            self._dirty = True
            self._scan_and_populate()
            msg = f"Deleted {len(edits)//2} items."
            if skipped:
                msg += f" ({skipped} read-only items skipped)"
            self._update_status(msg)


    def _give_item(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Give Item", "No save file loaded.")
            return

        dlg = GiveItemDialog(self._name_db, self._items, self, experimental=self._experimental_mode, icon_cache=self._icon_cache if self._icons_enabled else None)
        if dlg.exec() != QDialog.Accepted:
            return

        target_key = dlg.target_key
        target_count = dlg.target_count
        donor_item = dlg.donor_item
        target_name = self._name_db.get_name(target_key)
        donor_name = self._name_db.get_name(donor_item.item_key)

        reply = QMessageBox.question(
            self, "Confirm Give Item",
            f"This will transform:\n\n"
            f"  DONOR: {donor_name} (key={donor_item.item_key}, stack={donor_item.stack_count})\n\n"
            f"Into:\n\n"
            f"  TARGET: {target_name} (key={target_key}, stack={target_count})\n\n"
            f"The donor item will be permanently replaced.\nContinue?",
            QMessageBox.Yes | QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        patches = smart_item_swap(
            self._save_data.decompressed_blob, donor_item, target_key
        )
        old_stack_bytes = apply_stack_edit(
            self._save_data.decompressed_blob, donor_item, target_count
        )
        patches.append((
            donor_item.offset + 18,
            old_stack_bytes,
            self._save_data.decompressed_blob[donor_item.offset + 18:donor_item.offset + 26]
        ))

        self._undo_stack.append(UndoEntry(
            description=f"Give {target_name} x{target_count} (donor: {donor_name})",
            patches=patches,
        ))
        self._dirty = True
        self._populate_inventory()
        self._populate_equipment()
        self._update_status(f"Gave {target_name} x{target_count} (replaced {donor_name})")

    def _add_new_item(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Add Item", "No save file loaded.")
            return

        dlg = AddItemDialog(self._name_db, self)
        if dlg.exec() != QDialog.Accepted:
            return

        target_key = dlg.selected_key
        target_count = dlg.selected_count
        target_enchant = dlg.selected_enchant
        category_key = dlg.selected_category_key
        target_name = self._name_db.get_name(target_key)

        reply = QMessageBox.question(
            self, "Confirm Add Item",
            f"Add item directly to inventory:\n\n"
            f"  {target_name} (key={target_key})\n"
            f"  Count: {target_count}\n\n"
            f"The item will appear in your inventory on next load.\nContinue?",
            QMessageBox.Yes | QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        try:
            from parc_inserter2 import add_item_to_inventory

            blob = bytes(self._save_data.decompressed_blob)

            max_no = max((it.item_no for it in self._items), default=100)
            new_item_no = max_no + 100

            new_blob = add_item_to_inventory(
                blob,
                new_item_key=target_key,
                new_item_no=new_item_no,
                new_stack=target_count,
            )

            old_blob = bytes(self._save_data.decompressed_blob)
            self._save_data.decompressed_blob = bytearray(new_blob)

            self._undo_stack.append(UndoEntry(
                description=f"Add {target_name} x{target_count} (PARC insert)",
                patches=[],
            ))
            self._dirty = True

            self._scan_and_populate()
            self._update_status(
                f"Added {target_name} x{target_count} to inventory!"
            )
            return

        except Exception as e:
            import traceback
            traceback.print_exc()
            QMessageBox.warning(
                self, "PARC Insertion Failed",
                f"Direct insertion failed:\n{e}\n\n"
                f"Falling back to Give Item (donor swap) method.\n"
                f"You will need to pick a donor item to sacrifice.",
            )
            dlg2 = GiveItemDialog(self._name_db, self._items, self, icon_cache=self._icon_cache if self._icons_enabled else None)
            dlg2._target_search.setText(str(target_key))
            dlg2._count_spin.setValue(target_count)
            if dlg2.exec() != QDialog.Accepted:
                return
            donor_item = dlg2.donor_item
            if not donor_item:
                return
            patches = smart_item_swap(
                self._save_data.decompressed_blob, donor_item, target_key
            )
            old_stack_bytes = apply_stack_edit(
                self._save_data.decompressed_blob, donor_item, target_count
            )
            patches.append((
                donor_item.offset + 18,
                old_stack_bytes,
                self._save_data.decompressed_blob[donor_item.offset + 18:donor_item.offset + 26]
            ))
            donor_name = self._name_db.get_name(donor_item.item_key)
            self._undo_stack.append(UndoEntry(
                description=f"Add {target_name} x{target_count} (fallback via {donor_name})",
                patches=patches,
            ))
            self._dirty = True
            self._populate_inventory()
            self._populate_equipment()
            self._update_status(
                f"Added {target_name} x{target_count} via donor swap (fallback)"
            )


    def _get_max_enchant(self, item_key: int) -> int:
        rust_info = self._buff_rust_lookup.get(item_key)
        if rust_info:
            edl = rust_info.get('enchant_data_list', [])
            if edl:
                return max(ed.get('level', 0) for ed in edl)
        val = self._max_enchant_map.get(str(item_key))
        if val is not None:
            return val
        return -1

    def _set_enchant(self) -> None:
        if not self._save_data:
            return
        selected = self._get_selected_items(self._equip_table)
        if not selected:
            QMessageBox.information(self, "Set Enchant", "Select equipment items first.")
            return

        new_val = self._equip_enchant.value()

        if self._buff_rust_lookup:
            over_limit = []
            for item in selected:
                if not item.has_enchant:
                    continue
                max_enc = self._get_max_enchant(item.item_key)
                if max_enc >= 0 and new_val > max_enc:
                    name = self._name_db.get_name(item.item_key)
                    over_limit.append(f"  {name} (max +{max_enc})")
            if over_limit:
                msg = (f"The following items cannot be enchanted to +{new_val} "
                       f"(game will crash):\n\n" + "\n".join(over_limit[:10]))
                if len(over_limit) > 10:
                    msg += f"\n  ... and {len(over_limit) - 10} more"
                msg += "\n\nContinue anyway? (NOT recommended)"
                reply = QMessageBox.warning(
                    self, "Enchant Over Limit", msg,
                    QMessageBox.Yes | QMessageBox.No, QMessageBox.No)
                if reply != QMessageBox.Yes:
                    return

        edits = []
        for item in selected:
            if not item.has_enchant:
                continue
            old = apply_enchant_edit(self._save_data.decompressed_blob, item, new_val)
            edits.append((item.offset + 26, old, self._save_data.decompressed_blob[item.offset + 26:item.offset + 28]))

        if edits:
            self._undo_stack.append(UndoEntry(
                description=f"Set enchant to {new_val}",
                patches=[(o, old, new) for o, old, new in edits],
            ))
            self._dirty = True
            self._populate_equipment()
            self._populate_inventory()
            self._update_status(f"Set enchant to +{new_val} for {len(edits)} items.")

    def _set_endurance(self) -> None:
        if not self._save_data:
            return
        selected = self._get_selected_items(self._equip_table)
        if not selected:
            QMessageBox.information(self, "Set Endurance", "Select equipment items first.")
            return

        reply = QMessageBox.warning(
            self, "Set Endurance",
            "Editing endurance may crash your save on some items.\n\n"
            "Make sure you have a backup before proceeding.\n"
            "Continue?",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        new_val = self._equip_endurance.value()
        edits = []
        for item in selected:
            old = apply_endurance_edit(self._save_data.decompressed_blob, item, new_val)
            edits.append((item.offset + 30, old, self._save_data.decompressed_blob[item.offset + 30:item.offset + 32]))

        if edits:
            self._undo_stack.append(UndoEntry(
                description=f"Set endurance to {new_val}",
                patches=[(o, old, new) for o, old, new in edits],
            ))
            self._dirty = True
            self._populate_equipment()
            self._update_status(f"Set endurance to {new_val} for {len(edits)} items.")

    def _set_sharpness(self) -> None:
        if not self._save_data:
            return
        selected = self._get_selected_items(self._equip_table)
        if not selected:
            QMessageBox.information(self, "Set Sharpness", "Select equipment items first.")
            return

        reply = QMessageBox.warning(
            self, "Set Sharpness",
            "Editing sharpness may crash your save on some items.\n\n"
            "Make sure you have a backup before proceeding.\n"
            "Continue?",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        new_val = self._equip_sharpness.value()
        edits = []
        for item in selected:
            old = apply_sharpness_edit(self._save_data.decompressed_blob, item, new_val)
            edits.append((item.offset + 32, old, self._save_data.decompressed_blob[item.offset + 32:item.offset + 34]))

        if edits:
            self._undo_stack.append(UndoEntry(
                description=f"Set sharpness to {new_val}",
                patches=[(o, old, new) for o, old, new in edits],
            ))
            self._dirty = True
            self._populate_equipment()
            self._update_status(f"Set sharpness to {new_val} for {len(edits)} items.")

    def _set_equip_stack(self) -> None:
        if not self._save_data:
            return
        selected = self._get_selected_items(self._equip_table)
        if not selected:
            QMessageBox.information(self, "Set Stack", "Select equipment items first.")
            return

        new_stack = self._equip_stack.value()
        edits = []
        for item in selected:
            old = apply_stack_edit(self._save_data.decompressed_blob, item, new_stack)
            edits.append((item.offset + 18, old, self._save_data.decompressed_blob[item.offset + 18:item.offset + 26]))

        if edits:
            self._undo_stack.append(UndoEntry(
                description=f"Set equip stack to {new_stack}",
                patches=[(o, old, new) for o, old, new in edits],
            ))
            self._dirty = True
            self._populate_equipment()
            self._populate_inventory()
            self._update_status(f"Set stack to {new_stack} for {len(edits)} equipment items.")


    def _populate_swap_list(self, filter_text: str = "", category: str = "All") -> None:
        table = self._swap_list
        table.setSortingEnabled(False)
        table.setRowCount(0)

        if filter_text:
            items = self._name_db.search(filter_text)
        else:
            items = self._name_db.get_all_sorted()

        if category == "Has Template":
            try:
                from item_template_db import load_db as _load_tmpl_db
                if not hasattr(self, '_template_keys_cache'):
                    self._template_keys_cache = set(int(k) for k in _load_tmpl_db().keys())
                items = [i for i in items if i.item_key in self._template_keys_cache]
            except Exception:
                pass
        elif category and category != "All":
            items = [i for i in items if i.category == category]

        table.setRowCount(len(items))
        for row, info in enumerate(items):
            icon_item = QTableWidgetItem()
            if self._icons_enabled:
                px = self._icon_cache.get_pixmap(info.item_key)
                if px:
                    icon_item.setIcon(QIcon(px))
            table.setItem(row, 0, icon_item)
            table.setItem(row, 1, QTableWidgetItem(str(info.item_key)))
            name_item = QTableWidgetItem(info.name)
            color = QColor(CATEGORY_COLORS.get(info.category, COLORS["text"]))
            name_item.setForeground(QBrush(color))
            table.setItem(row, 2, name_item)
            table.setItem(row, 3, QTableWidgetItem(info.category))

        table.setSortingEnabled(True)

    def _filter_swap_items(self) -> None:
        text = self._swap_search.text().strip()
        cat = self._swap_category.currentText() if hasattr(self, '_swap_category') else "All"
        self._populate_swap_list(text, cat)

    def _perform_swap(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Swap", "No save file loaded.")
            return

        selected = self._get_selected_items(self._inv_table)
        if not selected:
            QMessageBox.information(
                self, "Item Swap",
                "Select an item from the Inventory tab first, then switch to this tab."
            )
            return

        item = selected[0]

        new_key = 0
        swap_rows = set(idx.row() for idx in self._swap_list.selectedIndexes())
        if swap_rows:
            row = min(swap_rows)
            key_widget = self._swap_list.item(row, 1)
            if key_widget:
                try:
                    new_key = int(key_widget.text())
                except ValueError:
                    pass

        if new_key == 0:
            new_key = self._swap_manual_key.value()

        if new_key <= 0:
            QMessageBox.warning(self, "Swap", "Select a target item or enter a manual key.")
            return

        if new_key == item.item_key:
            QMessageBox.information(self, "Swap", "Target key is same as current key.")
            return

        old_name = item.name
        new_name = self._name_db.get_name(new_key)

        consume_one = False
        if item.stack_count > 1:
            msg_box = QMessageBox(self)
            msg_box.setWindowTitle("Swap Stacked Item")
            msg_box.setText(
                f"'{old_name}' has {item.stack_count} in the stack.\n\n"
                f"Swap to '{new_name}' (key={new_key})?"
            )
            swap_one_btn = msg_box.addButton("Swap 1 (consume from stack)", QMessageBox.AcceptRole)
            swap_all_btn = msg_box.addButton(f"Swap all {item.stack_count}", QMessageBox.AcceptRole)
            msg_box.addButton(QMessageBox.Cancel)
            msg_box.exec_()
            clicked = msg_box.clickedButton()
            if clicked == swap_one_btn:
                consume_one = True
            elif clicked == swap_all_btn:
                consume_one = False
            else:
                return
        else:
            reply = QMessageBox.question(
                self, "Confirm Swap",
                f"Swap item '{old_name}' (key={item.item_key})\n"
                f"to '{new_name}' (key={new_key})?\n\n"
                "This will patch the item record and equipment slot records.",
                QMessageBox.Yes | QMessageBox.No,
            )
            if reply != QMessageBox.Yes:
                return

        all_patches = []

        if consume_one:
            old_stack = apply_stack_edit(self._save_data.decompressed_blob, item, 1)
            all_patches.append((
                item.offset + 18, old_stack,
                self._save_data.decompressed_blob[item.offset + 18:item.offset + 26]
            ))

        patches = smart_item_swap(self._save_data.decompressed_blob, item, new_key)
        all_patches.extend(patches)
        item.name = self._name_db.get_name(new_key)
        item.category = self._name_db.get_category(new_key)

        self._undo_stack.append(UndoEntry(
            description=f"Swap {old_name} -> {new_name}" + (" (1 from stack)" if consume_one else ""),
            patches=all_patches,
        ))
        self._dirty = True
        self._populate_inventory()
        self._populate_equipment()
        mode = "PARC" if item.parc_parsed else "legacy"
        extra = f", consumed 1 from stack of {item.stack_count}" if consume_one else ""
        self._update_status(f"Swapped {old_name} -> {new_name} ({len(all_patches)} patches, {mode} mode{extra})")

    def _perform_swap_all(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Swap All", "No save file loaded.")
            return

        selected = self._get_selected_items(self._inv_table)
        if not selected:
            QMessageBox.information(
                self, "Swap All",
                "Select an item from the Inventory tab first, then switch to this tab."
            )
            return

        item = selected[0]

        new_key = 0
        swap_rows = set(idx.row() for idx in self._swap_list.selectedIndexes())
        if swap_rows:
            row = min(swap_rows)
            key_widget = self._swap_list.item(row, 1)
            if key_widget:
                try:
                    new_key = int(key_widget.text())
                except ValueError:
                    pass
        if new_key == 0:
            new_key = self._swap_manual_key.value()
        if new_key <= 0:
            QMessageBox.warning(self, "Swap All", "Select a target item or enter a manual key.")
            return
        if new_key == item.item_key:
            QMessageBox.information(self, "Swap All", "Target key is same as current key.")
            return

        old_name = item.name
        new_name = self._name_db.get_name(new_key)

        reply = QMessageBox.warning(
            self, "Confirm GLOBAL Swap",
            f"GLOBAL SWAP: This will replace EVERY occurrence of\n"
            f"'{old_name}' (key={item.item_key})\n\n"
            f"with '{new_name}' (key={new_key})\n\n"
            f"ALL items with this key will be changed — not just the selected one.\n"
            f"This is useful when you have multiple copies you want to transform together.\n\n"
            f"Continue?",
            QMessageBox.Yes | QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        patches = apply_item_swap_all(self._save_data.decompressed_blob, item, new_key)

        for it in self._items:
            if it.item_key == item.item_key or it.item_key == new_key:
                it.name = self._name_db.get_name(new_key)
                it.category = self._name_db.get_category(new_key)
                it.item_key = new_key

        self._undo_stack.append(UndoEntry(
            description=f"Swap All {old_name} -> {new_name}",
            patches=patches,
        ))
        self._dirty = True
        self._populate_inventory()
        self._populate_equipment()
        self._update_status(f"Global swap: {old_name} -> {new_name} ({len(patches)} patches)")

    def _perform_template_swap(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Template Swap", "No save file loaded.")
            return

        selected = self._get_selected_items(self._inv_table)
        if not selected:
            QMessageBox.warning(self, "Template Swap", "Select an item in the Inventory tab first.")
            return

        item = selected[0]

        swap_sel = self._swap_list.selectedItems()
        if swap_sel:
            key_item = self._swap_list.item(swap_sel[0].row(), 1)
            new_key = int(key_item.text()) if key_item else 0
        else:
            new_key = self._swap_manual_key.value()

        if new_key == 0:
            QMessageBox.warning(self, "Template Swap", "Select a target item or enter a manual key.")
            return
        if new_key == item.item_key:
            QMessageBox.information(self, "Template Swap", "Target key is same as current key.")
            return

        try:
            import json as _json
            import os as _os
            limits_path = _os.path.join(_os.path.dirname(_os.path.abspath(__file__)), 'item_limits.json')
            with open(limits_path, 'r') as _f:
                item_limits = _json.load(_f).get('items', {})
        except Exception:
            item_limits = {}

        template = None
        try:
            from item_template_db import get_template
            template = get_template(new_key)
        except Exception:
            pass

        old_name = self._name_db.get_name(item.item_key)
        new_name = self._name_db.get_name(new_key)
        old_limits = item_limits.get(str(item.item_key), {})
        new_limits = item_limits.get(str(new_key), {})
        old_is_equip = old_limits.get('slotType', -1) not in (-1, 65535)
        new_is_equip = new_limits.get('slotType', -1) not in (-1, 65535)
        new_stack_limit = new_limits.get('stackLimit', 999999)

        current_item_size = 0
        if hasattr(item, 'block_size') and item.block_size > 0:
            current_item_size = item.block_size

        can_template_replace = False
        if template and current_item_size > 0 and template['size'] == current_item_size:
            can_template_replace = True
        elif template and current_item_size == 0:
            pass

        if can_template_replace:
            method = f"FULL TEMPLATE REPLACE ({template['size']}B — real game data overwrites entire record)"
        elif template:
            method = f"Key swap + field patch from template (enchant, endurance, sharpness, sockets)"
        else:
            method = "Key swap only (no template in DB — stats may not match)"

        warnings = []
        if old_is_equip != new_is_equip:
            warnings.append(f"Type mismatch: {'Equipment' if old_is_equip else 'Item'} -> {'Equipment' if new_is_equip else 'Item'}")
        if item.stack_count > new_stack_limit > 0:
            warnings.append(f"Stack {item.stack_count} exceeds target limit {new_stack_limit}")
        warn_text = "\n\nWarnings:\n" + "\n".join(f"  - {w}" for w in warnings) if warnings else ""

        reply = QMessageBox.question(
            self, "Template Swap",
            f"  {old_name} -> {new_name}\n\n"
            f"  Method: {method}\n"
            f"  Stack limit: {new_stack_limit}"
            f"{warn_text}\n\nContinue?",
            QMessageBox.Yes | QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        patches = []

        if can_template_replace:
            import struct as _struct
            entry = bytearray(bytes.fromhex(template['hex']))
            fp = template.get('field_positions', {})

            if '_itemNo' in fp:
                _struct.pack_into('<q', entry, fp['_itemNo']['rel_offset'], item.item_no)
            if '_itemKey' in fp:
                _struct.pack_into('<I', entry, fp['_itemKey']['rel_offset'], new_key)
            if '_slotNo' in fp:
                _struct.pack_into('<H', entry, fp['_slotNo']['rel_offset'], item.slot_no)
            if '_stackCount' in fp:
                stack = min(item.stack_count, new_stack_limit) if new_stack_limit > 0 else item.stack_count
                _struct.pack_into('<q', entry, fp['_stackCount']['rel_offset'], stack)
            if '_transferredItemKey' in fp:
                _struct.pack_into('<I', entry, fp['_transferredItemKey']['rel_offset'], new_key)

            mbc = _struct.unpack_from('<H', entry, 0)[0]
            po_offset = 2 + mbc + 2 + 1 + 8
            item_abs_start = item.offset - (po_offset + 8)

            _struct.pack_into('<I', entry, po_offset, item_abs_start + po_offset + 4)

            _SENT = b'\xFF\xFF\xFF\xFF\xFF\xFF\xFF\xFF'
            for off in range(len(entry) - 15):
                m = _struct.unpack_from('<H', entry, off)[0]
                if m < 1 or m > 8:
                    continue
                s = off + 2 + m + 3
                if s + 12 > len(entry):
                    continue
                if entry[s:s + 8] != _SENT:
                    continue
                t = _struct.unpack_from('<H', entry, off + 2 + m)[0]
                if t > 200 or entry[off + 2 + m + 2] != 0:
                    continue
                pp = s + 8
                wrapper_end = off + 2 + m + 2 + 1 + 4 + 4 + 4
                _struct.pack_into('<I', entry, pp, item_abs_start + wrapper_end)

            for off in range(len(entry) - 18):
                if entry[off + 6:off + 14] == _SENT:
                    _struct.pack_into('<I', entry, off + 14, item_abs_start + off + 18)

            try:
                from parc_inserter2 import parse_and_collect
                current_type_idx = _struct.unpack_from('<H', self._save_data.decompressed_blob, item_abs_start + 2 + mbc)[0]
                _struct.pack_into('<H', entry, 2 + mbc, current_type_idx)

                current_socket_type = None
                for off in range(len(self._save_data.decompressed_blob) - 18):
                    check_start = item_abs_start + 20
                    check_end = item_abs_start + len(entry)
                    if check_start <= item.offset + off < check_end:
                        pass
            except Exception:
                pass

            old_bytes = bytes(self._save_data.decompressed_blob[item_abs_start:item_abs_start + len(entry)])
            self._save_data.decompressed_blob[item_abs_start:item_abs_start + len(entry)] = entry
            patches.append((item_abs_start, old_bytes, bytes(entry)))

            method_used = "FULL TEMPLATE REPLACE"
        else:
            patches = smart_item_swap(self._save_data.decompressed_blob, item, new_key)

            if new_stack_limit > 0 and item.stack_count > new_stack_limit:
                old_stack_bytes = apply_stack_edit(
                    self._save_data.decompressed_blob, item, new_stack_limit
                )
                patches.append((
                    item.offset + 18,
                    old_stack_bytes,
                    self._save_data.decompressed_blob[item.offset + 18:item.offset + 26]
                ))

            field_patches = 0
            if template:
                try:
                    from item_scanner import compute_item_field_offsets
                    import struct as _struct
                    blob = self._save_data.decompressed_blob
                    fp = template.get('field_positions', {})
                    t_hex = bytes.fromhex(template['hex'])

                    item_offsets = compute_item_field_offsets(bytes(blob), item.offset)

                    PATCH_FIELDS = [
                        '_enchantLevel', '_endurance', '_sharpness',
                        '_batteryStat', '_maxBatteryStat',
                        '_maxSocketCount', '_validSocketCount',
                    ]
                    for fname in PATCH_FIELDS:
                        if fname in item_offsets and fname in fp:
                            save_off = item_offsets[fname]
                            tmpl_rel = fp[fname]['rel_offset']
                            tmpl_sz = fp[fname]['size']

                            tmpl_bytes = t_hex[tmpl_rel:tmpl_rel + tmpl_sz]
                            old_bytes_f = bytes(blob[save_off:save_off + tmpl_sz])

                            if old_bytes_f != tmpl_bytes:
                                blob[save_off:save_off + tmpl_sz] = tmpl_bytes
                                patches.append((save_off, old_bytes_f, tmpl_bytes))
                                field_patches += 1
                except Exception as e:
                    log.warning("Template field patch failed: %s", e)

            if field_patches > 0:
                method_used = f"Key swap + {field_patches} fields patched from template"
            elif template:
                method_used = "Key swap (template fields same or unavailable)"
            else:
                method_used = "Key swap (no template in DB)"

        item.name = new_name
        item.category = self._name_db.get_category(new_key)
        item.item_key = new_key

        self._undo_stack.append(UndoEntry(
            description=f"Template Swap: {old_name} -> {new_name} [{method_used}]",
            patches=patches,
        ))
        self._dirty = True
        self._populate_inventory()
        self._populate_equipment()
        self._update_status(f"Template Swap: {old_name} -> {new_name} [{method_used}]")


    def _perform_clean_swap(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Clean Swap", "No save file loaded.")
            return

        selected = self._get_selected_items(self._inv_table)
        if not selected:
            QMessageBox.warning(self, "Clean Swap", "Select an item in the Inventory tab first.")
            return

        item = selected[0]

        swap_sel = self._swap_list.selectedItems()
        if swap_sel:
            key_item = self._swap_list.item(swap_sel[0].row(), 1)
            new_key = int(key_item.text()) if key_item else 0
        else:
            new_key = self._swap_manual_key.value()

        if new_key == 0:
            QMessageBox.warning(self, "Clean Swap", "Select a target item or enter a manual key.")
            return
        if new_key == item.item_key:
            return

        old_name = self._name_db.get_name(item.item_key)
        new_name = self._name_db.get_name(new_key)

        reply = QMessageBox.question(
            self, "Clean Swap",
            f"Swap + clean leftover data:\n\n"
            f"  {old_name} -> {new_name}\n\n"
            f"This does a normal swap PLUS zeros out:\n"
            f"  - _currentGimmickState (may fix placeholder icons)\n"
            f"  - _chargedUseableCount\n"
            f"  - _timeWhenPushItem\n\n"
            f"Continue?",
            QMessageBox.Yes | QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        patches = smart_item_swap(self._save_data.decompressed_blob, item, new_key)

        blob = self._save_data.decompressed_blob
        if item.parc_parsed and item.field_offsets:
            fo = item.field_offsets
            if '_currentGimmickState' in fo:
                off = fo['_currentGimmickState']
                old = bytes(blob[off:off + 4])
                struct.pack_into('<I', blob, off, 0)
                patches.append((off, old, bytes(blob[off:off + 4])))
            if '_chargedUseableCount' in fo:
                off = fo['_chargedUseableCount']
                old = bytes(blob[off:off + 8])
                struct.pack_into('<q', blob, off, 0)
                patches.append((off, old, bytes(blob[off:off + 8])))
            if '_timeWhenPushItem' in fo:
                off = fo['_timeWhenPushItem']
                old = bytes(blob[off:off + 8])
                struct.pack_into('<Q', blob, off, 0)
                patches.append((off, old, bytes(blob[off:off + 8])))

        item.name = new_name
        item.category = self._name_db.get_category(new_key)
        item.item_key = new_key

        self._undo_stack.append(UndoEntry(
            description=f"Clean Swap: {old_name} -> {new_name} (zeroed gimmick/charged/time)",
            patches=patches,
        ))
        self._dirty = True
        self._populate_inventory()
        self._populate_equipment()
        self._update_status(f"Clean Swap: {old_name} -> {new_name} [gimmick/charged/time zeroed]")

    def _populate_database(self) -> None:
        categories = set()
        for info in self._name_db.items.values():
            categories.add(info.category)
        current_cat = self._db_category.currentText()
        self._db_category.blockSignals(True)
        self._db_category.clear()
        self._db_category.addItem("All")
        for cat in sorted(categories):
            self._db_category.addItem(cat)
        idx = self._db_category.findText(current_cat)
        if idx >= 0:
            self._db_category.setCurrentIndex(idx)
        self._db_category.blockSignals(False)

        self._filter_database()

    def _filter_database(self) -> None:
        table = self._db_table
        table.setSortingEnabled(False)
        table.setRowCount(0)

        search = self._db_search.text().strip()
        cat_filter = self._db_category.currentText()

        if search:
            items = self._name_db.search(search)
        else:
            items = self._name_db.get_all_sorted()

        if cat_filter != "All":
            items = [i for i in items if i.category == cat_filter]

        table.setRowCount(len(items))
        for row, info in enumerate(items):
            color = QColor(CATEGORY_COLORS.get(info.category, COLORS["text"]))

            icon_item = QTableWidgetItem()
            if self._icons_enabled:
                px = self._icon_cache.get_pixmap(info.item_key)
                if px:
                    icon_item.setIcon(QIcon(px))
                elif self._icon_cache.has_icon(info.item_key):
                    self._icon_cache.request_icon(info.item_key, self._on_icon_loaded)
            table.setItem(row, 0, icon_item)

            key_item = QTableWidgetItem(str(info.item_key))
            key_item.setData(Qt.UserRole, info.item_key)
            table.setItem(row, 1, key_item)

            name_item = QTableWidgetItem(info.name)
            name_item.setForeground(QBrush(color))
            table.setItem(row, 2, name_item)

            table.setItem(row, 3, QTableWidgetItem(info.internal_name))

            cat_item = QTableWidgetItem(info.category)
            cat_item.setForeground(QBrush(color))
            table.setItem(row, 4, cat_item)

            table.setItem(row, 5, QTableWidgetItem(str(info.max_stack)))

        table.setSortingEnabled(True)
        self._db_info_label.setText(
            f"Showing {len(items)} of {len(self._name_db.items)} items  |  "
            f"DB version: {self._name_db.version}  |  "
            f"Path: {self._name_db.loaded_path or '(none)'}"
        )

    def _rename_item(self) -> None:
        rows = set(idx.row() for idx in self._db_table.selectedIndexes())
        if not rows:
            QMessageBox.information(self, "Rename", "Select an item first.")
            return

        new_name = self._db_rename_input.text().strip()
        if not new_name:
            QMessageBox.information(self, "Rename", "Enter a new name.")
            return

        row = min(rows)
        key_widget = self._db_table.item(row, 1)
        if not key_widget:
            return

        key = key_widget.data(Qt.UserRole)
        old_name = self._name_db.get_name(key)
        self._name_db.rename_item(key, new_name)
        self._name_db.save()

        for item in self._items:
            if item.item_key == key:
                item.name = new_name

        self._filter_database()
        self._populate_inventory()
        self._populate_equipment()
        self._populate_swap_list(self._swap_search.text().strip())
        self._update_status(f"Renamed item {key}: '{old_name}' -> '{new_name}'")
        self._db_rename_input.clear()

    def _copy_item_key(self) -> None:
        rows = set(idx.row() for idx in self._db_table.selectedIndexes())
        if not rows:
            QMessageBox.information(self, "Copy Key", "Select an item first.")
            return
        row = min(rows)
        key_w = self._db_table.item(row, 1)
        if key_w:
            QApplication.clipboard().setText(key_w.text())
            name_w = self._db_table.item(row, 1)
            name = name_w.text() if name_w else key_w.text()
            self._update_status(f"Copied key {key_w.text()} ({name}) to clipboard")

    def _db_context_menu(self, pos):
        rows = sorted(set(idx.row() for idx in self._db_table.selectedIndexes()))
        if not rows:
            return

        from PySide6.QtWidgets import QMenu
        menu = QMenu(self)

        copy_act = menu.addAction(f"Copy Key(s) ({len(rows)} selected)")
        export_pack_act = menu.addAction(f"Export as DropSet Pack ({len(rows)} items)")

        action = menu.exec(self._db_table.viewport().mapToGlobal(pos))

        if action == copy_act:
            keys = []
            for r in rows:
                key_w = self._db_table.item(r, 1)
                if key_w:
                    keys.append(key_w.text())
            if keys:
                QApplication.clipboard().setText(", ".join(keys))
                self._update_status(f"Copied {len(keys)} key(s) to clipboard")

        elif action == export_pack_act:
            self._db_export_dropset_pack(rows)

    def _db_export_dropset_pack(self, rows):
        from PySide6.QtWidgets import QInputDialog, QFileDialog

        name, ok = QInputDialog.getText(
            self, "DropSet Pack Name", "Name for this drop pack:",
            text="My Drop Pack")
        if not ok or not name.strip():
            return

        items = []
        for r in rows:
            key_w = self._db_table.item(r, 1)
            name_w = self._db_table.item(r, 2)
            cat_w = self._db_table.item(r, 4)
            if not key_w:
                continue
            try:
                item_key = int(key_w.text())
            except ValueError:
                continue
            item_name = name_w.text() if name_w else f"Item_{item_key}"
            items.append({
                "item_key": item_key,
                "name": item_name,
                "rate_pct": 100,
                "qty": 1,
            })

        if not items:
            return

        packs_dir = os.path.join(os.path.dirname(os.path.abspath(sys.argv[0])), "dropset_packs")
        os.makedirs(packs_dir, exist_ok=True)
        default_fn = name.strip().replace(" ", "_") + ".json"

        path, _ = QFileDialog.getSaveFileName(
            self, "Save DropSet Pack",
            os.path.join(packs_dir, default_fn),
            "JSON Files (*.json)")
        if not path:
            return

        pack = {
            "type": "dropset_pack",
            "version": 1,
            "name": name.strip(),
            "author": "CrimsonSaveEditor",
            "description": f"{len(items)} items selected from Item Database",
            "items": items,
        }

        with open(path, "w", encoding="utf-8") as f:
            json.dump(pack, f, indent=2)

        self._update_status(f"Exported {len(items)} items as DropSet pack: {os.path.basename(path)}")
        QMessageBox.information(self, "Pack Exported",
            f"Saved {len(items)} items to:\n{path}\n\n"
            f"This pack will appear in the DropSets tab Pack dropdown.")

    def _sync_github(self) -> None:
        self._update_status("Syncing from GitHub...")
        QApplication.processEvents()

        ok, msg = self._name_db.sync_from_github()
        if ok:
            self._populate_database()
            self._populate_swap_list(self._swap_search.text().strip())
            for item in self._items:
                item.name = self._name_db.get_name(item.item_key)
                item.category = self._name_db.get_category(item.item_key)
            self._populate_inventory()
            self._populate_equipment()
        self._update_status(msg)
        QMessageBox.information(self, "GitHub Sync", msg)

    def _sync_all_icons(self) -> None:
        import json as _json
        from urllib.request import urlopen, Request

        keys = set()
        for item in self._name_db._items.values():
            keys.add(item.item_key)
        for item in self._items:
            keys.add(item.item_key)

        local_dir = self._icon_cache._local_dir
        already = sum(1 for k in keys if os.path.isfile(os.path.join(local_dir, f"{k}.webp")))
        needed = len(keys) - already

        if needed == 0:
            QMessageBox.information(self, "Sync Icons", f"All {already} icons already downloaded.")
            return

        reply = QMessageBox.question(
            self, "Sync All Icons",
            f"Download {needed} icons from GitHub?\n"
            f"({already} already cached, {len(keys)} total)\n\n"
            f"This requires internet and may take a few minutes.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        self._update_status(f"Downloading {needed} icons...")
        QApplication.processEvents()

        from icon_cache import _GITHUB_ICON_BASE
        downloaded = 0
        errors = 0
        for i, key in enumerate(sorted(keys)):
            local_path = os.path.join(local_dir, f"{key}.webp")
            if os.path.isfile(local_path):
                continue
            try:
                url = f"{_GITHUB_ICON_BASE}/{key}.webp"
                req = Request(url, headers={"User-Agent": "CrimsonSaveEditor"})
                with urlopen(req, timeout=15) as resp:
                    data = resp.read()
                if data and len(data) > 100:
                    with open(local_path, 'wb') as f:
                        f.write(data)
                    downloaded += 1
                else:
                    errors += 1
            except Exception:
                errors += 1

            if (downloaded + errors) % 100 == 0:
                self._update_status(f"Icons: {downloaded} downloaded, {errors} failed, {needed - downloaded - errors} remaining...")
                QApplication.processEvents()

        msg = f"Downloaded {downloaded} icons, {errors} not available on GitHub.\nTotal cached: {already + downloaded}"
        self._update_status(msg)
        QMessageBox.information(self, "Sync Complete", msg)


    def _get_backup_dir(self) -> str:
        if not self._loaded_path:
            return ""
        save_dir = os.path.dirname(self._loaded_path)
        return os.path.join(save_dir, "backups")

    def _create_backup(self, save_path: str) -> str:
        if not os.path.isfile(save_path):
            return ""

        backup_dir = os.path.join(os.path.dirname(save_path), "backups")
        os.makedirs(backup_dir, exist_ok=True)

        timestamp = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        base = os.path.basename(save_path)
        backup_name = f"{base}.{timestamp}.bak"
        backup_path = os.path.join(backup_dir, backup_name)

        shutil.copy2(save_path, backup_path)

        try:
            existing = sorted(
                [f for f in os.listdir(backup_dir)
                 if f.endswith(".bak") and ".PRISTINE." not in f],
                key=lambda f: os.path.getmtime(os.path.join(backup_dir, f)),
                reverse=True,
            )
            for old in existing[10:]:
                os.remove(os.path.join(backup_dir, old))
        except OSError:
            pass

        try:
            slot_name = os.path.basename(os.path.dirname(save_path))
            exe_dir = self._app_dir()
            global_dir = os.path.join(exe_dir, "backups", slot_name)
            os.makedirs(global_dir, exist_ok=True)

            global_path = os.path.join(global_dir, backup_name)
            shutil.copy2(save_path, global_path)

            g_existing = sorted(
                [f for f in os.listdir(global_dir) if f.endswith(".bak")],
                key=lambda f: os.path.getmtime(os.path.join(global_dir, f)),
                reverse=True,
            )
            for old in g_existing[10:]:
                os.remove(os.path.join(global_dir, old))
        except Exception:
            pass

        return backup_path

    def _create_pristine_backup(self, save_path: str) -> str:
        if not os.path.isfile(save_path):
            return ""

        backup_dir = os.path.join(os.path.dirname(save_path), "backups")
        os.makedirs(backup_dir, exist_ok=True)

        base = os.path.basename(save_path)
        pristine_name = f"{base}.PRISTINE.bak"
        pristine_path = os.path.join(backup_dir, pristine_name)

        if os.path.isfile(pristine_path):
            return ""

        try:
            from save_crypto import load_save_file
            sd = load_save_file(save_path)
            if not sd or not sd.decompressed_blob or len(sd.decompressed_blob) < 100:
                log.warning("Skipping PRISTINE backup — save appears invalid")
                return ""
        except Exception as e:
            log.warning("Skipping PRISTINE backup — save failed validation: %s", e)
            return ""

        shutil.copy2(save_path, pristine_path)
        return pristine_path

    def _refresh_backups(self) -> None:
        self._backup_list.clear()
        backup_dir = self._get_backup_dir()
        if not backup_dir or not os.path.isdir(backup_dir):
            self._backup_list.addItem("(No backups found)")
            self._tabs.setTabText(self._backup_tab_index, "Backup/Restore")
            return

        backups = []
        for name in os.listdir(backup_dir):
            path = os.path.join(backup_dir, name)
            if os.path.isfile(path):
                mtime = os.path.getmtime(path)
                size = os.path.getsize(path)
                backups.append((name, path, mtime, size))

        backups.sort(key=lambda x: x[2], reverse=True)

        if not backups:
            self._backup_list.addItem("(No backups found)")
            self._tabs.setTabText(self._backup_tab_index, "Backup/Restore")
            return

        for name, path, mtime, size in backups:
            dt = datetime.datetime.fromtimestamp(mtime).strftime("%Y-%m-%d %H:%M:%S")
            is_pristine = ".PRISTINE." in name
            tag = "  [PRISTINE]" if is_pristine else ""
            display = f"{name}  |  {dt}  |  {size:,} bytes{tag}"
            item = QListWidgetItem(display)
            item.setData(Qt.UserRole, path)
            if is_pristine:
                item.setForeground(QBrush(QColor(COLORS["success"])))
            self._backup_list.addItem(item)

        self._tabs.setTabText(self._backup_tab_index, f"Backup/Restore ({len(backups)})")

    def _restore_backup(self) -> None:
        current = self._backup_list.currentItem()
        if not current:
            QMessageBox.information(self, "Restore", "Select a backup first.")
            return

        backup_path = current.data(Qt.UserRole)
        if not backup_path or not os.path.isfile(backup_path):
            QMessageBox.warning(self, "Restore", "Backup file not found.")
            return

        if not self._loaded_path:
            QMessageBox.warning(self, "Restore", "No save file loaded to restore to.")
            return

        reply = QMessageBox.warning(
            self, "Restore Backup",
            f"Restore backup:\n{os.path.basename(backup_path)}\n\n"
            f"This will OVERWRITE your current save:\n{self._loaded_path}\n\n"
            "This cannot be undone. Continue?",
            QMessageBox.Yes | QMessageBox.No,
            QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return

        try:
            from save_crypto import load_save_file
            try:
                test = load_save_file(backup_path)
                if not test or not test.decompressed_blob or len(test.decompressed_blob) < 100:
                    raise ValueError("Backup appears corrupted (too small or empty)")
            except Exception as ve:
                reply2 = QMessageBox.warning(
                    self, "Backup May Be Corrupted",
                    f"This backup failed validation:\n{ve}\n\n"
                    f"Restoring it may result in a save that crashes the game.\n"
                    f"Restore anyway?",
                    QMessageBox.Yes | QMessageBox.No,
                    QMessageBox.No,
                )
                if reply2 != QMessageBox.Yes:
                    return

            shutil.copy2(backup_path, self._loaded_path)
            self._load_save(self._loaded_path)
            self._update_status(f"Restored from backup: {os.path.basename(backup_path)}")
        except Exception as e:
            QMessageBox.critical(self, "Restore Error", f"Failed to restore:\n{e}")

    def _delete_backup(self) -> None:
        current = self._backup_list.currentItem()
        if not current:
            QMessageBox.information(self, "Delete", "Select a backup first.")
            return
        backup_path = current.data(Qt.UserRole)
        if not backup_path:
            return
        name = os.path.basename(backup_path)
        reply = QMessageBox.warning(
            self, "Delete Backup",
            f"Permanently delete:\n{name}\n\nThis cannot be undone.",
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return
        try:
            os.remove(backup_path)
            self._refresh_backups()
            self._update_status(f"Deleted backup: {name}")
        except Exception as e:
            QMessageBox.critical(self, "Delete Error", f"Failed to delete:\n{e}")

    def _reset_pristine(self) -> None:
        if not self._loaded_path:
            QMessageBox.warning(self, "Reset PRISTINE", "No save file loaded.")
            return
        backup_dir = os.path.join(os.path.dirname(self._loaded_path), "backups")
        base = os.path.basename(self._loaded_path)
        pristine_path = os.path.join(backup_dir, f"{base}.PRISTINE.bak")

        msg = "Set the currently loaded save as the new PRISTINE backup?"
        if os.path.isfile(pristine_path):
            msg += "\n\nThis will REPLACE the existing PRISTINE backup."

        reply = QMessageBox.question(
            self, "Reset PRISTINE", msg,
            QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
        )
        if reply != QMessageBox.Yes:
            return
        try:
            os.makedirs(backup_dir, exist_ok=True)
            shutil.copy2(self._loaded_path, pristine_path)
            self._refresh_backups()
            self._update_status("PRISTINE backup updated from current save.")
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to update PRISTINE:\n{e}")

    def _open_backup_folder(self) -> None:
        backup_dir = self._get_backup_dir()
        if not backup_dir:
            QMessageBox.information(self, "Backup Folder", "No save file loaded.")
            return
        os.makedirs(backup_dir, exist_ok=True)
        os.startfile(backup_dir)


    def _dragon_unlock_swap(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Dragon Unlock", "No save loaded.")
            return

        DRAGON_KEY = 1000799
        blob = self._save_data.decompressed_blob

        try:
            import parc_serializer as ps
            parc = ps.parse_parc_blob(bytes(blob))

            merc_toc = None
            for e in parc.toc_entries:
                if e.class_index < len(parc.types):
                    if parc.types[e.class_index].name == "MercenaryClanSaveData":
                        merc_toc = e
                        break

            if merc_toc is None:
                QMessageBox.warning(self, "Dragon Unlock", "MercenaryClanSaveData not found in save.")
                return

            raw = parc.block_raw[merc_toc.index]
            abs_off = merc_toc.data_offset
            sentinel = b'\xff\xff\xff\xff\xff\xff\xff\xff'

            merc_type_idx = None
            for i, t in enumerate(parc.types):
                if t.name == 'MercenarySaveData':
                    merc_type_idx = i
                    break

            entries = []
            for off in range(len(raw) - 24):
                if raw[off:off + 8] != sentinel:
                    continue
                if merc_type_idx is not None and off >= 3:
                    ti = struct.unpack_from('<H', raw, off - 3)[0]
                    if ti != merc_type_idx:
                        continue
                key_off = off + 16
                if key_off + 4 > len(raw):
                    continue
                ckey = struct.unpack_from('<I', raw, key_off)[0]
                if ckey > 0 and ckey < 0x7FFFFFFF:
                    entries.append((key_off, ckey))

            dragon_bytes = struct.pack('<I', DRAGON_KEY)
            dragon_pos = raw.find(dragon_bytes)
            if dragon_pos >= 0:
                QMessageBox.information(self, "Dragon Unlock",
                                        f"Dragon (key={DRAGON_KEY}) already exists in MercenaryClanSaveData at +{dragon_pos}!")
                return

            if not entries:
                QMessageBox.warning(self, "Dragon Unlock",
                                    "No mercenary entries found in MercenaryClanSaveData.\n"
                                    "You need at least one hired mercenary in your save to swap.")
                return

            choices = []
            for i, (koff, ckey) in enumerate(entries):
                choices.append(f"{i+1}. Mercenary (characterKey={ckey})")

            from PySide6.QtWidgets import QInputDialog
            selected, ok = QInputDialog.getItem(
                self, "Dragon Unlock — Pick mercenary to replace",
                f"Found {len(entries)} mercenary entries in MercenaryClanSaveData.\n"
                f"Pick one to REPLACE with Dragon (key={DRAGON_KEY}).\n"
                f"The replaced mercenary will be LOST.\n\n"
                f"NOTE: You may also need Knowledge_BlackWolf and Knowledge_CallDragon\n"
                f"for the Dragon to appear in-game. This is experimental.",
                choices, 0, False,
            )
            if not ok:
                return

            idx = choices.index(selected)
            key_off, old_key = entries[idx]
            abs_key_off = abs_off + key_off

            old_bytes = blob[abs_key_off:abs_key_off + 4]
            struct.pack_into('<I', blob, abs_key_off, DRAGON_KEY)
            new_bytes = blob[abs_key_off:abs_key_off + 4]

            self._undo_stack.append(UndoEntry(
                description=f"Dragon Unlock: replaced mercenary key {old_key} with {DRAGON_KEY}",
                patches=[(abs_key_off, old_bytes, new_bytes)],
            ))
            self._dirty = True

            old_name = choices[idx].split(". ", 1)[1]
            QMessageBox.information(
                self, "Dragon Unlock",
                f"Replaced {old_name} with Dragon (key={DRAGON_KEY}).\n\n"
                f"Save the file and load in-game.\n"
                f"Check your F1 summon menu for the Dragon.\n\n"
                f"If Dragon doesn't appear, you may also need:\n"
                f"- Knowledge_BlackWolf (key=40068)\n"
                f"- Knowledge_CallDragon (key=1000175)"
            )

        except Exception as e:
            QMessageBox.critical(self, "Dragon Unlock Error", str(e))

    def _dragon_knowledge_swap(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Dragon Knowledge", "No save loaded.")
            return

        NEEDED = {40068: "Knowledge_BlackWolf", 1000175: "Knowledge_CallDragon"}
        blob = self._save_data.decompressed_blob

        try:
            import parc_serializer as ps
            parc = ps.parse_parc_blob(bytes(blob))

            know_toc = None
            for e in parc.toc_entries:
                if e.class_index < len(parc.types) and parc.types[e.class_index].name == "KnowledgeSaveData":
                    know_toc = e
                    break
            if know_toc is None:
                QMessageBox.warning(self, "Dragon Knowledge", "KnowledgeSaveData not found.")
                return

            know_elem_type = None
            for i, t in enumerate(parc.types):
                if t.name == "KnowledgeElementSaveData":
                    know_elem_type = i
                    break

            raw = parc.block_raw[know_toc.index]
            abs_off = know_toc.data_offset
            sentinel = b'\xff\xff\xff\xff\xff\xff\xff\xff'

            entries = []
            for off in range(len(raw) - 20):
                if raw[off:off + 8] != sentinel:
                    continue
                if know_elem_type is not None and off >= 3:
                    ti = struct.unpack_from('<H', raw, off - 3)[0]
                    if ti != know_elem_type:
                        continue
                key_off = off + 16
                if key_off + 4 <= len(raw):
                    kkey = struct.unpack_from('<I', raw, key_off)[0]
                    if kkey > 0 and kkey < 0x7FFFFFFF:
                        entries.append((key_off, kkey))

            if not entries:
                QMessageBox.warning(self, "Dragon Knowledge", "No knowledge entries found in save.")
                return

            existing = {kkey for _, kkey in entries}
            missing = {k: v for k, v in NEEDED.items() if k not in existing}

            if not missing:
                QMessageBox.information(self, "Dragon Knowledge",
                                        "Both Knowledge_BlackWolf and Knowledge_CallDragon already present!")
                return

            keep_keys = set(NEEDED.keys()) | {1000174}
            swappable = [(koff, kkey) for koff, kkey in entries if kkey not in keep_keys]

            if len(swappable) < len(missing):
                QMessageBox.warning(self, "Dragon Knowledge",
                                    f"Need {len(missing)} entries to swap but only {len(swappable)} available.")
                return

            missing_names = "\n".join(f"  - {v} (key={k})" for k, v in missing.items())
            sacrifice_keys = [str(s[1]) for s in swappable[:len(missing)]]
            sacrifice_text = ", ".join(sacrifice_keys)

            reply = QMessageBox.question(
                self, "Add Dragon Knowledge",
                f"Missing knowledge entries:\n{missing_names}\n\n"
                f"Will swap {len(missing)} existing knowledge entries (keys: {sacrifice_text}).\n"
                f"Those knowledge entries will be lost.\n\n"
                f"Proceed?",
                QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
            )
            if reply != QMessageBox.Yes:
                return

            all_patches = []
            for i, (needed_key, needed_name) in enumerate(missing.items()):
                koff, old_key = swappable[i]
                abs_key_off = abs_off + koff
                old_bytes = blob[abs_key_off:abs_key_off + 4]
                struct.pack_into('<I', blob, abs_key_off, needed_key)
                new_bytes = blob[abs_key_off:abs_key_off + 4]
                all_patches.append((abs_key_off, old_bytes, new_bytes))

            self._undo_stack.append(UndoEntry(
                description=f"Dragon Knowledge: added {', '.join(missing.values())}",
                patches=all_patches,
            ))
            self._dirty = True

            added = "\n".join(f"  - {v}" for v in missing.values())
            QMessageBox.information(
                self, "Dragon Knowledge Added",
                f"Added:\n{added}\n\n"
                f"Save the file and load in-game.\n"
                f"Try summoning the Dragon from the F1 wheel."
            )

        except Exception as e:
            QMessageBox.critical(self, "Dragon Knowledge Error", str(e))

    def _find_merc_entries(self, parc, block_raw, toc_entry):
        merc_type = None
        for i, t in enumerate(parc.types):
            if t.name == 'MercenarySaveData':
                merc_type = i
                break
        if merc_type is None:
            return []

        raw = block_raw
        sentinel = b'\xff\xff\xff\xff\xff\xff\xff\xff'
        entries = []

        for off in range(len(raw) - 20):
            if raw[off:off + 8] != sentinel:
                continue
            if off < 3:
                continue
            ti = struct.unpack_from('<H', raw, off - 3)[0]
            if ti != merc_type:
                continue

            loc_start = None
            for mbc_val in range(1, 10):
                ls = off - 3 - mbc_val - 2
                if ls >= 0 and struct.unpack_from('<H', raw, ls)[0] == mbc_val:
                    loc_start = ls
                    break
            if loc_start is None:
                loc_start = off - 11

            ckey = struct.unpack_from('<I', raw, off + 16)[0]
            entries.append((loc_start, off, ckey))

        result = []
        for i, (ls, sent, ckey) in enumerate(entries):
            if i + 1 < len(entries):
                entry_end = entries[i + 1][0]
            else:
                entry_end = len(raw)
            result.append((ls, sent, entry_end, ckey))

        return result

    def _dragon_template_patch(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Dragon Template", "No save loaded.")
            return

        from PySide6.QtWidgets import QFileDialog
        src_path, _ = QFileDialog.getOpenFileName(
            self, "Select save with legit Dragon (e.g. slot104)",
            "", "Save files (*.save);;All files (*)"
        )
        if not src_path:
            return

        DRAGON_KEY = 1000799

        try:
            import parc_serializer as ps
            import save_crypto

            src_sd = save_crypto.load_save_file(src_path)
            src_parc = ps.parse_parc_blob(bytes(src_sd.decompressed_blob))

            src_merc_toc = None
            for e in src_parc.toc_entries:
                if e.class_index < len(src_parc.types) and src_parc.types[e.class_index].name == 'MercenaryClanSaveData':
                    src_merc_toc = e
                    break

            if src_merc_toc is None:
                QMessageBox.warning(self, "Dragon Template", "Source save has no MercenaryClanSaveData.")
                return

            src_raw = src_parc.block_raw[src_merc_toc.index]
            src_entries = self._find_merc_entries(src_parc, src_raw, src_merc_toc)

            src_dragon = None
            for ls, sent, end, ckey in src_entries:
                if ckey == DRAGON_KEY:
                    src_dragon = (ls, sent, end, ckey)
                    break

            if src_dragon is None:
                QMessageBox.warning(self, "Dragon Template", f"Source save has no Dragon entry (key={DRAGON_KEY}).")
                return

            dragon_template = bytearray(src_raw[src_dragon[0]:src_dragon[2]])
            dragon_template_size = len(dragon_template)
            src_block_abs = src_merc_toc.data_offset

            blob = self._save_data.decompressed_blob
            tgt_parc = ps.parse_parc_blob(bytes(blob))

            tgt_merc_toc = None
            for e in tgt_parc.toc_entries:
                if e.class_index < len(tgt_parc.types) and tgt_parc.types[e.class_index].name == 'MercenaryClanSaveData':
                    tgt_merc_toc = e
                    break

            if tgt_merc_toc is None:
                QMessageBox.warning(self, "Dragon Template", "Current save has no MercenaryClanSaveData.")
                return

            tgt_raw = tgt_parc.block_raw[tgt_merc_toc.index]
            tgt_entries = self._find_merc_entries(tgt_parc, tgt_raw, tgt_merc_toc)

            if not tgt_entries:
                QMessageBox.warning(self, "Dragon Template", "No mercenary entries found in current save.")
                return

            for ls, sent, end, ckey in tgt_entries:
                if ckey == DRAGON_KEY:
                    entry_size = end - ls

                    if dragon_template_size > entry_size:
                        QMessageBox.warning(self, "Dragon Template",
                            f"Dragon template ({dragon_template_size}B) is larger than target entry ({entry_size}B).\n"
                            f"Cannot overwrite in-place. Try Full Clone instead.")
                        return

                    adj_template = bytearray(dragon_template)
                    sentinel = b'\xff\xff\xff\xff\xff\xff\xff\xff'
                    src_entry_abs = src_block_abs + src_dragon[0]
                    tgt_entry_abs = tgt_merc_toc.data_offset + ls

                    delta = tgt_entry_abs - src_entry_abs
                    for toff in range(len(adj_template) - 12):
                        if adj_template[toff:toff + 8] == sentinel:
                            po_off = toff + 8
                            po_val = struct.unpack_from('<I', adj_template, po_off)[0]
                            if po_val > 0 and po_val != 0xFFFFFFFF:
                                struct.pack_into('<I', adj_template, po_off, po_val + delta)

                    write_pos = tgt_merc_toc.data_offset + ls
                    old_bytes = bytes(blob[write_pos:write_pos + entry_size])
                    blob[write_pos:write_pos + dragon_template_size] = adj_template
                    if entry_size > dragon_template_size:
                        blob[write_pos + dragon_template_size:write_pos + entry_size] = b'\x00' * (entry_size - dragon_template_size)
                    new_bytes = bytes(blob[write_pos:write_pos + entry_size])

                    self._undo_stack.append(UndoEntry(
                        description=f"Dragon Template: overwrote {entry_size}B entry with {dragon_template_size}B legit template",
                        patches=[(write_pos, old_bytes, new_bytes)],
                    ))
                    self._dirty = True
                    QMessageBox.information(self, "Dragon Template",
                        f"Overwrote Dragon entry with legit template.\n"
                        f"Template: {dragon_template_size}B, Entry: {entry_size}B\n"
                        f"Zeroed {entry_size - dragon_template_size}B trailing garbage.\n\n"
                        f"Save and load in-game to test.")
                    return

            choices = []
            for i, (ls, sent, end, ckey) in enumerate(tgt_entries):
                size = end - ls
                fit = "CAN FIT" if size >= dragon_template_size else "TOO SMALL"
                choices.append(f"key={ckey}, {size}B ({fit})")

            from PySide6.QtWidgets import QInputDialog
            selected, ok = QInputDialog.getItem(
                self, "Dragon Template — Pick entry to overwrite",
                f"Dragon template is {dragon_template_size}B.\n"
                f"Pick an entry to overwrite (must be large enough):\n",
                choices, 0, False,
            )
            if not ok:
                return

            idx = choices.index(selected)
            ls, sent, end, old_key = tgt_entries[idx]
            entry_size = end - ls

            if dragon_template_size > entry_size:
                QMessageBox.warning(self, "Dragon Template",
                    f"Template ({dragon_template_size}B) > entry ({entry_size}B). Cannot fit.")
                return

            adj_template = bytearray(dragon_template)
            sentinel_b = b'\xff\xff\xff\xff\xff\xff\xff\xff'
            src_entry_abs = src_block_abs + src_dragon[0]
            tgt_entry_abs = tgt_merc_toc.data_offset + ls
            delta = tgt_entry_abs - src_entry_abs

            for toff in range(len(adj_template) - 12):
                if adj_template[toff:toff + 8] == sentinel_b:
                    po_off = toff + 8
                    po_val = struct.unpack_from('<I', adj_template, po_off)[0]
                    if po_val > 0 and po_val != 0xFFFFFFFF:
                        struct.pack_into('<I', adj_template, po_off, po_val + delta)

            write_pos = tgt_merc_toc.data_offset + ls
            old_bytes = bytes(blob[write_pos:write_pos + entry_size])
            blob[write_pos:write_pos + dragon_template_size] = adj_template
            if entry_size > dragon_template_size:
                blob[write_pos + dragon_template_size:write_pos + entry_size] = b'\x00' * (entry_size - dragon_template_size)
            new_bytes = bytes(blob[write_pos:write_pos + entry_size])

            self._undo_stack.append(UndoEntry(
                description=f"Dragon Template: replaced key={old_key} with Dragon template",
                patches=[(write_pos, old_bytes, new_bytes)],
            ))
            self._dirty = True
            QMessageBox.information(self, "Dragon Template",
                f"Replaced entry (key={old_key}, {entry_size}B) with Dragon template ({dragon_template_size}B).\n"
                f"Save and load in-game to test.")

        except Exception as e:
            QMessageBox.critical(self, "Dragon Template Error", str(e))

    def _dragon_full_clone(self) -> None:
        if not self._save_data:
            QMessageBox.warning(self, "Dragon Clone", "No save loaded.")
            return

        from PySide6.QtWidgets import QFileDialog
        src_path, _ = QFileDialog.getOpenFileName(
            self, "Select save with legit Dragon (e.g. slot104)",
            "", "Save files (*.save);;All files (*)"
        )
        if not src_path:
            return

        try:
            import parc_serializer as ps
            import save_crypto

            src_sd = save_crypto.load_save_file(src_path)
            src_blob = bytes(src_sd.decompressed_blob)
            src_parc = ps.parse_parc_blob(src_blob)

            src_merc_toc = None
            for e in src_parc.toc_entries:
                if e.class_index < len(src_parc.types) and src_parc.types[e.class_index].name == 'MercenaryClanSaveData':
                    src_merc_toc = e
                    break

            if src_merc_toc is None:
                QMessageBox.warning(self, "Dragon Clone", "Source save has no MercenaryClanSaveData.")
                return

            src_raw = src_parc.block_raw[src_merc_toc.index]

            dk = struct.pack('<I', 1000799)
            if src_raw.find(dk) < 0:
                QMessageBox.warning(self, "Dragon Clone", "Source save has no Dragon entry.")
                return

            blob = self._save_data.decompressed_blob
            tgt_parc = ps.parse_parc_blob(bytes(blob))

            tgt_merc_toc = None
            for e in tgt_parc.toc_entries:
                if e.class_index < len(tgt_parc.types) and tgt_parc.types[e.class_index].name == 'MercenaryClanSaveData':
                    tgt_merc_toc = e
                    break

            if tgt_merc_toc is None:
                QMessageBox.warning(self, "Dragon Clone", "Current save has no MercenaryClanSaveData.")
                return

            tgt_raw = tgt_parc.block_raw[tgt_merc_toc.index]
            size_diff = len(src_raw) - len(tgt_raw)

            reply = QMessageBox.question(
                self, "Dragon: Full MercenaryClan Clone",
                f"Replace ENTIRE MercenaryClanSaveData block?\n\n"
                f"Source: {len(src_raw):,}B ({src_path.split('/')[-2]})\n"
                f"Target: {len(tgt_raw):,}B (current save)\n"
                f"Size change: {size_diff:+,}B\n\n"
                f"This replaces ALL mercenaries with the source save's mercenaries.\n"
                f"Internal payload offsets will be adjusted.\n"
                f"TOC entries for subsequent blocks will be shifted.\n\n"
                f"This is EXPERIMENTAL. A backup will be saved to undo stack.",
                QMessageBox.Yes | QMessageBox.No, QMessageBox.No,
            )
            if reply != QMessageBox.Yes:
                return

            new_block = bytearray(src_raw)
            sentinel = b'\xff\xff\xff\xff\xff\xff\xff\xff'
            offset_delta = tgt_merc_toc.data_offset - src_merc_toc.data_offset

            for off in range(len(new_block) - 12):
                if new_block[off:off + 8] == sentinel:
                    po_off = off + 8
                    po_val = struct.unpack_from('<I', new_block, po_off)[0]
                    if po_val > 0 and po_val != 0xFFFFFFFF:
                        new_po = po_val + offset_delta
                        if 0 < new_po < 0x7FFFFFFF:
                            struct.pack_into('<I', new_block, po_off, new_po)

            tgt_start = tgt_merc_toc.data_offset
            tgt_end = tgt_start + len(tgt_raw)
            old_blob_bytes = bytes(blob[tgt_start:tgt_end])

            new_blob = bytearray()
            new_blob += blob[:tgt_start]
            new_blob += new_block
            new_blob += blob[tgt_end:]

            toc_off = tgt_parc.toc_offset
            if toc_off:
                for e in tgt_parc.toc_entries:
                    entry_off = toc_off + e.index * 20
                    if e.index == tgt_merc_toc.index:
                        struct.pack_into('<I', new_blob, entry_off + 16, len(src_raw))
                    elif e.data_offset > tgt_merc_toc.data_offset:
                        old_off = struct.unpack_from('<I', new_blob, entry_off + 12)[0]
                        struct.pack_into('<I', new_blob, entry_off + 12, old_off + size_diff)

                old_stream = struct.unpack_from('<I', new_blob, 4)[0]
                struct.pack_into('<I', new_blob, 4, old_stream + size_diff)

            for e in tgt_parc.toc_entries:
                if e.data_offset > tgt_merc_toc.data_offset:
                    new_data_off = e.data_offset + size_diff
                    blk = tgt_parc.block_raw.get(e.index, b'')
                    for boff in range(len(blk) - 12):
                        abs_pos = new_data_off + boff
                        if abs_pos + 12 > len(new_blob):
                            break
                        if new_blob[abs_pos:abs_pos + 8] == sentinel:
                            po_pos = abs_pos + 8
                            po_val = struct.unpack_from('<I', new_blob, po_pos)[0]
                            if po_val > 0 and po_val != 0xFFFFFFFF and po_val > tgt_merc_toc.data_offset:
                                struct.pack_into('<I', new_blob, po_pos, po_val + size_diff)

            self._undo_stack.append(UndoEntry(
                description=f"Dragon Full Clone: replaced MercenaryClan {len(tgt_raw)}B -> {len(src_raw)}B",
                patches=[],
            ))

            self._save_data.decompressed_blob = new_blob
            self._dirty = True

            QMessageBox.information(self, "Dragon Full Clone",
                f"MercenaryClanSaveData cloned successfully!\n\n"
                f"Block: {len(tgt_raw):,}B -> {len(src_raw):,}B\n"
                f"Payload offsets adjusted by {offset_delta:+d}\n"
                f"TOC entries shifted by {size_diff:+d}B\n\n"
                f"Save the file and load in-game.\n"
                f"NOTE: Undo will NOT work for this — reload the save to revert.")

        except Exception as e:
            QMessageBox.critical(self, "Dragon Clone Error", str(e))

    def _set_font_scale(self, scale: float) -> None:
        import re
        def _scale_px(m):
            orig = int(m.group(1))
            return f"font-size: {max(8, int(orig * scale))}px"
        scaled_ss = re.sub(r'font-size:\s*(\d+)px', _scale_px, DARK_STYLESHEET)
        self.setStyleSheet(scaled_ss)
        self._config["font_scale"] = scale
        self._save_config()
        self._update_status(f"Font size: {int(scale * 100)}%")

    def _set_widget_scale(self, scale: float) -> None:
        import re

        base_ss = self.styleSheet() or DARK_STYLESHEET

        def _scale_padding(m):
            vals = m.group(1).split()
            scaled = []
            for v in vals:
                if v.endswith('px'):
                    num = int(v[:-2])
                    scaled.append(f"{max(1, int(num * scale))}px")
                else:
                    try:
                        num = int(v)
                        scaled.append(str(max(1, int(num * scale))))
                    except ValueError:
                        scaled.append(v)
            return f"padding: {' '.join(scaled)}"

        scaled_ss = re.sub(r'padding:\s*([^;]+)', _scale_padding, base_ss)

        default_row = max(18, int(22 * scale))
        for table in self.findChildren(QTableWidget):
            table.verticalHeader().setDefaultSectionSize(default_row)

        if hasattr(self, '_buff_items_table'):
            t = self._buff_items_table
            t.setColumnWidth(1, max(80, int(180 * scale)))
            t.setColumnWidth(2, max(40, int(70 * scale)))
            t.setColumnWidth(4, max(40, int(70 * scale)))
        if hasattr(self, '_buff_stats_table'):
            t = self._buff_stats_table
            t.setColumnWidth(0, max(120, int(240 * scale)))
            t.setColumnWidth(1, max(60, int(100 * scale)))

        from PySide6.QtWidgets import QTreeWidget
        for tree in self.findChildren(QTreeWidget):
            tree.setIndentation(max(8, int(16 * scale)))

        if hasattr(self, '_save_dock'):
            scaled_sidebar = max(180, int(260 * scale))
            docks, widths = [], []
            if not self._sb_collapsed:
                self._sb_saved_width = scaled_sidebar
                docks.append(self._save_dock); widths.append(scaled_sidebar)
            if not self._ps_collapsed:
                self._ps_saved_width = scaled_sidebar
                docks.append(self._pack_dock); widths.append(scaled_sidebar)
            if docks:
                self.resizeDocks(docks, widths, Qt.Horizontal)

        if hasattr(self, '_center_status'):
            self._center_status.setFixedHeight(max(24, int(36 * scale)))

        self.setStyleSheet(scaled_ss)
        self._config["widget_scale"] = scale
        self._save_config()
        self._update_status(f"UI scale: {int(scale * 100)}%")

    def _undo(self) -> None:
        if not self._undo_stack or not self._save_data:
            self._update_status("Nothing to undo.")
            return

        entry = self._undo_stack.pop()
        blob = self._save_data.decompressed_blob

        for offset, old_bytes, _new_bytes in entry.patches:
            blob[offset:offset + len(old_bytes)] = old_bytes

        self._scan_and_populate()
        self._dirty = bool(self._undo_stack)
        self._update_status(f"Undone: {entry.description}")


